// ===================== MAINTENANCE MODE =====================
function isMaintenanceMode() {
  try {
    db = repairDB(db);
    return !!db?.maintenance?.enabled;
  } catch (_) {
    return false;
  }
}

function setMaintenanceMode(enabled, message) {
  db = repairDB(db);
  db.maintenance = db.maintenance && typeof db.maintenance === "object" ? db.maintenance : {};
  db.maintenance.enabled = !!enabled;
  if (typeof message === "string" && message.trim()) db.maintenance.message = message.trim();
  if (!db.maintenance.message) db.maintenance.message = "🛠 The bot is currently under maintenance. Please try again shortly.";
  saveDB();
  return db.maintenance.enabled;
}

function maintenanceModeText() {
  try {
    db = repairDB(db);
    return String(db?.maintenance?.message || "🛠 The bot is currently under maintenance. Please try again shortly.");
  } catch (_) {
    return "🛠 The bot is currently under maintenance. Please try again shortly.";
  }
}


