// ===== WEEKLY DRAW LIVE COUNTDOWN UPDATER (edits same message every 30s) =====
const weeklyDrawLiveIntervals = new Map(); // chatId -> intervalId
const weeklyDrawLastMenuMessage = new Map(); // chatId -> last weekly draw message id

function rememberWeeklyDrawMenu(chatId, messageId) {
  try {
    if (!messageId) return;
    weeklyDrawLastMenuMessage.set(String(chatId), Number(messageId));
  } catch (_) {}
}

async function deletePreviousWeeklyDrawMenu(chatId, exceptMessageId = null) {
  try {
    const key = String(chatId);
    const prev = Number(weeklyDrawLastMenuMessage.get(key) || 0);
    if (!prev) return;
    if (exceptMessageId && Number(prev) === Number(exceptMessageId)) return;
    await bot.deleteMessage(chatId, prev).catch(() => {});
    if (!exceptMessageId || Number(prev) !== Number(exceptMessageId)) {
      weeklyDrawLastMenuMessage.delete(key);
    }
  } catch (_) {}
}

function startWeeklyDrawLiveUpdate(chatId, messageId, preferCaption = true) {
  const key = String(chatId);
  stopWeeklyDrawLiveUpdate(chatId);

  const tick = async () => {
    try {
      const caption = buildWeeklyDrawMainCaption(chatId) + (weeklyDrawLastWinnersText(chatId) || "");
      const kb = weeklyDrawUserMenuKeyboard(chatId);

      // Try caption edit first (for photo messages), then fallback to text edit.
      if (preferCaption) {
        await bot.editMessageCaption(caption, {
          chat_id: chatId,
          message_id: messageId,
          ...kb,
        }).catch(async () => {
          await bot.editMessageText(caption, {
            chat_id: chatId,
            message_id: messageId,
            ...kb,
          }).catch(() => {});
        });
      } else {
        await bot.editMessageText(caption, {
          chat_id: chatId,
          message_id: messageId,
          ...kb,
        }).catch(async () => {
          await bot.editMessageCaption(caption, {
            chat_id: chatId,
            message_id: messageId,
            ...kb,
          }).catch(() => {});
        });
      }
    } catch (_) {
      stopWeeklyDrawLiveUpdate(chatId);
    }
  };

  tick();
  const id = setInterval(tick, 30 * 1000);
  weeklyDrawLiveIntervals.set(key, id);
}

function stopWeeklyDrawLiveUpdate(chatId) {
  const key = String(chatId);
  const id = weeklyDrawLiveIntervals.get(key);
  if (id) clearInterval(id);
  weeklyDrawLiveIntervals.delete(key);
}

async function refreshWeeklyDrawUserMenuMessage(chatId) {
  try {
    const messageId = Number(weeklyDrawLastMenuMessage.get(String(chatId)) || 0);
    if (!messageId) return false;
    const caption = buildWeeklyDrawMainCaption(chatId) + (weeklyDrawLastWinnersText(chatId) || "");
    const kb = weeklyDrawUserMenuKeyboard(chatId, "menu");
    await bot.editMessageCaption(caption, {
      chat_id: chatId,
      message_id: messageId,
      ...kb,
    }).catch(async () => {
      await bot.editMessageText(caption, {
        chat_id: chatId,
        message_id: messageId,
        ...kb,
      });
    });
    try { startWeeklyDrawLiveUpdate(chatId, messageId, true); } catch (_) {}
    return true;
  } catch (_) {
    return false;
  }
}

async function openWeeklyDrawUserMenu(chatId) {
  const c = ensureWeeklyDrawObject();
  if (!c.enabled) {
    return sendTracked(chatId, tr(chatId,"❌ WEEKLY DRAW is not active right now.","❌ Droo ya Wiki haiko hewani kwa sasa."), mainMenuKeyboard(chatId)).catch(() => {});
  }

  const caption = buildWeeklyDrawMainCaption(chatId) + (weeklyDrawLastWinnersText(chatId) || "");
  const img = String(c.image || "").trim();

  try { stopWeeklyDrawLiveUpdate(chatId); } catch (_) {}
  try { await deletePreviousWeeklyDrawMenu(chatId); } catch (_) {}

  try {
    if (img) {
      const sent = await bot.sendPhoto(chatId, img, { caption, ...weeklyDrawUserMenuKeyboard(chatId, "menu") });
      try { rememberWeeklyDrawMenu(chatId, sent.message_id); } catch (_) {}
      try { startWeeklyDrawLiveUpdate(chatId, sent.message_id, true); } catch (_) {}
      return sent;
    } else {
      const sent = await sendTracked(chatId, caption, weeklyDrawUserMenuKeyboard(chatId, "menu"));
      try { rememberWeeklyDrawMenu(chatId, sent.message_id); } catch (_) {}
      try { startWeeklyDrawLiveUpdate(chatId, sent.message_id, false); } catch (_) {}
      return sent;
    }
  } catch (e) {
    const sent = await sendTracked(chatId, caption, weeklyDrawUserMenuKeyboard(chatId, "menu")).catch(() => null);
    if (sent) {
      try { rememberWeeklyDrawMenu(chatId, sent.message_id); } catch (_) {}
      try { startWeeklyDrawLiveUpdate(chatId, sent.message_id, false); } catch (_) {}
      return sent;
    }
    return null;
  }
}



