// ===================== USER DATA BACKUP / RESTORE =====================
// Export/import a user's OWN data safely. Backup includes:
// - db.users[chatId]
// - db.campaign.entries[chatId] (if present)
// - db.pendingRedeems[chatId] (if present)
// - db.redeemCooldownByChat[chatId] (if present)
function buildUserBackup(chatId) {
  const cid = String(chatId);

  // User-scoped ledger events (withdrawals, orders, points, etc.)
  const ledgerAll = Array.isArray(db?.ledger) ? db.ledger : [];
  const userLedger = ledgerAll.filter(e => String(e?.chatId || "") === cid);

  return {
    version: 3,
    createdAt: Date.now(),
    chatId: cid,

    // Core user record (balances, settings, referral fields, business plan, withdrawStats, etc.)
    user: db?.users?.[cid] || {},

    // Campaign / weekly draw user-scoped data
    campaignEntry: db?.campaign?.entries?.[cid] || null,
    campaignSpend: (db?.campaign?.spend && typeof db.campaign.spend === "object") ? Number(db.campaign.spend[cid] || 0) : 0,
    campaignWithdrawReq: (db?.campaign?.withdrawReq && typeof db.campaign.withdrawReq === "object") ? Number(db.campaign.withdrawReq[cid] || 0) : 0,
    campaignOfferCount: (db?.campaign?.offerCount && typeof db.campaign.offerCount === "object") ? (db.campaign.offerCount[cid] || null) : null,

    // Withdraw system
    pendingRedeem: db?.pendingRedeems?.[cid] || null,
    redeemCooldown: db?.redeemCooldownByChat?.[cid] || null,
    redeemByPhoneDay: db?.redeemByPhoneDay?.[cid] || null,

    // User-scoped history
    ledger: userLedger
  };
}

function sha256Hex(bufOrStr) {
  try {
    return crypto.createHash("sha256").update(bufOrStr).digest("hex");
  } catch (_) {
    return "";
  }
}

function kenyaBackupStamp(ts = Date.now()) {
  try {
    const parts = new Intl.DateTimeFormat("en-GB", {
      timeZone: "Africa/Nairobi",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      hour12: true,
    }).formatToParts(new Date(ts));

    const get = (type) => String((parts.find((p) => p.type === type) || {}).value || "");
    const day = get("day");
    const month = get("month");
    const year = get("year");
    const hour = get("hour");
    const minute = get("minute");
    const period = get("dayPeriod").toUpperCase();
    return `${day}${month}${year}${hour}${minute}${period}`;
  } catch (_) {
    const d = new Date(ts);
    const dd = String(d.getDate()).padStart(2, "0");
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const yyyy = String(d.getFullYear());
    let hh = d.getHours();
    const ampm = hh >= 12 ? "PM" : "AM";
    hh = hh % 12 || 12;
    const h2 = String(hh).padStart(2, "0");
    const mi = String(d.getMinutes()).padStart(2, "0");
    return `${dd}${mm}${yyyy}${h2}${mi}${ampm}`;
  }
}

function randomUpperToken(len) {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let out = "";
  for (let i = 0; i < Number(len || 0); i++) {
    const idx = crypto.randomInt(0, chars.length);
    out += chars[idx];
  }
  return out;
}

const BACKUP_KEY_EXPIRE_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

function generateBackupKey() {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

  function block(len) {
    let out = "";
    for (let i = 0; i < len; i++) {
      out += chars[crypto.randomInt(0, chars.length)];
    }
    return out;
  }

  return `BINGWA-${block(4)}-${block(4)}-${block(4)}-${block(4)}-${block(4)}-${block(4)}`;
}

function hashBackupKey(key) {
  return crypto
    .createHash("sha256")
    .update(String(key || "").trim().toUpperCase())
    .digest("hex");
}

function backupKeyInfo(rawKey) {
  db = repairDB(db);
  const keyHash = hashBackupKey(rawKey);
  return db.backupVault?.[keyHash] || null;
}

function isBackupAlreadyUsed(backupKey) {
  try {
    const rec = backupKeyInfo(backupKey);
    return !!(rec && rec.usedAt);
  } catch (_) {
    return false;
  }
}

function isBackupExpired(rec) {
  if (!rec || !rec.createdAt) return true;
  return (Date.now() - Number(rec.createdAt || 0)) > BACKUP_KEY_EXPIRE_MS;
}

function markBackupUsed(backupKey, restoredByChatId) {
  try {
    db = repairDB(db);
    const keyHash = hashBackupKey(backupKey);
    if (!keyHash || !db.backupVault?.[keyHash]) return;
    db.backupVault[keyHash].usedAt = Date.now();
    db.backupVault[keyHash].restoredByChatId = String(restoredByChatId || "");
    db.usedBackupIds[keyHash] = Date.now();
    saveDB();
  } catch (_) {}
}

function createServerBackupKey(chatId) {
  db = repairDB(db);
  db.backupVault = db.backupVault && typeof db.backupVault === "object" ? db.backupVault : {};

  let key = "";
  let keyHash = "";
  for (let i = 0; i < 5; i++) {
    key = generateBackupKey();
    keyHash = hashBackupKey(key);
    if (!db.backupVault[keyHash]) break;
  }
  if (!key || !keyHash) throw new Error("Failed to generate backup key.");

  const payload = buildUserBackup(chatId);
  db.backupVault[keyHash] = {
    ownerChatId: String(chatId),
    createdAt: Date.now(),
    usedAt: 0,
    restoredByChatId: "",
    payload,
  };
  saveDB();
  return { key, payload };
}

function cleanupExpiredBackups() {
  db = repairDB(db);
  db.backupVault = db.backupVault && typeof db.backupVault === "object" ? db.backupVault : {};
  const now = Date.now();
  for (const [keyHash, rec] of Object.entries(db.backupVault || {})) {
    if (!rec || (now - Number(rec.createdAt || 0)) > BACKUP_KEY_EXPIRE_MS) {
      delete db.backupVault[keyHash];
    }
  }
  saveDB();
}

function applyUserBackup(chatId, payload) {
  const cid = String(chatId);

  if (!payload || typeof payload !== "object") throw new Error("Invalid backup payload");

  // Never reset the user's chosen language during restore.
  const keepLang = getStoredLang(chatId);

  if (!db.users || typeof db.users !== "object") db.users = {};
  const restoredUser = payload.user && typeof payload.user === "object" ? { ...payload.user } : {};
  restoredUser.lang = keepLang;
  db.users[cid] = restoredUser;

  // Restore campaign user-scoped maps (if present in backup)
  if (payload.campaignEntry !== undefined) {
    if (!db.campaign || typeof db.campaign !== "object") db.campaign = { enabled: false, status: "OFF" };
    if (!db.campaign.entries || typeof db.campaign.entries !== "object") db.campaign.entries = {};
    if (payload.campaignEntry === null) delete db.campaign.entries[cid];
    else db.campaign.entries[cid] = payload.campaignEntry;
  }

  if (payload.campaignSpend !== undefined) {
    if (!db.campaign || typeof db.campaign !== "object") db.campaign = { enabled: false, status: "OFF" };
    if (!db.campaign.spend || typeof db.campaign.spend !== "object") db.campaign.spend = {};
    const v = Number(payload.campaignSpend || 0);
    if (v <= 0) delete db.campaign.spend[cid];
    else db.campaign.spend[cid] = v;
  }

  if (payload.campaignWithdrawReq !== undefined) {
    if (!db.campaign || typeof db.campaign !== "object") db.campaign = { enabled: false, status: "OFF" };
    if (!db.campaign.withdrawReq || typeof db.campaign.withdrawReq !== "object") db.campaign.withdrawReq = {};
    const v = Number(payload.campaignWithdrawReq || 0);
    if (v <= 0) delete db.campaign.withdrawReq[cid];
    else db.campaign.withdrawReq[cid] = v;
  }

  if (payload.campaignOfferCount !== undefined) {
    if (!db.campaign || typeof db.campaign !== "object") db.campaign = { enabled: false, status: "OFF" };
    if (!db.campaign.offerCount || typeof db.campaign.offerCount !== "object") db.campaign.offerCount = {};
    if (payload.campaignOfferCount === null) delete db.campaign.offerCount[cid];
    else db.campaign.offerCount[cid] = payload.campaignOfferCount;
  }

  // Restore withdraw pending + cooldowns
  if (payload.pendingRedeem !== undefined) {
    if (!db.pendingRedeems || typeof db.pendingRedeems !== "object") db.pendingRedeems = {};
    if (payload.pendingRedeem === null) delete db.pendingRedeems[cid];
    else db.pendingRedeems[cid] = payload.pendingRedeem;
  }

  if (payload.redeemCooldown !== undefined) {
    if (!db.redeemCooldownByChat || typeof db.redeemCooldownByChat !== "object") db.redeemCooldownByChat = {};
    if (payload.redeemCooldown === null) delete db.redeemCooldownByChat[cid];
    else db.redeemCooldownByChat[cid] = payload.redeemCooldown;
  }

  if (payload.redeemByPhoneDay !== undefined) {
    if (!db.redeemByPhoneDay || typeof db.redeemByPhoneDay !== "object") db.redeemByPhoneDay = {};
    if (payload.redeemByPhoneDay === null) delete db.redeemByPhoneDay[cid];
    else db.redeemByPhoneDay[cid] = payload.redeemByPhoneDay;
  }

  // Restore user-scoped ledger events (withdraw history / purchases / points)
  if (payload.ledger !== undefined) {
    if (!Array.isArray(db.ledger)) db.ledger = [];
    const keep = db.ledger.filter(e => String(e?.chatId || "") !== cid);
    const add = Array.isArray(payload.ledger) ? payload.ledger : [];
    db.ledger = keep.concat(add);

    if (db.ledger.length > 20000) db.ledger = db.ledger.slice(-20000);
  }

  db = repairDB(db);
  saveDB();
}

function backupUniqueKey(payloadObj) {
  try {
    const stable = JSON.stringify(payloadObj || {});
    const h = crypto.createHash("sha256").update(stable).digest("hex");
    return "sha:" + h;
  } catch (_) {
    return "";
  }
}

// Legacy Telegram backup-file download helpers kept for compatibility
function tgHttpGetBuffer(url) {
  const https = require("https");
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      if (res.statusCode !== 200) {
        reject(new Error(`HTTP ${res.statusCode}`));
        return;
      }
      const chunks = [];
      res.on("data", (d) => chunks.push(d));
      res.on("end", () => resolve(Buffer.concat(chunks)));
    }).on("error", reject);
  });
}

async function tgDownloadFileBuffer(fileId) {
  const https = require("https");
  const token = String(process.env.TELEGRAM_TOKEN || process.env.BOT_TOKEN || "").trim();
  if (!token) throw new Error("Telegram bot token missing. Set TELEGRAM_TOKEN (or BOT_TOKEN) in Render environment variables.");

  const api = `https://api.telegram.org/bot${token}/getFile?file_id=${encodeURIComponent(fileId)}`;
  const meta = await new Promise((resolve, reject) => {
    https.get(api, (res) => {
      const chunks = [];
      res.on("data", (d) => chunks.push(d));
      res.on("end", () => {
        try {
          const j = JSON.parse(Buffer.concat(chunks).toString("utf8"));
          if (!j.ok) return reject(new Error("getFile failed"));
          resolve(j.result);
        } catch (e) { reject(e); }
      });
    }).on("error", reject);
  });

  const filePath = meta.file_path;
  if (!filePath) throw new Error("file_path missing");
  const url = `https://api.telegram.org/file/bot${token}/${filePath}`;
  return await tgHttpGetBuffer(url);
}

function getUser(chatId) {
  const cid = String(chatId);
  db = repairDB(db);
  if (!db.users[cid]) {
    db.users[cid] = {
      phone: "",
      lang: "en",
      antiSpam: { lastAt: 0, lastSig: "" },
      lastSeen: 0,
      purchasesByDay: {},
      weeklyPurchases: {},
      redeemUnlockStart: 0,
      redeemUnlockPurchases: 0,
      redeemedCounts: {},
      inviterId: "",
      inviterSetAt: 0,
      lastReferralRewardDay: "",
      points: 0,
      walletBalance: 0,
      totalSpentKsh: 0,
      referralSuccessCount: 0,
      referralCounted: false,
      pendingAction: null,

      // ✅ Admin moderation
      banned: false,

      // user preference: cleanup previous bot messages (0 = OFF)
      autoDeleteMs: 0,

      // ✅ Account types
      accountType: "normal", // normal | business
      subscriptionStart: 0,
      subscriptionExpiry: 0,

      // ✅ Business notifications
      businessIntroShown: false,        // show benefits intro only once ever
      businessReminderLastDay: "",      // YYYY-MM-DD (Kenya) last 3-day reminder sent
      businessExpiredNotifiedAt: 0,     // last expiry timestamp we already notified for

      // ✅ Profile (for leaderboards / display)
      profile: { firstName: "", lastName: "", username: "" },
      profileUpdatedAt: 0,
      createdAt: Date.now(),
      firstSeen: Date.now(),
      isAdult: false,
      qPurch20Count: 0,
    
      // ⚡ Fast Purchase (Business)
      fastPurchaseEnabled: false,

      // ⚙️ Quick Purchase Add-on (Business)
      quickPurchaseAddonEnabled: false,

      // 🔁 Auto Retry STK (Business)
      autoRetryStkEnabled: false,

      // 🛒 Multi Purchase
      multiPurchaseEnabled: false,

      // 🔕 Notification preferences (Business)
      stopCampaignNotifs: false,
      stopCashbackNotifs: false,
      stopReferralNotifs: false,

      // 🗑️ Delete previous bot messages toggle (Business)
      autoDelete24hEnabled: false,

      // 🧩 UI preference: hide quick actions row
      hideQuickActionsEnabled: false,
      // 🔒 UI preference: hide reply-keyboard buttons (except Help)
      // When ON: only Help button is shown; other button texts + inline actions are blocked.
      autoHideButtonsEnabled: false,
      walletLocked: false,
};
  }
  if (db.users[cid].pendingAction === undefined) db.users[cid].pendingAction = null;
  if (db.users[cid].banned === undefined) db.users[cid].banned = false;
  if (db.users[cid].autoDeleteMs === undefined) db.users[cid].autoDeleteMs = 0;
  if (db.users[cid].autoHideButtonsEnabled === undefined) db.users[cid].autoHideButtonsEnabled = false;
  if (db.users[cid].walletLocked === undefined) db.users[cid].walletLocked = false;
  if (db.users[cid].lang === undefined) db.users[cid].lang = "en";
  if (typeof db.users[cid].walletBalance !== "number") db.users[cid].walletBalance = 0;


  if (db.users[cid].autoRetryStkEnabled === undefined) db.users[cid].autoRetryStkEnabled = false;
  if (db.users[cid].multiPurchaseEnabled === undefined) db.users[cid].multiPurchaseEnabled = false;
  if (db.users[cid].stopCampaignNotifs === undefined) db.users[cid].stopCampaignNotifs = false;
  if (db.users[cid].stopCashbackNotifs === undefined) db.users[cid].stopCashbackNotifs = false;
  if (db.users[cid].stopReferralNotifs === undefined) db.users[cid].stopReferralNotifs = false;
  if (db.users[cid].autoDelete24hEnabled === undefined) db.users[cid].autoDelete24hEnabled = false;
  if (db.users[cid].hideQuickActionsEnabled === undefined) db.users[cid].hideQuickActionsEnabled = false;
  if (!db.users[cid].profile || typeof db.users[cid].profile !== "object") db.users[cid].profile = { firstName: "", lastName: "", username: "" };
  if (typeof db.users[cid].profileUpdatedAt !== "number") db.users[cid].profileUpdatedAt = 0;
  return db.users[cid];
}

function touchLastSeen(chatId) {
  const u = getUser(chatId);
  u.lastSeen = Date.now();
  saveDB();
}

function setUserPhone(chatId, phone254) {
  const u = getUser(chatId);
  u.phone = phone254;
  saveDB();
}

function getUserPhone(chatId) {
  const u = getUser(chatId);
  return u.phone || "";
}

function setUserReceivePhone(chatId, phone254) {
  const u = getUser(chatId);
  u.receivePhone = phone254 || "";
  try { registerReceiveNumberOwner(chatId, phone254 || ""); } catch (_) {}
  saveDB();
}

function getUserReceivePhone(chatId) {
  const u = getUser(chatId);
  return u.receivePhone || u.phone || "";
}

function getWalletBalance(chatId) {
  const u = getUser(chatId);
  return Number(u.walletBalance || 0);
}

function setWalletBalance(chatId, amount) {
  const u = getUser(chatId);
  u.walletBalance = Math.max(0, Number(Number(amount || 0).toFixed(2)));
  saveDB();
  if (u.walletBalance > walletSuspiciousThreshold(chatId)) {
    try { scheduleWalletReviewCheck(chatId, "wallet_balance_high"); } catch (_) {}
  }
  return u.walletBalance;
}

function addWalletBalance(chatId, amount) {
  return setWalletBalance(chatId, getWalletBalance(chatId) + Number(amount || 0));
}

function deductWalletBalance(chatId, amount) {
  const current = getWalletBalance(chatId);
  const need = Number(amount || 0);
  if (current + 1e-9 < need) return false;
  setWalletBalance(chatId, current - need);
  return true;
}

function formatWalletAmount(amount) {
  return Number(amount || 0).toFixed(2);
}

function getWalletReviewRecord(chatId) {
  db = repairDB(db);
  if (!db.walletReviewLocks || typeof db.walletReviewLocks !== "object") db.walletReviewLocks = {};
  return db.walletReviewLocks[String(chatId)] || null;
}

function isWalletLocked(chatId) {
  const rec = getWalletReviewRecord(chatId);
  return !!(rec && rec.status === "locked");
}

function lockWalletForReview(chatId, details = {}) {
  db = repairDB(db);
  if (!db.walletReviewLocks || typeof db.walletReviewLocks !== "object") db.walletReviewLocks = {};
  db.walletReviewLocks[String(chatId)] = {
    status: "locked",
    createdAt: Date.now(),
    amount: Number(details?.amount || getWalletBalance(chatId) || 0),
    reason: String(details?.reason || "wallet_review"),
    reportSentAt: Number(details?.reportSentAt || 0),
    reviewedAt: 0,
    decision: "",
    byAdmin: 0,
  };
  saveDB();
  return db.walletReviewLocks[String(chatId)];
}

function unlockWalletReview(chatId, decision = "accepted", adminId = 0) {
  db = repairDB(db);
  if (!db.walletReviewLocks || typeof db.walletReviewLocks !== "object") db.walletReviewLocks = {};
  const rec = db.walletReviewLocks[String(chatId)] || {};
  rec.status = "unlocked";
  rec.reviewedAt = Date.now();
  rec.decision = String(decision || "accepted");
  rec.byAdmin = Number(adminId || 0);
  db.walletReviewLocks[String(chatId)] = rec;
  saveDB();
  return rec;
}

function scheduleWalletReviewCheck(chatId, reason = "wallet_balance_check") {
  db = repairDB(db);
  if (!db.walletReviewChecks || typeof db.walletReviewChecks !== "object") db.walletReviewChecks = {};
  db.walletReviewChecks[String(chatId)] = {
    dueAt: Date.now() + 60 * 1000,
    reason: String(reason || "wallet_balance_check"),
  };
  saveDB();
}

function walletSuspiciousThreshold(chatId) {
  return Number(getWalletDepositPerTxnLimit(chatId) || 0);
}

function recentSuccessfulWalletDepositExists(chatId, withinMs = 65 * 1000) {
  try {
    const u = getUser(chatId);
    ensureTxLog(u);
    const now = Date.now();
    return (u.txLog || []).some((t) => String(t?.type || "") === "wallet_deposit_success" && (now - Number(t?.ts || 0)) <= withinMs);
  } catch (_) {
    return false;
  }
}

async function walletReviewTick() {
  try {
    db = repairDB(db);
    const checks = db.walletReviewChecks || {};
    for (const [cid, rec] of Object.entries(checks)) {
      if (!rec || Number(rec.dueAt || 0) > Date.now()) continue;
      delete checks[cid];
      const chatId = Number(cid);
      const bal = Number(getWalletBalance(chatId) || 0);
      if (!(bal > walletSuspiciousThreshold(chatId))) continue;
      if (recentSuccessfulWalletDepositExists(chatId)) continue;
      const existing = getWalletReviewRecord(chatId);
      if (existing && existing.status === "locked") continue;
      lockWalletForReview(chatId, { amount: bal, reason: rec.reason || "wallet_balance_check", reportSentAt: Date.now() });
      const kb = { reply_markup: { inline_keyboard: [[
        { text: "✅ Accept", callback_data: `walletrev:accept:${chatId}` },
        { text: "❌ Decline", callback_data: `walletrev:decline:${chatId}` }
      ]] } };
      try {
        await notifyAdmin(`🚨 Wallet review required
User: ${chatId}
Wallet balance: Ksh ${formatWalletAmount(bal)}
Reason: suspicious wallet amount with no recent deposit.
Action: Accept or Decline.`, kb);
      } catch (_) {}
      try {
        await sendTracked(chatId, `⛔ Your wallet has been locked temporarily for admin review.

Wallet balance: *Ksh ${formatWalletAmount(bal)}*

You cannot use wallet purchases or subscriptions until admin reviews the request.`, { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) });
      } catch (_) {}
    }
    saveDB();
  } catch (_) {}
}

const WALLET_DEPOSIT_MIN_KSH = 5;
const WALLET_DEPOSIT_MAX_KSH_NORMAL = 1000;
const WALLET_DEPOSIT_MAX_KSH_BUSINESS = 10000;
const WALLET_DEPOSIT_DAILY_MAX_NORMAL = 2500;
const WALLET_DEPOSIT_DAILY_MAX_BUSINESS = 20000;
const WALLET_DEPOSIT_CREDIT_DELAY_MS = 7000;

function getWalletDepositPerTxnLimit(chatId) {
  return isBusinessActive(chatId) ? WALLET_DEPOSIT_MAX_KSH_BUSINESS : WALLET_DEPOSIT_MAX_KSH_NORMAL;
}

function getWalletDepositDailyLimit(chatId) {
  return isBusinessActive(chatId) ? WALLET_DEPOSIT_DAILY_MAX_BUSINESS : WALLET_DEPOSIT_DAILY_MAX_NORMAL;
}

function getSuccessfulWalletDepositsToday(chatId, dayKey = kenyaDayKey()) {
  try {
    const u = getUser(chatId);
    ensureTxLog(u);
    let total = 0;
    for (const t of (u.txLog || [])) {
      if (kenyaDateOnlyFromTs(t.ts) !== dayKey) continue;
      if (String(t?.type || '') !== 'wallet_deposit_success') continue;
      total += Number(t?.walletAmount || 0);
    }
    return Number(total || 0);
  } catch (_) {
    return 0;
  }
}

function walletDepositFee(amount) {
  const amt = Number(amount || 0);
  if (!Number.isFinite(amt) || amt <= 100) return 0;
  if (amt <= 200) return 5;
  if (amt <= 500) return 12;
  if (amt <= 1000) return 15;
  if (amt <= 2500) return 25;
  if (amt <= 5000) return 35;
  return 55;
}

function walletDepositBreakdown(amount) {
  const requested = Number(Number(amount || 0).toFixed(2));
  const fee = Number(walletDepositFee(requested).toFixed(2));
  const netAmount = Math.max(0, Number((requested - fee).toFixed(2)));
  const totalCharge = requested;
  return { requested, fee, totalCharge, netAmount };
}

function walletDepositFeeGuideLines(chatId) {
  const maxLimit = getWalletDepositPerTxnLimit(chatId);
  return [
    `• Ksh 5 - 100  → fee Ksh 0`,
    `• Ksh 101 - 200  → fee Ksh 5`,
    `• Ksh 201 - 500  → fee Ksh 12`,
    `• Ksh 501 - 1,000  → fee Ksh 15`,
    `• Ksh 1,001 - 2,500  → fee Ksh 25`,
    `• Ksh 2,501 - 5,000  → fee Ksh 35`,
    `• Ksh 5,001 - ${formatMoneyCompact(maxLimit)}  → fee Ksh 55`,
  ].join("\n");
}

function walletCheckoutConfirmKeyboard() {
  return {
    reply_markup: {
      inline_keyboard: [
        [{ text: "✅ Yes continue", callback_data: "walletbuy:yes" }],
        [{ text: "❌ No choose other method", callback_data: "walletbuy:no" }]
      ]
    }
  };
}

async function startWalletCheckoutConfirmation(chatId, pending, meta = {}) {
  const amount = Number(pending?.price || 0);
  if (!Number.isFinite(amount) || amount <= 0) {
    return sendTracked(chatId, "❌ Invalid wallet amount.", { ...mainMenuKeyboard(chatId) });
  }
  const currentBalance = Number(getWalletBalance(chatId) || 0);
  const remaining = Math.max(0, currentBalance - amount);
  setPendingAction(chatId, {
    type: "wallet_checkout_confirm",
    pending,
    meta: {
      scope: String(meta?.scope || "session_purchase"),
      planKey: meta?.planKey ? String(meta.planKey) : "",
    },
  });
  return sendTracked(
    chatId,
    `💼 *Pay with Wallet*

` +
      `Amount to pay: *Ksh ${formatWalletAmount(amount)}*
` +
      `Current wallet balance: *Ksh ${formatWalletAmount(currentBalance)}*
` +
      `Wallet balance after payment: *Ksh ${formatWalletAmount(remaining)}*

` +
      `Are you sure you want to continue?`,
    { parse_mode: "Markdown", ...walletCheckoutConfirmKeyboard() }
  );
}

