async function sendWalletFlowMessage(chatId, text, options = {}, preferredMessageId = null) {
  const opts = { disable_web_page_preview: true, ...(options || {}) };
  if (preferredMessageId) {
    const edited = await safeEditMessageText(chatId, preferredMessageId, text, opts);
    if (edited) return { message_id: preferredMessageId, edited: true, raw: edited };
  }
  const sent = await bot.sendMessage(chatId, text, opts);
  return { message_id: sent?.message_id || 0, edited: false, raw: sent };
}

async function startWalletDepositFlow(chatId, ctx = {}) {
  const existing = getPendingAction(chatId);
  const existingPromptMessageId = Number(existing?.promptMessageId || 0);
  setPendingAction(chatId, {
    type: "wallet_deposit_amount",
    promptMessageId: existingPromptMessageId || Number(ctx.messageId || 0) || 0,
    __ttlMs: 5 * 60 * 1000,
  });
  const perTxnMax = getWalletDepositPerTxnLimit(chatId);
  const dailyMax = getWalletDepositDailyLimit(chatId);
  const dayTotal = getSuccessfulWalletDepositsToday(chatId);
  const remainingToday = Math.max(0, dailyMax - dayTotal);
  const text = `💳 *Wallet Deposit*

Send the amount you want to pay into your wallet.

• Minimum: *Ksh ${WALLET_DEPOSIT_MIN_KSH}*
• Maximum per transaction: *Ksh ${perTxnMax}*
• Daily limit: *Ksh ${dailyMax}*
• Deposited today: *Ksh ${formatWalletAmount(dayTotal)}*
• Remaining today: *Ksh ${formatWalletAmount(remainingToday)}*

*PayHero STK fee guide*
${walletDepositFeeGuideLines(chatId)}

The transaction fee will be deducted from this amount before wallet credit.

Example: \`400\``;

  const sent = await sendWalletFlowMessage(chatId, text, { parse_mode: "Markdown", ...walletFlowCancelKeyboard() }, Number(ctx.messageId || existingPromptMessageId || 0));
  const latest = getPendingAction(chatId) || {};
  setPendingAction(chatId, {
    ...latest,
    type: "wallet_deposit_amount",
    promptMessageId: Number(sent?.message_id || ctx.messageId || existingPromptMessageId || 0),
    __ttlMs: 5 * 60 * 1000,
  });
  return sent?.raw || null;
}

async function resolvePendingWalletCheckout(chatId) {
  const act = getPendingAction(chatId);
  if (!act || act.type !== "wallet_checkout_confirm") return false;

  const pending = act.pending || null;
  const scope = String(act?.meta?.scope || "session_purchase");
  clearPendingAction(chatId);

  if (scope === "business_purchase") {
    return completeWalletCheckout(chatId, pending);
  }

  const s = ensureSessionSecurityShape(sessions.get(chatId) || {}, chatId);
  if (!s) {
    return sendTracked(chatId, "⚠️ Your order session expired. Please choose the offer again.", { ...mainMenuKeyboard(chatId) });
  }
  return proceedPurchase(chatId, s, { method: "wallet", confirmed: true });
}

async function completeWalletCheckout(chatId, pending) {
  if (isWalletLocked(chatId) && !isAdmin(chatId)) {
    return sendTracked(chatId, "⛔ Your wallet/account is locked for admin review. Purchases are temporarily disabled until the review is completed.", { ...mainMenuKeyboard(chatId) });
  }
  const amount = Number(pending?.price || 0);
  if (!Number.isFinite(amount) || amount <= 0) {
    return sendTracked(chatId, "❌ Invalid wallet amount.", { ...mainMenuKeyboard(chatId) });
  }
  if (getWalletBalance(chatId) + 1e-9 < amount) {
    return sendTracked(chatId, `❌ Wallet balance is not enough.

Wallet: *Ksh ${formatWalletAmount(getWalletBalance(chatId))}*
Required: *Ksh ${formatWalletAmount(amount)}*`, { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) });
  }
  if (!deductWalletBalance(chatId, amount)) {
    return sendTracked(chatId, "❌ Wallet deduction failed. Please try again.", { ...mainMenuKeyboard(chatId) });
  }
  const whenTs = Date.now();
  const when = kenyaDateTimeFromTs(whenTs);
  const externalRef = makeExternalRef(chatId, `WALLET_${String(pending?.category || 'ORDER').replace(/\s+/g, '_')}`, amount);
  const paidOrders = Array.isArray(pending?.cartOrders) && pending.cartOrders.length
    ? pending.cartOrders.map((order) => ({ ...pending, category: order.category, pkgLabel: order.pkgLabel, price: order.price, phone254: order.phone254, receivePhone254: order.receivePhone254 || order.phone254 }))
    : [pending];

  for (const [paidIndex, paidOrder] of paidOrders.entries()) {
    try { if (paidOrder.phone254) markPhoneUsage(chatId, paidOrder.phone254); } catch (_) {}
    const bingwaReceivePhone = paidOrder.category === "Bingwa Deals" ? bingwaCheckPhoneFromItem(paidOrder) : null;
    if (paidOrder.category === "Bingwa Deals" && bingwaReceivePhone) {
      const bingwaLockRef = `${externalRef}:${paidIndex}`;
      if (!tryLockBingwaSuccess(bingwaReceivePhone, bingwaLockRef)) continue;
      if (bingwaAlreadyPurchasedToday(bingwaReceivePhone)) {
        releaseBingwaSuccessLock(bingwaReceivePhone, bingwaLockRef);
        continue;
      }
      markBingwaPurchasedToday(bingwaReceivePhone, bingwaLockRef);
    }
    recordSuccessfulRevenue(paidOrder);
    recordSuccessfulTransaction({ ...paidOrder, chatId }, externalRef, "WALLET", when);
    if (paidOrder.pkgLabel) incPurchaseStats(chatId, paidOrder.pkgLabel);
  }

  if (pending?.category !== "Business Account") {
    const rewardSourceChatId = pending?.sourceChatId || getUser(chatId)?.sourceChatId || null;
    if (!rewardSourceChatId || !isRewardsFrozenForChat(rewardSourceChatId)) {
      awardSuccessPurchasePoints(chatId, pending);
      if (!detectReferralFraudOnSuccess(chatId, pending)) {
        maybeRewardInviterOnSuccessPurchase(chatId, pending.price, when, pending?.receivePhone254 || pending?.phone254 || getUserReceivePhone(chatId));
      }
    }
  }

  if (pending && pending.category === "Business Account") {
    const plan = BUSINESS_PLANS[pending.planKey];
    if (plan) {
      activateBusiness(chatId, pending.planKey, plan);
      await maybeShowBusinessIntroOnce(chatId);
    }
  }

  try {
    const ss = ensureSessionSecurityShape(sessions.get(chatId) || {}, chatId);
    if (ss) {
      if (Array.isArray(ss.cart) && ss.cart.length) clearSessionCart(ss);
      ss.cartEditIndex = null;
      ss.pendingCheckoutRef = null;
      ss.pendingPaymentOrder = null;
      clearCheckoutLock(ss);
      setSessionAtomic(chatId, ss, { cartMutated: false });
    }
  } catch (_) {}

  const user = getUser(chatId);
  try { user.orders = Array.isArray(user.orders) ? user.orders : []; } catch (_) {}
  user.totalPurchases = Number(user.totalPurchases || 0) + 1;
  user.totalSpentKsh = Number(user.totalSpentKsh || 0) + amount;
  try {
    user.orders.unshift({ when: Date.now(), ref: externalRef, amount, category: pending?.category || "", phone: pending?.phone254 || "", status: "PAID_WALLET" });
    user.orders = user.orders.slice(0, 10);
  } catch (_) {}
  saveDB();

  const isCartPayment = Array.isArray(pending?.cartOrders) && pending.cartOrders.length > 0;
  const packageName = isCartPayment ? `Cart Checkout (${pending.cartOrders.length} orders)` : (pending?.pkgLabel || "Unknown Package");
  try { addUserTx(chatId, { status: "success", pkgLabel: packageName, amountKsh: amount, phone254: String(pending?.phone254 || ""), receivePhone254: String(pending?.receivePhone254 || pending?.phone254 || "") }); } catch (_) {}
  try {
    if (pending && pending.category !== "Business Account") {
      const uu = getUser(chatId);
      uu.lastPurchase = { category: pending.category, pkgLabel: pending.pkgLabel, price: pending.price, at: Date.now(), phone254: pending.phone254 || null };
      recordSuccessfulPurchase(chatId, pending.category, pending.pkgLabel, pending.phone254, pending.price, channelIdForCategory(pending.category));
      recordOfferTrend(pending.category, pending.pkgLabel);
      clearStkFailures(chatId, pending.phone254);
      saveDB();
    }
  } catch (_) {}

  const walletRemaining = getWalletBalance(chatId);
  if (pending?.autoRecommendHold) {
    const order = scheduleAutoRecommendOrder({
      chatId,
      category: String(pending?.category || ""),
      pkgLabel: String(pending?.pkgLabel || ""),
      price: Number(pending?.price || 0),
      phone254: String(pending?.phone254 || getUserPhone(chatId) || ""),
      receivePhone254: String(pending?.receivePhone254 || pending?.phone254 || getUserReceivePhone(chatId) || ""),
      requestedTime: String(pending?.requestedTime || "00:00"),
      scheduledForTs: Number(pending?.scheduledForTs || Date.now()),
      sourceChatId: pending?.sourceChatId || 0,
    });
    db = repairDB(db);
    if (db.autoRecommendOrders && db.autoRecommendOrders[order.id]) {
      db.autoRecommendOrders[order.id].externalRef = externalRef;
      db.autoRecommendOrders[order.id].paymentConfirmedAt = whenTs;
      saveDB();
    }
    return sendTracked(chatId,
      `✅ *Auto Recommend Saved*

` +
      `Your payment was confirmed successfully.
` +
      `Your package will be loaded on: *${mdEscape(formatAutoRecommendLoadTime(Number(pending?.scheduledForTs || Date.now())))}*
` +
      `Orders set for this date: *${countUserAutoRecommendReservationsByDay(chatId, autoRecommendDayKeyFromTs(Number(pending?.scheduledForTs || Date.now())))}/${AUTO_RECOMMEND_MAX_PER_DAY}*`,
      { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) }
    );
  }

  const businessExtra = pending?.category === "Business Account"
    ? (() => {
        const u = getUser(chatId);
        const exp = u.subscriptionExpiry ? kenyaDateTimeFromTs(u.subscriptionExpiry) : "N/A";
        return `

💼 *Business Account Active*
Expiry: \`${mdEscape(exp)}\``;
      })()
    : "";
  const successMsg =
    `✅ *Payment Confirmed*

` +
    `🆔 Reference: *${externalRef}*
` +
    `📦 Package: *${packageName}*
` +
    `💳 Payment Method: *Wallet*
` +
    `📱 Payment Number: *${maskPhone(pending?.phone254 || "")}*
` +
    `${formatSuccessReceiveNumbers(pending)}
` +
    `🕒 Transaction Date & Time: *${when}*
` +
    `💰 Amounts: *${formatSuccessAmounts(pending)}*
` +
    `👛 Wallet Balance: *Ksh ${formatWalletAmount(walletRemaining)}*

` +
    `Your wallet payment has been received and your request is being processed.` + businessExtra;

  await sendTracked(chatId, successMsg, { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) });

  try {
    if (Array.isArray(pending?.cartOrders) && pending.cartOrders.length) {
      for (const order of pending.cartOrders) {
        enqueueAdminNotification(`💼 Wallet Payment
` + formatAdminConfirmedReceipt(chatId, { ...pending, category: order.category, pkgLabel: order.pkgLabel, price: order.price, phone254: order.phone254, receivePhone254: order.receivePhone254 || order.phone254 }, whenTs, 0, externalRef));
      }
    } else {
      enqueueAdminNotification(`💼 Wallet Payment
` + formatAdminConfirmedReceipt(chatId, pending, whenTs, 0, externalRef));
    }
  } catch (_) {}
  return true;
}

// ===================== BUSINESS SUBSCRIPTION HELPERS =====================
function isBusinessActive(chatId) {
  const u = getUser(chatId);
  if (u.accountType !== "business") return false;
  if (!u.subscriptionExpiry) return false;

  if (Date.now() > u.subscriptionExpiry) {
    // Auto-revert on expiry
    u.accountType = "normal";
    u.subscriptionStart = 0;
    u.subscriptionExpiry = 0;
    // Auto-disable Fast Purchase on expiry
    try { u.fastPurchaseEnabled = false; } catch (_) {}
    saveDB();
    return false;}
  return true;
}

function activateBusiness(chatId, planKey, plan) {
  const u = getUser(chatId);
  const now = Date.now();

  const days = Number(plan?.days || 0);
  const months = Number(plan?.months || 0);

  // weekly plans use exact days; monthly uses 30-day month approximation (keeps your old behavior)
  const durationMs =
    days > 0 ? days * 24 * 60 * 60 * 1000 : months * 30 * 24 * 60 * 60 * 1000;

  u.accountType = "business";
  activateBusinessFeatures(u);
  u.subscriptionStart = now;
  u.subscriptionExpiry = now + durationMs;

  // track the active plan (for marking / deactivation UX)
  u.businessPlanKey = String(planKey || "");
  u.businessPlanLabel = String(plan?.label || "");

  // Do NOT reset businessIntroShown (announcement should show only once ever)
  saveDB();
}

function deactivateBusiness(chatId) {
  const u = getUser(chatId);
  u.accountType = "normal";
  u.subscriptionStart = 0;
  u.subscriptionExpiry = 0;
  u.businessPlanKey = "";
  u.businessPlanLabel = "";
  disableBusinessFeatures(u);
  saveDB();
}


async function maybeShowBusinessIntroOnce(chatId) {
  const u = getUser(chatId);
  if (!isBusinessActive(chatId)) return;
  if (u.businessIntroShown) return;

  u.businessIntroShown = true;
  saveDB();

  await sendTracked(
    chatId,
    `✅ *Business Account Activated!*\n\n` +
      `🚀 Benefits unlocked for your subscription period:\n` +
      `• Unlimited referrals\n` +
      `• Unlimited rewards\n` +
      `• Unlimited number usage\n` +
      `• All limits bypassed (except Bingwa daily rule)\n\n` +
      `⚠️ Self-referral is not allowed.`,
    { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) }
  );
}



