async function startSupportLiveChat(chatId, ctx = {}) {
  setPendingAction(chatId, { type: "support_live_chat", startedAt: Date.now(), source: String(ctx?.source || "") });
  return bot.sendMessage(chatId, supportLiveChatIntro(chatId), {
    parse_mode: "Markdown",
    ...supportLiveChatKeyboard(),
  }).catch(() => null);
}

async function endSupportLiveChat(chatId, opts = {}) {
  try {
    const gids = [];
    for (const [gid, pack] of supportLiveAlbums.entries()) {
      if (String(pack?.chatId || "") === String(chatId)) gids.push(gid);
    }
    for (const gid of gids) {
      const pack = supportLiveAlbums.get(gid);
      if (pack?.timer) clearTimeout(pack.timer);
      supportLiveAlbums.delete(gid);
    }
  } catch (_) {}

  clearPendingAction(chatId);
  if (opts.silent) return null;
  return bot.sendMessage(chatId, "✅ Chat ended. Returning to main menu.", { ...mainMenuKeyboard(chatId) }).catch(() => null);
}

async function relaySupportLiveSingle(msg) {
  const chatId = msg?.chat?.id;
  if (!chatId || !ADMIN_ID) return false;

  let mediaKind = "text";
  if (msg.photo) mediaKind = "photo";
  else if (msg.video) mediaKind = "video";
  else if (msg.document) mediaKind = "document";
  else if (msg.audio) mediaKind = "audio";
  else if (msg.voice) mediaKind = "voice";
  else if (msg.sticker) mediaKind = "sticker";
  else if (msg.contact) mediaKind = "contact";
  else if (msg.location) mediaKind = "location";
  else if (msg.video_note) mediaKind = "video note";
  else if (msg.animation) mediaKind = "animation";

  await bot.sendMessage(ADMIN_ID, supportLiveHeaderText(chatId, msg, { mediaKind }), {
    parse_mode: "Markdown",
    disable_web_page_preview: true,
  }).catch(() => {});

  await bot.copyMessage(ADMIN_ID, chatId, msg.message_id).catch(async () => {
    const fallback = String(msg.text || msg.caption || "[Unsupported message]").trim() || "[Unsupported message]";
    await bot.sendMessage(ADMIN_ID, fallback).catch(() => {});
  });

  return true;
}

async function flushSupportLiveAlbum(mediaGroupId) {
  const gid = String(mediaGroupId || "");
  const pack = supportLiveAlbums.get(gid);
  if (!pack) return;
  supportLiveAlbums.delete(gid);

  const items = Array.isArray(pack.items) ? pack.items.slice() : [];
  if (!items.length) return;

  const chatId = Number(pack.chatId || items[0]?.chat?.id || 0);
  if (!chatId || !ADMIN_ID) return;

  await bot.sendMessage(ADMIN_ID, supportLiveHeaderText(chatId, items[0], { mediaKind: "album", count: items.length }), {
    parse_mode: "Markdown",
    disable_web_page_preview: true,
  }).catch(() => {});

  const media = [];
  for (let i = 0; i < items.length; i += 1) {
    const built = buildInputMediaFromMsg(items[i], i === 0);
    if (built) media.push(built);
  }

  if (media.length) {
    await bot.sendMediaGroup(ADMIN_ID, media).catch(async () => {
      for (const item of items) {
        await bot.copyMessage(ADMIN_ID, chatId, item.message_id).catch(() => {});
      }
    });
    return;
  }

  for (const item of items) {
    await bot.copyMessage(ADMIN_ID, chatId, item.message_id).catch(() => {});
  }
}

function queueSupportLiveAlbum(msg) {
  const gid = String(msg?.media_group_id || "");
  if (!gid) return;
  const existing = supportLiveAlbums.get(gid) || { chatId: msg?.chat?.id, items: [], timer: null };
  existing.items.push(msg);
  supportLiveAlbums.set(gid, existing);
  if (existing.timer) clearTimeout(existing.timer);
  existing.timer = setTimeout(() => {
    flushSupportLiveAlbum(gid).catch(() => {});
  }, 1800);
}

