// Global maintenance gate: block all non-admin user interactions before any handlers run.
try {
  const _emit = bot.emit.bind(bot);
  bot.emit = function patchedEmit(eventName, ...args) {
    try {
      if (eventName === "message") {
        const msg = args[0] || {};
        const actorId = Number(msg?.from?.id || msg?.chat?.id || 0);
        if (actorId && !isAdmin(actorId) && isMaintenanceMode()) {
          bot.sendMessage(msg.chat.id, maintenanceModeText()).catch(() => {});
          return false;
        }
      }
      if (eventName === "callback_query") {
        const q = args[0] || {};
        const actorId = Number(q?.from?.id || q?.message?.chat?.id || 0);
        if (actorId && !isAdmin(actorId) && isMaintenanceMode()) {
          bot.answerCallbackQuery(q.id, { text: maintenanceModeText(), show_alert: true }).catch(() => {});
          return false;
        }
      }
    } catch (_) {}
    return _emit(eventName, ...args);
  };
} catch (_) {}

