const FORCE_JOIN_CHANNEL = "@bingwadata";
const FORCE_JOIN_URL = "https://t.me/Bingwadatabot";
const WEEKLY_DRAW_DEEPLINK = "https://t.me/Bingwadatabot?start=weeklydraw";
