function ensureForceJoinStore() {
  try {
    db = repairDB(db);
    if (!Array.isArray(db.forceJoinChannels)) db.forceJoinChannels = [];
    const clean = [];
    for (const item of db.forceJoinChannels) {
      const n = normalizeForceJoinChannel(item);
      if (n && !clean.includes(n)) clean.push(n);
    }
    if (!clean.length && normalizeForceJoinChannel(FORCE_JOIN_CHANNEL)) {
      clean.push(normalizeForceJoinChannel(FORCE_JOIN_CHANNEL));
    }
    db.forceJoinChannels = clean;
    saveDB();
  } catch (_) {}
}

function normalizeForceJoinChannel(input) {
  let value = String(input || "").trim();
  if (!value) return null;

  if (/^https?:\/\/t\.me\//i.test(value)) {
    value = value.replace(/^https?:\/\/t\.me\//i, "");
  } else if (/^t\.me\//i.test(value)) {
    value = value.replace(/^t\.me\//i, "");
  }

  value = value.split("/")[0].trim();
  value = value.replace(/^@+/, "");

  if (!/^[A-Za-z0-9_]{4,}$/.test(value)) return null;
  return "@" + value;
}

function forceJoinInviteUrl(channel) {
  const raw = String(channel || "").replace(/^@/, "");
  return `https://t.me/${raw}`;
}

function getForceJoinChannels() {
  ensureForceJoinStore();
  return Array.isArray(db.forceJoinChannels) ? db.forceJoinChannels.slice() : [];
}

function saveForceJoinChannels(list) {
  db = repairDB(db);
  db.forceJoinChannels = Array.isArray(list) ? list.slice() : [];
  saveDB();
}

