// ===================== AUTO-DELETE BOT MESSAGES (5 minutes) =====================


function parseDurationToMs(input) {
  const s = String(input || "").trim().toLowerCase();
  if (!s) return null;

  // allow formats: 10s, 10sec, 10secs, 10m, 10min, 10mins, 1h, 24hr, 24hrs
  const m = s.match(/^([0-9]+)\s*(s|sec|secs|second|seconds|m|min|mins|minute|minutes|h|hr|hrs|hour|hours)$/i);
  if (!m) return null;

  const n = Math.floor(Number(m[1]));
  if (!Number.isFinite(n) || n <= 0) return null;

  const unit = m[2].toLowerCase();
  let ms = 0;
  if (unit.startsWith("s")) ms = n * 1000;
  else if (unit.startsWith("m")) ms = n * 60 * 1000;
  else ms = n * 60 * 60 * 1000;

  const max = 24 * 60 * 60 * 1000; // 24h max
  if (ms > max) ms = max;
  if (ms < 1000) ms = 1000;
  return ms;
}

function formatMsShort(ms) {
  const n = Math.max(0, Number(ms || 0));
  if (!Number.isFinite(n) || n <= 0) return "off";
  const s = Math.round(n / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.round(s / 60);
  if (m < 60) return `${m}min`;
  const h = Math.round(m / 60);
  return `${h}hr`;
}

function getAutoDeleteMsForChat(chatId) {
  try {
    const u = getUser(chatId);
    const max = 24 * 60 * 60 * 1000;

    // Default: OFF unless enabled (Business setting "Auto delete messages (24hrs)")
    if (!u || !u.autoDelete24hEnabled) {
      const ms = Number(u && u.autoDeleteMs);
      if (!Number.isFinite(ms) || ms <= 0) return 0;
      return Math.min(max, Math.max(1000, ms));
    }

    return max;
  } catch (_) {
    return 0;
  }
}

function scheduleAutoDelete(sentMsg, ms = 5 * 60 * 1000) {
  try {
    const chatId = sentMsg && sentMsg.chat && sentMsg.chat.id;
    const messageId = sentMsg && sentMsg.message_id;
    if (!chatId || !messageId) return;

    setTimeout(async () => {
      try {
        await bot.deleteMessage(chatId, String(messageId));
      } catch (_) {}
    }, Math.max(1000, Number(ms) || 5 * 60 * 1000));
  } catch (_) {}
}

function _isProtectedAnnouncementText(t) {
  const s = String(t || "");
  if (!s) return false;
  // Never auto-delete: announcements, weekly draw broadcasts/updates/winners
  return (
    /\bWEEKLY\s*DRAW\b/i.test(s) ||
    /\bPREVIOUS\s*WINNERS\b/i.test(s) ||
    /\bWINNERS\b/i.test(s) ||
    /\bBROADCAST\b/i.test(s) ||
    /📢|📣/i.test(s) ||
    /ANNOUNC/i.test(s)
  );
}

function shouldKeepBotMessage(t) {
  const s = String(t || "").trim();
  if (!s) return false;
  return (
    s.startsWith("✅ Payment Confirmed") ||
    _isProtectedAnnouncementText(s)
  );
}

function shouldAutoDeleteOutbound(text = "", options = {}) {
  const s = String(text || "").trim();
  if (!s) return false;

  // Auto-delete ONLY these temporary messages after 5 minutes:
  // 1) Cashback earned notice
  // 2) STK request expired notice
  return (
    s.startsWith("🎁 Cashback Earned!") ||
    s.startsWith("⌛ STK request expired on")
  );
}

// Monkey-patch sendMessage + sendPhoto to auto-delete ONLY selected messages
try {
  const _sendMessage = bot.sendMessage.bind(bot);
  bot.sendMessage = async (chatId, text, options = {}) => {
    const rawOptions = options || {};
    const skipCleanupTrack = !!rawOptions.__skipCleanupTrack;
    const opt = { ...rawOptions };
    delete opt.__skipCleanupTrack;
    const m = await _sendMessage(chatId, text, opt);
    if (!skipCleanupTrack && m && m.message_id && !shouldKeepBotMessage(text)) trackBotMsg(chatId, m.message_id);
    if (shouldAutoDeleteOutbound(text, opt)) scheduleAutoDelete(m, 5 * 60 * 1000);
    return m;
  };

  const _sendPhoto = bot.sendPhoto.bind(bot);
  bot.sendPhoto = async (chatId, photo, options = {}) => {
    const rawOptions = options || {};
    const skipCleanupTrack = !!rawOptions.__skipCleanupTrack;
    const opt = { ...rawOptions };
    delete opt.__skipCleanupTrack;
    const m = await _sendPhoto(chatId, photo, opt);
    const cap = opt && opt.caption ? opt.caption : "";
    if (!skipCleanupTrack && m && m.message_id && !shouldKeepBotMessage(cap)) trackBotMsg(chatId, m.message_id);
    if (shouldAutoDeleteOutbound(cap, opt)) scheduleAutoDelete(m, 5 * 60 * 1000);
    return m;
  };
} catch (_) {}

// ===================== BUTTON COOLDOWN =====================
const buttonCooldownMap = new Map(); // chatId -> lastTapMs
function isOnButtonCooldown(chatId) {
  const cooldownMs = Number(ANTI_SPAM.BUTTON_COOLDOWN_MS || 0);
  if (!(cooldownMs > 0)) return false;
  const now = Date.now();
  const last = Number(buttonCooldownMap.get(String(chatId)) || 0);
  if (now - last < cooldownMs) return true;
  buttonCooldownMap.set(String(chatId), now);
  return false;
}


// ===================== MESSAGE FLOOD PROTECTION =====================
const msgFloodMap = new Map(); // chatId -> [timestamps]
const msgFloodWarnMap = new Map(); // chatId -> lastWarnMs

function getTempMuteRemainingMs(chatId) {
  try {
    db = repairDB(db);
    const until = Number(db.tempMutedChats?.[String(chatId)] || 0);
    const rem = until - Date.now();
    return rem > 0 ? rem : 0;
  } catch (_) {
    return 0;
  }
}

function setTempMute(chatId, ms = Number(ANTI_SPAM.TEMP_MUTE_MS || 60000)) {
  try {
    db = repairDB(db);
    if (!db.tempMutedChats || typeof db.tempMutedChats !== "object") db.tempMutedChats = {};
    db.tempMutedChats[String(chatId)] = Date.now() + Math.max(1000, Number(ms || 60000));
    saveDB();
  } catch (_) {}
}

function clearExpiredTempMutes() {
  try {
    db = repairDB(db);
    const now = Date.now();
    let changed = false;
    for (const [cid, until] of Object.entries(db.tempMutedChats || {})) {
      if (Number(until || 0) <= now) {
        delete db.tempMutedChats[cid];
        changed = true;
      }
    }
    if (changed) saveDB();
  } catch (_) {}
}

function isMessageFlood(chatId) {
  const now = Date.now();
  const key = String(chatId);
  const windowMs = Number(ANTI_SPAM.MESSAGE_FLOOD_WINDOW_MS || 3000);
  const limit = Number(ANTI_SPAM.MESSAGE_FLOOD_LIMIT || 10);
  const arr = (msgFloodMap.get(key) || []).filter((t) => now - t < windowMs);
  arr.push(now);
  msgFloodMap.set(key, arr);

  if (arr.length >= limit) {
    const lastWarn = Number(msgFloodWarnMap.get(key) || 0);
    if (now - lastWarn > 15000) {
      msgFloodWarnMap.set(key, now);
      const esc = applyAntiSpamEscalation(chatId, "message_flood");
      const mins = Math.max(1, Math.ceil(Number(esc.ms || 60000) / 60000));
      bot.sendMessage(chatId, esc.action === "temp_ban"
        ? `⛔ Too many messages too fast. You are temporarily banned for ${mins} minute${mins === 1 ? "" : "s"}.`
        : `⏳ Too many messages too fast. You have been muted for ${mins} minute${mins === 1 ? "" : "s"}.`
      ).catch(() => {});
    }
    return true;
  }
  return false;
}
