  const pendingReq = db?.pendingRedeems?.[String(chatId)];
  let pendingLine = "";
  if (pendingReq && pendingReq.type === "withdraw" && pendingReq.status === "pending") {
    const ksh = Number(pointsToKes(pendingReq.amount || 0));
    pendingLine = `\n• 🕚 Pending: Ksh ${ksh}`;
  }

  // Weekly draw stats
