function kenyaDateParts(ts = Date.now()) {
  try {
    const parts = new Intl.DateTimeFormat("en-GB", {
      timeZone: "Africa/Nairobi",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hour12: false,
    }).formatToParts(new Date(ts));
    const get = (type) => (parts.find((x) => x.type === type) || {}).value || "00";
    return {
      year: Number(get("year")),
      month: Number(get("month")),
      day: Number(get("day")),
      hour: Number(get("hour")),
      minute: Number(get("minute")),
      second: Number(get("second")),
    };
  } catch (_) {
    const d = new Date(ts);
    return { year: d.getUTCFullYear(), month: d.getUTCMonth() + 1, day: d.getUTCDate(), hour: d.getUTCHours(), minute: d.getUTCMinutes(), second: d.getUTCSeconds() };
  }
}

function kenyaDateAtTimeTs(hour, minute, second = 1, daysAhead = 1) {
  const nowParts = kenyaDateParts();
  const tsGuess = Date.UTC(nowParts.year, nowParts.month - 1, nowParts.day + Number(daysAhead || 0), Number(hour || 0), Number(minute || 0), Number(second || 0));
  return tsGuess - (3 * 60 * 60 * 1000);
}

function autoRecommendId() {
  return `AR-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;
}

function parseAutoRecommendTimeInput(value) {
  const raw = String(value || "").trim();
  if (!raw) return null;

  const compact = raw.replace(/\s+/g, "");
  const m12compact = compact.match(/^(\d{1,2})(?::?(\d{2}))([AaPp][Mm])$/);
  if (m12compact) {
    let hh = Number(m12compact[1]);
    const mm = Number(m12compact[2]);
    const meridiem = String(m12compact[3] || "").toUpperCase();
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || hh < 1 || hh > 12 || mm < 0 || mm > 59) return null;
    if (meridiem === "AM") {
      hh = hh === 12 ? 0 : hh;
    } else {
      hh = hh === 12 ? 12 : hh + 12;
    }
    return { hour: hh, minute: mm, format: "12h", meridiem };
  }

  const m12 = raw.match(/^(\d{1,2}):(\d{2})\s*([AaPp][Mm])$/);
  if (m12) {
    let hh = Number(m12[1]);
    const mm = Number(m12[2]);
    const meridiem = String(m12[3] || "").toUpperCase();
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || hh < 1 || hh > 12 || mm < 0 || mm > 59) return null;
    if (meridiem === "AM") {
      hh = hh === 12 ? 0 : hh;
    } else {
      hh = hh === 12 ? 12 : hh + 12;
    }
    return { hour: hh, minute: mm, format: "12h", meridiem };
  }

  const m24compact = compact.match(/^(\d{1,2})(\d{2})$/);
  if (m24compact) {
    const hh = Number(m24compact[1]);
    const mm = Number(m24compact[2]);
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || hh < 0 || hh > 23 || mm < 0 || mm > 59) return null;
    return { hour: hh, minute: mm, format: "24h" };
  }

  const m24 = raw.match(/^(\d{1,2}):(\d{2})$/);
  if (!m24) return null;
  const hh = Number(m24[1]);
  const mm = Number(m24[2]);
  if (!Number.isFinite(hh) || !Number.isFinite(mm) || hh < 0 || hh > 23 || mm < 0 || mm > 59) return null;
  return { hour: hh, minute: mm, format: "24h" };
}

function kenyaSpecificDateTimeTs(day, month, hour, minute, second = 1, year = 0) {
  const nowParts = kenyaDateParts();
  const yyyy = Number(year || nowParts.year);
  const dd = Number(day || 0);
  const mm = Number(month || 0);
  const hh = Number(hour || 0);
  const min = Number(minute || 0);
  const sec = Number(second || 0);
  if (!Number.isFinite(yyyy) || !Number.isFinite(dd) || !Number.isFinite(mm) || !Number.isFinite(hh) || !Number.isFinite(min) || !Number.isFinite(sec)) return 0;
  const ts = Date.UTC(yyyy, mm - 1, dd, hh, min, sec) - (3 * 60 * 60 * 1000);
  const check = kenyaDateParts(ts);
  if (check.year !== yyyy || check.month !== mm || check.day !== dd || check.hour !== hh || check.minute !== min) return 0;
  return ts;
}

function parseAutoRecommendScheduleInput(value) {
  const raw = String(value || "").trim();
  if (!raw) return null;

  const compact = raw.replace(/\s+/g, "");

  let m = compact.match(/^(\d{2})(\d{2})\.(\d{2})(\d{2})([AaPp][Mm])?$/);
  if (!m) m = compact.match(/^(\d{2})\/(\d{2})[-T]?(\d{2}):(\d{2})([AaPp][Mm])?$/);
  if (!m) m = compact.match(/^(\d{2})-(\d{2})[-T]?(\d{2}):(\d{2})([AaPp][Mm])?$/);
  if (m) {
    let day = Number(m[1]);
    let month = Number(m[2]);
    let hour = Number(m[3]);
    const minute = Number(m[4]);
    const meridiemRaw = String(m[5] || "").toUpperCase();
    if (meridiemRaw) {
      if (hour < 1 || hour > 12) return null;
      hour = meridiemRaw === "AM" ? (hour === 12 ? 0 : hour) : (hour === 12 ? 12 : hour + 12);
    }
    if (!Number.isFinite(day) || !Number.isFinite(month) || !Number.isFinite(hour) || !Number.isFinite(minute)) return null;
    if (day < 1 || day > 31 || month < 1 || month > 12 || hour < 0 || hour > 23 || minute < 0 || minute > 59) return null;
    return { explicitDate: true, day, month, hour, minute, format: meridiemRaw ? "date12h" : "date24h", meridiem: meridiemRaw || "" };
  }

  const onlyTime = parseAutoRecommendTimeInput(raw);
  if (!onlyTime) return null;
  return { explicitDate: false, ...onlyTime };
}

function autoRecommendMinuteKeyFromTs(ts) {
  const p = kenyaDateParts(ts);
  return `${String(p.year).padStart(4, "0")}-${String(p.month).padStart(2, "0")}-${String(p.day).padStart(2, "0")} ${String(p.hour).padStart(2, "0")}:${String(p.minute).padStart(2, "0")}`;
}

function autoRecommendDayKeyFromTs(ts) {
  const p = kenyaDateParts(ts);
  return `${String(p.year).padStart(4, "0")}-${String(p.month).padStart(2, "0")}-${String(p.day).padStart(2, "0")}`;
}

function formatAutoRecommendLoadTime(ts) {
  const p = kenyaDateParts(ts || Date.now());
  const dd = String(p.day).padStart(2, "0");
  const mm = String(p.month).padStart(2, "0");
  const yyyy = String(p.year).padStart(4, "0");
  let hh = Number(p.hour || 0);
  const min = String(p.minute).padStart(2, "0");
  const ampm = hh >= 12 ? "pm" : "am";
  hh = hh % 12 || 12;
  return `${dd}/${mm}/${yyyy}, ${String(hh).padStart(2, "0")}:${min} ${ampm}`;
}

function countUserAutoRecommendReservationsByDay(chatId, dayKey) {
  db = repairDB(db);
  const cid = Number(chatId || 0);
  const key = String(dayKey || "");
  let total = 0;
  for (const rec of Object.values(db.autoRecommendOrders || {})) {
    if (!rec || Number(rec.chatId || 0) !== cid) continue;
    if (String(rec.status || "active") !== "active") continue;
    if (autoRecommendDayKeyFromTs(Number(rec.scheduledForTs || 0)) !== key) continue;
    total += 1;
  }
  for (const rec of Object.values(db.pendingPayments || {})) {
    if (!rec || !rec.autoRecommendHold) continue;
    if (Number(rec.chatId || 0) !== cid) continue;
    if (autoRecommendDayKeyFromTs(Number(rec.scheduledForTs || 0)) !== key) continue;
    total += 1;
  }
  return total;
}

function listAutoRecommendOrders(status = "active") {
  db = repairDB(db);
  return Object.values(db.autoRecommendOrders || {})
    .filter((x) => x && (!status || String(x.status || "") === String(status)))
    .map((x) => ({
      ...x,
      phone254: decryptPhoneField(x.phone254 || ""),
      receivePhone254: decryptPhoneField(x.receivePhone254 || x.phone254 || ""),
    }))
    .sort((a, b) => Number(a.scheduledForTs || 0) - Number(b.scheduledForTs || 0));
}

function reserveUniqueAutoRecommendTs(baseTs, excludeId = "") {
  db = repairDB(db);
  let ts = Number(baseTs || 0);
  if (!Number.isFinite(ts) || ts <= 0) return 0;
  let guard = 0;
  while (guard < 5000) {
    guard += 1;
    const conflict = Object.values(db.autoRecommendOrders || {}).some((x) => x && x.id !== excludeId && String(x.status || "active") === "active" && Number(x.scheduledForTs || 0) === ts);
    if (!conflict) return ts;
    ts += 5000;
  }
  return ts;
}

function scheduleAutoRecommendOrder(payload) {
  db = repairDB(db);
  const id = autoRecommendId();
  const rec = {
    id,
    status: "active",
    createdAt: Date.now(),
    updatedAt: Date.now(),
    dispatchAttempts: 0,
    dispatchedAt: 0,
    requestedTime: String(payload?.requestedTime || "00:02"),
    scheduledForTs: Number(payload?.scheduledForTs || 0),
    chatId: Number(payload?.chatId || 0),
    category: String(payload?.category || ""),
    pkgLabel: String(payload?.pkgLabel || ""),
    price: Number(payload?.price || 0),
    phone254: encryptSensitive(String(payload?.phone254 || "")),
    receivePhone254: encryptSensitive(String(payload?.receivePhone254 || payload?.phone254 || "")),
    sourceChatId: payload?.sourceChatId ? Number(payload.sourceChatId) : 0,
  };
  db.autoRecommendOrders[id] = rec;
  saveDB();
  return { ...rec, phone254: payload?.phone254 || "", receivePhone254: payload?.receivePhone254 || payload?.phone254 || "" };
}

function postponeAutoRecommendOrder(id, nextTs, reason = "busy") {
  db = repairDB(db);
  const rec = db.autoRecommendOrders?.[String(id || "")];
  if (!rec) return false;
  rec.scheduledForTs = reserveUniqueAutoRecommendTs(Number(nextTs || 0), rec.id);
  rec.updatedAt = Date.now();
  rec.lastDelayReason = String(reason || "busy");
  saveDB();
  return true;
}

function completeAutoRecommendOrder(id, status = "sent") {
  db = repairDB(db);
  const rec = db.autoRecommendOrders?.[String(id || "")];
  if (!rec) return false;
  rec.status = String(status || "sent");
  rec.dispatchedAt = Date.now();
  rec.updatedAt = Date.now();
  saveDB();
  return true;
}

function cancelAutoRecommendOrder(id) {
  db = repairDB(db);
  const rec = db.autoRecommendOrders?.[String(id || "")];
  if (!rec) return false;
  rec.status = "cancelled";
  rec.updatedAt = Date.now();
  saveDB();
  return true;
}

function formatAutoRecommendOrderLine(rec, idx = 0) {
  return `${idx ? `${idx}. ` : ""}${rec.id} | ${rec.category} | ${rec.pkgLabel} | Ksh ${rec.price} | ${kenyaDateTimeFromTs(rec.scheduledForTs || 0)} | Pay ${maskPhone(rec.phone254 || "")} | Receive ${maskPhone(rec.receivePhone254 || rec.phone254 || "")}`;
}

async function dispatchAutoRecommendOrder(rec) {
  const chatId = Number(rec?.chatId || 0);
  if (!chatId) return false;
  const siblingConflict = listAutoRecommendOrders("active").some((x) => x.id !== rec.id && Math.abs(Number(x.scheduledForTs || 0) - Number(rec.scheduledForTs || 0)) < 5000);
  if (siblingConflict) {
    postponeAutoRecommendOrder(rec.id, Number(rec.scheduledForTs || 0) + 5000, "auto_recommend_collision");
    return false;
  }
  const pkg = findPackageByLabel(rec.category, rec.pkgLabel);
  if (!pkg) {
    completeAutoRecommendOrder(rec.id, "expired");
    await sendTracked(chatId, `⚠️ Auto Recommend expired because the offer is no longer available.

Offer: ${rec.pkgLabel}`, { ...mainMenuKeyboard(chatId) });
    return false;
  }
  completeAutoRecommendOrder(rec.id, "sent");
  const fakePending = {
    category: rec.category,
    pkgLabel: rec.pkgLabel,
    price: rec.price,
    phone254: rec.phone254 || getUserPhone(chatId) || "",
    receivePhone254: rec.receivePhone254 || rec.phone254 || getUserReceivePhone(chatId) || "",
  };
  try {
    enqueueAdminNotification(`📋 Auto Recommend
${formatAdminConfirmedReceipt(chatId, fakePending, Number(rec.paymentConfirmedAt || Date.now()), 0, String(rec.externalRef || ""))}`);
  } catch (_) {}
  await sendTracked(chatId,
    `⏰ *Auto Recommend Released*

` +
    `Offer: *${mdEscape(rec.pkgLabel)}*
` +
    `Category: *${mdEscape(rec.category)}*
` +
    `Release time: *${kenyaDateTimeFromTs(Date.now())}*

` +
    `✅ Your recommendation went through and has now been released for processing.`,
    { parse_mode: "Markdown", ...mainMenuKeyboard(chatId) }
  );
  return true;
}

async function autoRecommendTick() {
  try {
    const due = listAutoRecommendOrders("active").filter((x) => Number(x.scheduledForTs || 0) <= Date.now());
    for (const rec of due) {
      try {
        await dispatchAutoRecommendOrder(rec);
      } catch (_) {}
    }
  } catch (_) {}
}

function randomIntInclusive(min, max) {
  const a = Number(min || 0);
  const b = Number(max || 0);
  if (!Number.isFinite(a) || !Number.isFinite(b)) return 0;
  const lo = Math.min(a, b);
  const hi = Math.max(a, b);
  return Math.floor(Math.random() * (hi - lo + 1)) + lo;
}

function autoRecommendFormatCompactDateTs(ts, useAmPm = false) {
  const p = kenyaDateParts(ts || Date.now());
  const dd = String(p.day).padStart(2, "0");
  const mm = String(p.month).padStart(2, "0");
  let hh = Number(p.hour || 0);
  const min = String(p.minute).padStart(2, "0");
  if (useAmPm) {
    const suffix = hh >= 12 ? "PM" : "AM";
    hh = hh % 12 || 12;
    return `${dd}${mm}.${String(hh).padStart(2, "0")}${min}${suffix}`;
  }
  return `${dd}${mm}.${String(hh).padStart(2, "0")}${min}`;
}

function autoRecommendSuggestionTimes() {
  const now = Date.now();
  const todayBase = now + (randomIntInclusive(15, 180) * 60 * 1000);
  const tomorrowBase = now + (24 * 60 * 60 * 1000) + (randomIntInclusive(15, 12 * 60) * 60 * 1000);
  const tomorrowBase2 = now + (24 * 60 * 60 * 1000) + (randomIntInclusive(12 * 60, 23 * 60) * 60 * 1000);

  const todayTs = reserveUniqueAutoRecommendTs(todayBase) || todayBase;
  const tomorrowTs = reserveUniqueAutoRecommendTs(tomorrowBase) || tomorrowBase;
  const tomorrowTs2 = reserveUniqueAutoRecommendTs(tomorrowBase2) || tomorrowBase2;

  return {
    quick1: autoRecommendFormatCompactDateTs(todayTs, false),
    quick2: autoRecommendFormatCompactDateTs(tomorrowTs, false),
    quick3: autoRecommendFormatCompactDateTs(tomorrowTs2, true),
    todayLabel: formatAutoRecommendLoadTime(todayTs),
    tomorrowLabel: formatAutoRecommendLoadTime(tomorrowTs),
    tomorrowLateLabel: formatAutoRecommendLoadTime(tomorrowTs2),
  };
}

function autoRecommendKeyboard(chatId) {
  const s = autoRecommendSuggestionTimes();
  return {
    reply_markup: {
      keyboard: [
        [s.quick1, s.quick2, s.quick3],
        ["❌ Cancel", "🏠 Main Menu"]
      ],
      resize_keyboard: true,
      one_time_keyboard: false,
    }
  };
}

