function safeEq(a, b) {
  const aa = Buffer.from(String(a || ""));
  const bb = Buffer.from(String(b || ""));
  if (aa.length !== bb.length) return false;
  try { return crypto.timingSafeEqual(aa, bb); } catch (_) { return false; }
}

function getSigningSecrets() {
  return [getCartSigningSecret(), getCartSigningSecretPrev()].filter(Boolean);
}

function getCallbackSecrets() {
  return [getPayheroCallbackSecret(), getPayheroCallbackSecretPrev()].filter(Boolean);
}

function makeAesKey() {
  const DATA_ENCRYPTION_KEY = getDataEncryptionKey();
  if (!DATA_ENCRYPTION_KEY) return null;
  return crypto.createHash("sha256").update(String(DATA_ENCRYPTION_KEY)).digest();
}

function encryptSensitive(value) {
  try {
    const DATA_ENCRYPTION_KEY = getDataEncryptionKey();
    if (!value || !DATA_ENCRYPTION_KEY) return value;
    const iv = crypto.randomBytes(12);
    const key = makeAesKey();
    const cipher = crypto.createCipheriv("aes-256-gcm", key, iv);
    const enc = Buffer.concat([cipher.update(String(value), "utf8"), cipher.final()]);
    const tag = cipher.getAuthTag();
    return `enc:${iv.toString("hex")}:${tag.toString("hex")}:${enc.toString("hex")}`;
  } catch (_) {
    return value;
  }
}

function decryptSensitive(value) {
  try {
    const src = String(value || "");
    if (!src.startsWith("enc:")) return value;
    const DATA_ENCRYPTION_KEY = getDataEncryptionKey();
    if (!DATA_ENCRYPTION_KEY) return "";
    const [, ivHex, tagHex, dataHex] = src.split(":");
    const key = makeAesKey();
    const decipher = crypto.createDecipheriv("aes-256-gcm", key, Buffer.from(ivHex, "hex"));
    decipher.setAuthTag(Buffer.from(tagHex, "hex"));
    const dec = Buffer.concat([decipher.update(Buffer.from(dataHex, "hex")), decipher.final()]);
    return dec.toString("utf8");
  } catch (_) {
    return "";
  }
}

function decryptPhoneField(value) {
  const out = decryptSensitive(value);
  return typeof out === "string" ? out : String(out || "");
}


function sanitizeLogText(value) {
  return String(value == null ? "" : value)
    .replace(/[\r\n\t]+/g, ' ')
    .replace(/[\u0000-\u001f\u007f-\u009f]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function logSecurityEvent(kind, details = {}) {
  try {
    db = repairDB(db);
    if (!Array.isArray(db.securityEvents)) db.securityEvents = [];
    const safe = JSON.parse(JSON.stringify(details || {}));
    for (const k of Object.keys(safe)) {
      if (/phone/i.test(k) && safe[k]) safe[k] = maskPhone(String(safe[k]));
      else safe[k] = sanitizeLogText(safe[k]);
    }
    db.securityEvents.push({ ts: Date.now(), kind: sanitizeLogText(kind), ...safe });
    db.securityEvents = db.securityEvents.slice(-500);
    saveDB();
  } catch (_) {}
}

function ensureCallbackPayloadStore() {
  db = repairDB(db);
  if (!db.callbackPayloadStore || typeof db.callbackPayloadStore !== 'object') db.callbackPayloadStore = {};
}

function pruneCallbackPayloadStore() {
  ensureCallbackPayloadStore();
  const now = Date.now();
  for (const [k, rec] of Object.entries(db.callbackPayloadStore || {})) {
    if (!rec || Number(rec.expiresAt || 0) <= now || rec.usedAt) delete db.callbackPayloadStore[k];
  }
}

function putCallbackPayload(payload, ttlMs = CALLBACK_PAYLOAD_TTL_MS) {
  pruneCallbackPayloadStore();
  const id = `cbp_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,8)}`;
  db.callbackPayloadStore[id] = { payload: String(payload || ''), createdAt: Date.now(), expiresAt: Date.now() + Number(ttlMs || CALLBACK_PAYLOAD_TTL_MS), usedAt: 0 };
  saveDB();
  return id;
}

function getCallbackPayload(id, consume = false) {
  pruneCallbackPayloadStore();
  const rec = db.callbackPayloadStore?.[String(id || '')];
  if (!rec) return null;
  if (consume) {
    rec.usedAt = Date.now();
    saveDB();
  }
  return String(rec.payload || '');
}

function rotateSensitiveSessionToken(s, chatId, reason = 'flow_rotate') {
  if (!s || typeof s !== 'object') return '';
  s.sessionNonce = `sn_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,10)}`;
  s.sessionNonceAt = Date.now();
  if (chatId) s.ownerChatId = String(chatId);
  try { logSecurityEvent('session_nonce_rotated', { chatId: String(chatId || s.ownerChatId || ''), reason }); } catch (_) {}
  return s.sessionNonce;
}

