function getMergeablePendingOrdersForUser(chatId, currentSession = null) {
  const out = [];
  const now = Date.now();
  for (const [ref, p] of Object.entries(db.pendingPayments || {})) {
    if (!p || Number(p.chatId) !== Number(chatId)) continue;
    const createdAt = Number(p.createdAt || 0);
    if (createdAt && (now - createdAt) > 10 * 60 * 1000) continue;
    if (Array.isArray(currentSession?.cart) && currentSession.cart.length && Array.isArray(p.cartOrders) && p.cartOrders.length) {
      const sameCurrent = JSON.stringify(p.cartOrders) === JSON.stringify(currentSession.cart);
      if (sameCurrent) continue;
    }
    if (Array.isArray(p.cartOrders) && p.cartOrders.length) {
      for (const item of p.cartOrders) {
        out.push({
          ref: String(ref),
          category: String(item?.category || p.category || ''),
          pkgLabel: String(item?.pkgLabel || p.pkgLabel || ''),
          price: Number(item?.price || 0),
          phone254: String(item?.phone254 || p.phone254 || ''),
          receivePhone254: String(item?.receivePhone254 || item?.phone254 || p.receivePhone254 || p.phone254 || ''),
        });
      }
    } else {
      out.push({
        ref: String(ref),
        category: String(p.category || ''),
        pkgLabel: String(p.pkgLabel || ''),
        price: Number(p.price || 0),
        phone254: String(p.phone254 || ''),
        receivePhone254: String(p.receivePhone254 || p.phone254 || ''),
      });
    }
  }
  return out;
}

function removePendingOrdersByRefs(refs = []) {
  if (!Array.isArray(refs) || !refs.length) return;
  for (const ref of refs) {
    try { deletePendingPayment(String(ref)); } catch (_) {}
  }
}

