/**
 * Confirm keyboard with phone picker when ⚡ Fast Purchase is enabled.
 * Shows:
 *  - recent numbers (masked) selectable
 *  - ➕ Add Number
 *  - ✅ Proceed / 📞 Change Number
 *  - Prev
 */
function confirmKeyboardV2(chatId, s, hasSavedPhone) {
  // Default
  if (!chatId || !s || !isFastPurchaseEnabled(chatId)) return confirmKeyboard(hasSavedPhone, true, chatId);

  const rows = [];
  const multiEnabled = !!isMultiPurchaseEnabled(chatId);
  const cartHasItems = !!(s && Array.isArray(s.cart) && s.cart.length);
  const hasReceivePhone = !!getUserReceivePhone(chatId);
  s.fpPhoneMap = s.fpPhoneMap || {};
  const phones = getRecentPhonesFromTxLog(chatId, 10);

  if (multiEnabled) rows.push(["➕ Add to Cart"]);
  if (hasSavedPhone && hasReceivePhone) rows.push(["⏰ Auto Recommend"]);

  const actionRow = [];
  if (hasSavedPhone) actionRow.push("📲 Pay with M-Pesa STK");
  if (hasSavedPhone) actionRow.push("💼 Pay with Wallet");
  if (multiEnabled && cartHasItems) actionRow.push("🛒 View Orders in Cart");
  if (actionRow.length) rows.push(actionRow);

  for (const p of phones) {
    const label = `📱 ${maskPhone(p)}`;
    if (s.fpPhoneMap[label]) continue;
    s.fpPhoneMap[label] = p;
    rows.push([label]);
  }

  rows.push(["➕ Add Number"]);
  rows.push(["📞 Change Payment Number", "📥 Change Receive Number"]);
  rows.push([PREV_BTN, "🏠 Main Menu"]);

  return { reply_markup: { keyboard: rows, resize_keyboard: true, one_time_keyboard: false } };
}

// ✅ Reusable: proceed with purchase (STK) using the saved phone & current session data
async function proceedPurchase(chatId, s, options = {}) {
  if (isWalletLocked(chatId) && !isAdmin(chatId)) {
    return sendTracked(chatId, "⛔ Your wallet/account is locked for admin review. Purchases are temporarily disabled until the review is completed.", { ...mainMenuKeyboard(chatId) });
  }
  const paymentMethod = String(options?.method || "mpesa").toLowerCase();
  const isWalletFlow = paymentMethod === "wallet";
  const walletConfirmed = !!options?.confirmed;
  ensureSessionSecurityShape(s, chatId);
  assertCartOwnership(chatId, s);
  if (s.pendingPaymentOrder && s.pendingPaymentOrder.ref) return sendTracked(chatId, "⏳ This cart already has a pending payment. Finish or cancel that payment first.", { ...mainMenuKeyboard(chatId) });
  if (hitActionRateLimit(chatId, "checkout_attempt", 3, 2 * 60 * 1000)) return sendTracked(chatId, "⏳ Too many checkout attempts. Please wait a moment and try again.", { ...mainMenuKeyboard(chatId) });
  const cart = getSessionCartItems(s);
  if (checkoutLockActive(s)) return sendTracked(chatId, "⏳ Checkout already in progress for this cart. Please wait for the current STK request.", { ...cartKeyboard() });
  if (cart.length) {
    let workingCart = cart.slice();
    if (isMultiPurchaseEnabled(chatId)) {
      const pendingOrders = getMergeablePendingOrdersForUser(chatId, s);
      if (pendingOrders.length) {
        const existingKeys = new Set(workingCart.map((item) => `${item.category}||${item.pkgLabel}||${item.price}||${item.phone254}||${item.receivePhone254 || item.phone254}`));
        for (const order of pendingOrders) {
          const key = `${order.category}||${order.pkgLabel}||${order.price}||${order.phone254}||${order.receivePhone254 || order.phone254}`;
          if (!existingKeys.has(key)) {
            workingCart.push({ ...order });
            existingKeys.add(key);
          }
        }
        s.cart = workingCart.map((item) => ({ ...item }));
        sessions.set(chatId, s);
        removePendingOrdersByRefs([...new Set(pendingOrders.map((x) => x.ref).filter(Boolean))]);
      }
    }
    const first = workingCart[0] || {};
    const badItem = workingCart.find((item) => !item.phone254 || !(item.receivePhone254 || item.phone254));
    if (badItem) {
      s.step = "cart_review";
      sessions.set(chatId, s);
      return sendTracked(chatId, "❌ Every cart item must have both payment and receive numbers before checkout.", cartKeyboard());
    }
    const bingwaReview = filterLimitedBingwaCartItems(chatId, workingCart);
    if (bingwaReview.removed.length) {
      const removedLines = bingwaReview.removed.map((item) => `• ${item.pkgLabel} — ${maskPhone(item.bingwaCheckPhone254 || bingwaCheckPhoneFromItem(item) || item.receivePhone254 || item.phone254 || "")}`);
      if (!bingwaReview.eligible.length) {
        s.cart = [];
        s.step = "cart_review";
        clearCheckoutLock(s);
        setSessionAtomic(chatId, s, { cartMutated: true });
        return sendTracked(chatId, `🚫 *All Bingwa cart items reached the daily limit*

Removed items:
${removedLines.join("\n")}

No eligible Bingwa items remain for checkout today.`, { parse_mode: "Markdown", ...cartKeyboard() });
      }
      workingCart = bingwaReview.eligible.map((item) => ({ ...item }));
      s.cart = workingCart.map((item) => ({ ...item }));
      sessions.set(chatId, s);
      await sendTracked(chatId, `ℹ️ *Limited Bingwa items removed from cart*

${removedLines.join("\n")}

Checkout will continue with the remaining eligible items.`, { parse_mode: "Markdown", ...cartKeyboard() });
    }
    s.cart = workingCart.map((item) => normalizeCartItem({ ...item, ownerChatId: String(item?.ownerChatId || chatId) }));
    s.cartIntegrityHash = computeCartHash(s.cart);
    const review = revalidateCartForCheckout(chatId, s);
    if (!review.ok) {
      s.step = "cart_review";
      setSessionAtomic(chatId, s, { cartMutated: false });
      if (review.code === "price_changed") return sendTracked(chatId, `⚠️ Cart price changed for ${review.item?.pkgLabel || "an item"}. Please review your cart again.`, { ...cartKeyboard() });
      if (review.code === "package_missing") return sendTracked(chatId, `⚠️ ${review.item?.pkgLabel || "A cart item"} is no longer available. Please review your cart again.`, { ...cartKeyboard() });
      if (review.code === "total_limit") return sendTracked(chatId, `⚠️ Cart total exceeds the allowed checkout limit of Ksh ${CART_CHECKOUT_MAX_KSH}.`, { ...cartKeyboard() });
      return sendTracked(chatId, "⚠️ Cart validation failed. Please review your cart again.", { ...cartKeyboard() });
    }
    s.cart = review.cart.map((item) => ({ ...item }));
    const totalPkg = { label: `Cart Checkout (${review.cart.length} orders)`, price: review.total };
    startCheckoutLock(s);
    const stkSession = { ...s, category: "Cart Checkout", pkgKey: totalPkg.label, cart: review.cart.map((item) => ({ ...item })), checkoutSnapshot: review.cart.map((item) => ({ ...item })) };
    auditCartEvent(chatId, "checkout_start", { lineCount: review.cart.length, amount: review.total, paymentPhone: first.phone254, receivePhone: first.receivePhone254 || first.phone254 });
    setSessionAtomic(chatId, s);
    if (isWalletFlow) {
      const walletPending = { chatId, category: "Cart Checkout", pkgLabel: totalPkg.label, phone254: first.phone254, receivePhone254: first.receivePhone254 || first.phone254, price: review.total, cartOrders: review.cart.map((item) => ({ ...item })) };
      if (!walletConfirmed) {
        clearCheckoutLock(s);
        setSessionAtomic(chatId, s, { cartMutated: false });
        return startWalletCheckoutConfirmation(chatId, walletPending, { scope: "session_purchase" });
      }
      return completeWalletCheckout(chatId, walletPending);
    }
    return initiatePurchaseStk(chatId, stkSession, totalPkg, first.phone254, first.receivePhone254 || first.phone254);
  }

  const savedPhone = getUserPhone(chatId);
  if (!savedPhone) {
    pushPrev(chatId, s);
    s.step = "phone";
    sessions.set(chatId, s);
    return sendTracked(
      chatId,
      `📱 Send your PAYMENT number:
Current: ${maskPhone(getUserPhone(chatId) || "") || "Not set"}
• 07XXXXXXXX
• 01XXXXXXXX
• 2547XXXXXXXX
• 2541XXXXXXXX`,
      confirmKeyboard(false, !!(s.receivePhone254 || getUserReceivePhone(chatId)), chatId)
    );
  }

  const receivePhone = s.receivePhone254 || getUserReceivePhone(chatId);
  if (!receivePhone) {
    pushPrev(chatId, s);
    s.step = "receive_phone";
    sessions.set(chatId, s);
    return sendTracked(
      chatId,
      `📥 Send your RECEIVE number:
Current: ${maskPhone(getUserReceivePhone(chatId) || getUserPhone(chatId) || "") || "Not set"}
• 07XXXXXXXX
• 01XXXXXXXX
• 2547XXXXXXXX
• 2541XXXXXXXX`,
      confirmKeyboard(true, false, chatId)
    );
  }

  const pkg = findPackageByLabel(s.category, s.pkgKey);
  if (!pkg) {
    sessions.delete(chatId);
    return sendTracked(chatId, "⚠️ Offer not found. Please try again.", { ...mainMenuKeyboard(chatId) });
  }

  if (isWalletFlow) {
    const walletPending = { chatId, category: s.category, pkgLabel: pkg.label, phone254: savedPhone, receivePhone254: receivePhone, price: pkg.price, sourceChatId: s?.sourceChatId || null };
    if (!walletConfirmed) {
      return startWalletCheckoutConfirmation(chatId, walletPending, { scope: "session_purchase" });
    }
    return completeWalletCheckout(chatId, walletPending);
  }
  return initiatePurchaseStk(chatId, s, pkg, savedPhone, receivePhone);
}




