function categoryNameFromButton(text) {
  const t = String(text || "").trim().toLowerCase();

  // Accept English button labels (and partial matches).
  // We intentionally use includes() checks to be resilient to emojis/prefixes.
  if ((t.includes("bingwa") && t.includes("deals")) || (t.includes("bingwa") && t.includes("deal"))) return "Bingwa Deals";

  // Unlimited Deals: "∞ Unlimited Deals" / "∞ Ofa Zisizo na Kikomo"
  if ((t.includes("unlimited") && t.includes("deals")) || (t.includes("zisizo") && t.includes("kikomo")) || t.includes("kikomo")) return "Unlimited Deals";

  // SMS Offers: "✉️ SMS Offers" / "✉️ Ofa za SMS"
  if (t.includes("sms") || (t.includes("ofa") && t.includes("sms"))) return "SMS Offers";

  // Minutes: "📞 Minutes" / "📞 Dakika"
  if (t.includes("minutes") || t.includes("dakika")) return "Minutes";

  // Bonga Points: "⭐ Bonga Points" / "⭐ Pointi za Bonga"
  if (t.includes("bonga") || (t.includes("pointi") && t.includes("bonga"))) return "Bonga Points";

  // Flex Deals: "🌀 Flex Deals" / "🌀 Ofa za Flex"
  if (t.includes("flex") || (t.includes("ofa") && t.includes("flex"))) return "Flex Deals";

  return null;
}

function findPackageByLabel(category, label) {
  const list = PACKAGES[category] || [];
  return list.find((x) => x.label === label) || null;
}

// ===================== REFERRAL HANDLING =====================
function applyReferralIfAny(chatId, payload) {
  if (!payload || typeof payload !== "string") return;
  if (!payload.startsWith("ref_")) return;
  const inviter = payload.slice(4).trim();
  if (!/^\d+$/.test(inviter)) return;
  if (String(inviter) === String(chatId)) return;

  const u = getUser(chatId);
  if (!u.inviterId) {
    u.inviterId = String(inviter);
    u.inviterSetAt = Date.now();
    saveDB();

    // Notify inviter + admin (unless inviter disabled referral notifications)
    try {
      if (!isStopReferralNotifs(inviter)) {
        bot.sendMessage(
          Number(inviter),
          `🎉 New referral joined!

Someone joined using your link.
✅ When they make a successful purchase, you earn referral points.`
        ).catch(() => {});
      }
    } catch (_) {}

    try {
      if (!isStopReferralNotifs(inviter)) {
        notifyAdmin(
          `👥 *New Referral Join*
Inviter: \`${mdEscape(inviter)}\`
New user: \`${mdEscape(chatId)}\`
Time: \`${mdEscape(kenyaDateTime())}\``
        );
      }
    } catch (_) {}
  }
}

const PROMO_CLICK_POINTS = 0.5;

function promoSourceToken(ownerId, sourceId) {
  return `${String(ownerId || "").trim()}__${String(sourceId || "").trim()}`;
}

function encodePromoStartPayload(ownerId, sourceId) {
  return `promo_${String(ownerId || "").trim()}_${String(sourceId || "").trim()}`;
}

function parsePromoStartPayload(payload) {
  const m = String(payload || "").trim().match(/^promo_(\d+)_(-?\d+)$/i);
  if (!m) return null;
  return { ownerId: String(m[1] || ""), sourceId: String(m[2] || "") };
}

function wrapPromoUrlForOwner(rawUrl, ownerId, sourceId) {
  const owner = String(ownerId || "").trim();
  const source = String(sourceId || "").trim();
  if (!owner || !/^\d+$/.test(owner)) return normalizePromoUrl(rawUrl);

  const raw = String(rawUrl || "").trim();
  const botName = String(BOT_USERNAME || "").replace(/^@/, "").trim();
  const startPayload = encodePromoStartPayload(owner, source || owner);

  if (!raw) return `https://t.me/${botName}?start=${startPayload}`;

  const m = raw.match(/^(?:https?:\/\/)?t\.me\/([^/?#]+)(?:\?([^#]+))?/i);
  if (!m) return normalizePromoUrl(raw);

  const target = String(m[1] || "").replace(/^@/, "").trim();
  if (!target || target.toLowerCase() !== botName.toLowerCase()) return normalizePromoUrl(raw);

  return `https://t.me/${botName}?start=${startPayload}`;
}

function claimPromoClickPoints(chatId, payload) {
  try {
    const parsed = parsePromoStartPayload(payload);
    if (!parsed) return false;

    const ownerId = String(parsed.ownerId || "");
    const sourceId = String(parsed.sourceId || ownerId);
    if (!/^\d+$/.test(ownerId)) return false;
    if (String(ownerId) === String(chatId)) return false;

    db = repairDB(db);

    // Prevent the SAME user from earning points for different channels/groups more than once.
    const globalKey = `global:${String(chatId)}`;
    if (db.promoClicksClaimed[globalKey]) return false;

    const sourceKey = `${ownerId}:${sourceId}:${chatId}`;
    if (db.promoClicksClaimed[sourceKey]) return false;

    db.promoClicksClaimed[globalKey] = Date.now();
    db.promoClicksClaimed[sourceKey] = Date.now();
    db.promoLinkOwners[promoSourceToken(ownerId, sourceId)] = {
      ownerId,
      sourceId,
      updatedAt: Date.now()
    };

    addPoints(ownerId, PROMO_CLICK_POINTS);

    db = repairDB(db);
    db.promoClicksStats.totalClicks = Number(db.promoClicksStats.totalClicks || 0) + 1;
    db.promoClicksStats.totalPoints = Number(db.promoClicksStats.totalPoints || 0) + PROMO_CLICK_POINTS;
    saveDB();

    try {
      if (!isStopReferralNotifs(ownerId)) {
        bot.sendMessage(
          Number(ownerId),
          `🎯 Promo click earned!

You earned ${PROMO_CLICK_POINTS} point from a channel/group promo click.
User: ${chatId}`
        ).catch(() => {});
      }
    } catch (_) {}

    return true;
  } catch (_) {
    return false;
  }
}

// ✅ Referral bonus credit ONLY on SUCCESS callback; bonus = 2% of amount paid
function maybeRewardInviterOnSuccessPurchase(buyerChatId, amountKsh, when, receivePhoneInput = "") {
  const buyer = getUser(buyerChatId);
  if (buyer?.sourceChatId && isRewardsFrozenForChat(buyer.sourceChatId)) return;

  const receiveOwner = resolveReferralOwnerFromReceiveNumber(
    buyerChatId,
    receivePhoneInput || buyer?.receivePhone || getUserReceivePhone(buyerChatId)
  );

  let inviterId = "";
  let setAt = 0;
  let ownerBased = false;

  if (receiveOwner && receiveOwner.ownerChatId && String(receiveOwner.ownerChatId) !== String(buyerChatId)) {
    inviterId = String(receiveOwner.ownerChatId);
    setAt = Number(receiveOwner.firstSeenAt || 0);
    ownerBased = true;
    buyer.inviterId = inviterId;
    buyer.inviterSetAt = setAt || Date.now();
    saveDB();
  } else {
    inviterId = buyer.inviterId;
    setAt = Number(buyer.inviterSetAt || 0);
  }

  if (!inviterId) return;

  // Legacy link-based referral window applies only when not using receive-number ownership
  const maxAgeMs = Number(REFERRAL.EXPIRY_DAYS || 30) * 24 * 60 * 60 * 1000;
  if (!ownerBased && (!setAt || Date.now() - setAt > maxAgeMs)) return;

  const amt = Number(amountKsh || 0);
  if (!Number.isFinite(amt) || amt <= 0) return;

  const bonus = amt * REFERRAL.BONUS_PERCENT;
  if (!Number.isFinite(bonus) || bonus <= 0) return;

  addPoints(inviterId, bonus);

  if (!buyer.referralCounted) {
    const inv = getUser(inviterId);
    inv.referralSuccessCount = Number(inv.referralSuccessCount || 0) + 1;
    buyer.referralCounted = true;
    saveDB();
  }

  const cleanBonus = parseFloat(bonus.toFixed(2));
  const inv = getUser(inviterId);
  inv.referralEarningsTotal = Number(inv.referralEarningsTotal || 0) + cleanBonus;
  inv.referralEarningsByDay = inv.referralEarningsByDay && typeof inv.referralEarningsByDay === "object" ? inv.referralEarningsByDay : {};
  const dayKey = kenyaDayKey();
  inv.referralEarningsByDay[dayKey] = Number(inv.referralEarningsByDay[dayKey] || 0) + cleanBonus;
  saveDB();

  if (!isStopReferralNotifs(inviterId)) notifyAdmin(
    `🎯 *Referral Reward*\n` +
    `Inviter: \`${mdEscape(inviterId)}\`\n` +
    `Buyer: \`${mdEscape(buyerChatId)}\`\n` +
    `Receive Number: *${mdEscape(maskPhone((receiveOwner && receiveOwner.phone254) || normalizePhone(receivePhoneInput || buyer?.receivePhone || getUserReceivePhone(buyerChatId) || "") || "N/A"))}*\n` +
    `Purchase: *Ksh ${mdEscape(amt)}*\n` +
    `Bonus: *${mdEscape(cleanBonus)}pts*\n` +
    `Mode: *${ownerBased ? "receive-owner" : "link"}*\n` +
    `Time: \`${mdEscape(String(when || kenyaDateTime()))}\``
  );
}


