bot.on("callback_query", async (q) => {
  try {
    const data = String(q.data || "");
    if (data !== "biz:manage") return;

    const chatId = q.message?.chat?.id;
    if (!chatId) return;

    try { await bot.answerCallbackQuery(q.id); } catch (_) {}

    const u = getUser(chatId);

    const header = isBusinessActive(chatId)
      ? "⚙️ *Manage Business Account*\n\nTap your ✅ active plan to deactivate, or choose another plan to subscribe."
      : "✅ *Activate Business Account*\n\nChoose a plan to subscribe:";

    await sendTracked(
      chatId,
      header,
      { parse_mode: "Markdown", ...sellKeyboard(chatId) }
    );
  } catch (_) {}
});






// ============================================================================
// ✅ AUTO CLEANUP FOR FORCE-JOIN CHANNELS
// ============================================================================

async function ensureJoinedChannel(chatId) {
  const channels = getForceJoinChannels();
  if (!channels.length) return true;

  let cleaned = false;
  const validChannels = [];
  let botInfo = null;

  try { botInfo = await bot.getMe(); } catch (_) {}

  for (const channel of channels) {
    try {
      if (!botInfo || !botInfo.id) {
        cleaned = true;
        continue;
      }

      const botMember = await bot.getChatMember(channel, botInfo.id);
      const botStatus = String(botMember && botMember.status || "");
      const botIsAdmin = (botStatus === "administrator" || botStatus === "creator");

      if (!botIsAdmin) {
        cleaned = true;
        continue;
      }

      validChannels.push(channel);

      const m = await bot.getChatMember(channel, chatId);
      const s = m && m.status;
      const ok = (s === "member" || s === "administrator" || s === "creator");
      if (!ok) return false;
    } catch (e) {
      cleaned = true;
      continue;
    }
  }

  if (cleaned) {
    try { saveForceJoinChannels(validChannels); } catch (_) {}
  }

  return true;
}

// ============================================================================
// ✅ CHANNEL / GROUP AUTO-WELCOME PROMO BROADCAST
// - When bot is added as admin to a channel/group, wait 3 minutes
// - Send saved promo (text / photo / video / album)
// - Add inline button (Click Now / Join Now / Buy Now / custom)
// - Auto-pin the promo message
// - Admin can edit promo using commands below in private chat
// ============================================================================

function ensureChannelPromoStore() {
  db = repairDB(db);

  if (!db.channelPromo || typeof db.channelPromo !== "object") db.channelPromo = {};
  if (!db.channelPromo.config || typeof db.channelPromo.config !== "object") {
    db.channelPromo.config = {
      mode: "text", // text | photo | video | album
      text: "",
      caption: "",
      media: [],
      buttonText: "BUY NOW",
      buttonUrl: "",
      delayMs: 3 * 60 * 1000,
      unpinOld: true,
      pinNew: true
    };
  }
  if (!db.channelPromo.sentChats || typeof db.channelPromo.sentChats !== "object") db.channelPromo.sentChats = {};
  if (!db.channelPromo.pending || typeof db.channelPromo.pending !== "object") db.channelPromo.pending = {};
  if (!db.channelPromo.albumBuffer || typeof db.channelPromo.albumBuffer !== "object") db.channelPromo.albumBuffer = {};
  if (!db.channelPromo.editState || typeof db.channelPromo.editState !== "object") db.channelPromo.editState = {};
  if (!db.channelPromo.repost || typeof db.channelPromo.repost !== "object") {
    db.channelPromo.repost = {
      enabled: false,
      intervalMs: 24 * 60 * 60 * 1000,
      targetMode: "all",
      targetChatId: "",
      deletePrevious: true,
      nextRunAt: 0
    };
  }
  return db.channelPromo;
}

function channelPromoCfg() {
  return ensureChannelPromoStore().config;
}

function promoAdmin(chatId) {
  try { return Number(chatId) === Number(ADMIN_ID); } catch (_) { return false; }
}

function normalizePromoUrl(url) {
  const raw = String(url || "").trim();
  if (!raw) return "";
  if (/^https?:\/\//i.test(raw)) return raw;
  if (/^t\.me\//i.test(raw)) return "https://" + raw;
  if (/^@[\w_]{4,}$/i.test(raw)) return "https://t.me/" + raw.replace(/^@/, "");
  return raw;
}

function promoButtonKeyboard(ownerId = "", sourceId = "") {
  const cfg = channelPromoCfg();
  if (!cfg.buttonText || !cfg.buttonUrl) return null;
  const finalUrl = wrapPromoUrlForOwner(cfg.buttonUrl, ownerId, sourceId);
  return {
    reply_markup: {
      inline_keyboard: [[{ text: String(cfg.buttonText || "Open"), url: finalUrl }]]
    }
  };
}

function setChannelPromoEditState(chatId, state) {
  const store = ensureChannelPromoStore();
  if (state) store.editState[String(chatId)] = state;
  else delete store.editState[String(chatId)];
  saveDB();
}

function getChannelPromoEditState(chatId) {
  const store = ensureChannelPromoStore();
  return store.editState[String(chatId)] || null;
}

function clearChannelPromoEditState(chatId) {
  setChannelPromoEditState(chatId, null);
}

function setChannelPromoFromText(textValue) {
  const cfg = channelPromoCfg();
  cfg.mode = "text";
  cfg.text = String(textValue || "").trim();
  cfg.caption = "";
  cfg.media = [];
  saveDB();
}

function setChannelPromoButton(buttonText, buttonUrl) {
  const cfg = channelPromoCfg();
  cfg.buttonText = String(buttonText || "").trim() || "BUY NOW";
  cfg.buttonUrl = normalizePromoUrl(buttonUrl);
  saveDB();
}

function setChannelPromoDelayMinutes(minutes) {
  const cfg = channelPromoCfg();
  const n = Math.max(0, Number(minutes || 3));
  cfg.delayMs = Math.round(n * 60 * 1000);
  saveDB();
}

function markChannelPromoSent(chatId) {
  const store = ensureChannelPromoStore();
  store.sentChats[String(chatId)] = Date.now();
  saveDB();
}

function wasChannelPromoSent(chatId) {
  const store = ensureChannelPromoStore();
  return !!store.sentChats[String(chatId)];
}

function clearChannelPromoSent(chatId) {
  const store = ensureChannelPromoStore();
  delete store.sentChats[String(chatId)];
  saveDB();
}

function channelPromoRepostCfg() {
  return ensureChannelPromoStore().repost;
}

function setChannelPromoRepostSchedule(ms) {
  const cfg = channelPromoRepostCfg();
  cfg.enabled = true;
  cfg.intervalMs = Math.max(1000, Number(ms || 0));
  cfg.nextRunAt = Date.now() + cfg.intervalMs;
  saveDB();
}

function setChannelPromoRepostTarget(mode, targetChatId = "") {
  const cfg = channelPromoRepostCfg();
  cfg.targetMode = String(mode || "all");
  cfg.targetChatId = String(targetChatId || "");
  saveDB();
}

async function sendConfiguredChannelPromoToTarget(targetChatId, opts = {}) {
  const cfg = channelPromoCfg();
  const repostCfg = channelPromoRepostCfg();
  let pinMessageId = null;

  if (opts.deletePrevious || repostCfg.deletePrevious) {
    try {
      const rec = ensurePromoChannelMetric(targetChatId);
      if (rec.lastPromoMessageId) {
        await bot.deleteMessage(targetChatId, rec.lastPromoMessageId).catch(() => {});
      }
    } catch (_) {}
  }

  if (cfg.unpinOld) {
    try { await bot.unpinAllChatMessages(targetChatId); } catch (_) {}
  }

  const ownerRecKey = Object.keys((db && db.promoLinkOwners) ? db.promoLinkOwners : {}).find((k) => String(k).endsWith(`__${String(targetChatId)}`));
  const ownerId = ownerRecKey && db.promoLinkOwners[ownerRecKey] ? String(db.promoLinkOwners[ownerRecKey].ownerId || "") : "";
  const kb = promoButtonKeyboard(ownerId, targetChatId);

  if (Array.isArray(cfg.media) && cfg.media.length) {
    const m0 = cfg.media[0];
    if (m0 && m0.file_id) {
      if (m0.type === "video") {
        const sent = await bot.sendVideo(targetChatId, m0.file_id, {
          caption: String(cfg.caption || cfg.text || ""),
          ...(kb || {})
        }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      } else {
        const sent = await bot.sendPhoto(targetChatId, m0.file_id, {
          caption: String(cfg.caption || cfg.text || ""),
          ...(kb || {})
        }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      }
    }
  } else {
    const sent = await bot.sendMessage(targetChatId, String(cfg.text || cfg.caption || ""), kb || {}).catch(() => null);
    if (sent && sent.message_id) pinMessageId = sent.message_id;
  }

  if (cfg.pinNew && pinMessageId) {
    try { await bot.pinChatMessage(targetChatId, pinMessageId, { disable_notification: true }); } catch (_) {}
  }
  if (pinMessageId) {
    try { trackPromoSend(targetChatId, pinMessageId); } catch (_) {}
  }
  return !!pinMessageId;
}

async function runChannelPromoRepostIfDue() {
  try {
    ensureChannelPromoStore();
    const rcfg = channelPromoRepostCfg();
    if (!rcfg.enabled) return;
    if (!rcfg.intervalMs || Date.now() < Number(rcfg.nextRunAt || 0)) return;

    const targets = [];
    if (String(rcfg.targetMode || "all") === "all") {
      const metrics = ensureChannelPromoMetricsStore();
      for (const [cid, rec] of Object.entries(metrics.byChannel || {})) {
        if (rec && rec.active) targets.push(cid);
      }
    } else if (rcfg.targetChatId) {
      targets.push(String(rcfg.targetChatId));
    }

    for (const targetId of targets) {
      await sendConfiguredChannelPromoToTarget(targetId, { deletePrevious: !!rcfg.deletePrevious }).catch(() => {});
    }

    rcfg.nextRunAt = Date.now() + Number(rcfg.intervalMs || 0);
    saveDB();
  } catch (_) {}
}

async function sendChannelPromoPreview(chatId) {
  const cfg = channelPromoCfg();
  const kb = promoButtonKeyboard("", "");
  const summary =
    `📣 Channel Promo Preview\n\n` +
    `Mode: ${cfg.mode}\n` +
    `Button: ${cfg.buttonText || "(none)"}\n` +
    `Link: ${cfg.buttonUrl || "(none)"}\n` +
    `Delay: ${Math.round(Number(cfg.delayMs || 180000) / 60000)} minute(s)\n` +
    `Pin new: ${cfg.pinNew ? "ON" : "OFF"}\n` +
    `Unpin old: ${cfg.unpinOld ? "ON" : "OFF"}`;

  await bot.sendMessage(chatId, summary).catch(() => {});

  if (cfg.mode === "album" && Array.isArray(cfg.media) && cfg.media.length) {
    const media = cfg.media.map((m, i) => {
      const item = { type: String(m.type || "photo"), media: String(m.file_id || "") };
      if (i === 0 && (cfg.caption || cfg.text)) item.caption = String(cfg.caption || cfg.text || "");
      return item;
    }).filter(x => x.media);

    if (media.length) {
      await bot.sendMediaGroup(chatId, media).catch(() => {});
      if (kb) await bot.sendMessage(chatId, "🔘 Promo button preview", kb).catch(() => {});
      return;
    }
  }

  if (cfg.mode === "photo" && Array.isArray(cfg.media) && cfg.media[0] && cfg.media[0].file_id) {
    await bot.sendPhoto(chatId, cfg.media[0].file_id, {
      caption: String(cfg.caption || cfg.text || ""),
      ...(kb || {})
    }).catch(() => {});
    return;
  }

  if (cfg.mode === "video" && Array.isArray(cfg.media) && cfg.media[0] && cfg.media[0].file_id) {
    await bot.sendVideo(chatId, cfg.media[0].file_id, {
      caption: String(cfg.caption || cfg.text || ""),
      ...(kb || {})
    }).catch(() => {});
    return;
  }

  await bot.sendMessage(chatId, String(cfg.text || cfg.caption || "No promo set yet."), kb || {}).catch(() => {});
}

async function sendConfiguredChannelPromo(targetChatId) {
  const cfg = channelPromoCfg();
  const kb = promoButtonKeyboard("", "");
  let pinMessageId = null;

  if (cfg.unpinOld) {
    try { await bot.unpinAllChatMessages(targetChatId); } catch (_) {}
  }

  if (cfg.mode === "album" && Array.isArray(cfg.media) && cfg.media.length) {
    const media = cfg.media.map((m, i) => {
      const item = { type: String(m.type || "photo"), media: String(m.file_id || "") };
      if (i === 0 && (cfg.caption || cfg.text)) item.caption = String(cfg.caption || cfg.text || "");
      return item;
    }).filter(x => x.media);

    if (media.length) {
      const sent = await bot.sendMediaGroup(targetChatId, media).catch(() => null);
      if (Array.isArray(sent) && sent.length) pinMessageId = sent[0].message_id;
      if (kb) {
        const btnMsg = await bot.sendMessage(targetChatId, "👇", kb).catch(() => null);
        if (!pinMessageId && btnMsg && btnMsg.message_id) pinMessageId = btnMsg.message_id;
      }
    }
  } else if (cfg.mode === "photo" && Array.isArray(cfg.media) && cfg.media[0] && cfg.media[0].file_id) {
    const sent = await bot.sendPhoto(targetChatId, cfg.media[0].file_id, {
      caption: String(cfg.caption || cfg.text || ""),
      ...(kb || {})
    }).catch(() => null);
    if (sent && sent.message_id) pinMessageId = sent.message_id;
  } else if (cfg.mode === "video" && Array.isArray(cfg.media) && cfg.media[0] && cfg.media[0].file_id) {
    const sent = await bot.sendVideo(targetChatId, cfg.media[0].file_id, {
      caption: String(cfg.caption || cfg.text || ""),
      ...(kb || {})
    }).catch(() => null);
    if (sent && sent.message_id) pinMessageId = sent.message_id;
  } else {
    const sent = await bot.sendMessage(targetChatId, String(cfg.text || cfg.caption || ""), kb || {}).catch(() => null);
    if (sent && sent.message_id) pinMessageId = sent.message_id;
  }

  if (cfg.pinNew && pinMessageId) {
    try { await bot.pinChatMessage(targetChatId, pinMessageId, { disable_notification: true }); } catch (_) {}
  }

  return !!pinMessageId;
}

async function scheduleChannelPromoForChat(chat) {
  try {
    if (!chat || !chat.id) return;
    ensureChannelPromoStore();
    const key = String(chat.id);
    const store = db.channelPromo;

    if (store.pending[key] || wasChannelPromoSent(chat.id)) return;

    store.pending[key] = {
      scheduledAt: Date.now(),
      runAt: Date.now() + Number(channelPromoCfg().delayMs || (3 * 60 * 1000)),
      type: String(chat.type || "")
    };
    saveDB();

    setTimeout(async () => {
      try {
        ensureChannelPromoStore();
        const pending = db.channelPromo.pending[key];
        if (!pending) return;

        try {
          const me = await bot.getMe();
          const botMember = await bot.getChatMember(chat.id, me.id);
          const status = String(botMember && botMember.status || "");
          const botOk = (status === "administrator" || status === "creator");
          if (!botOk) {
            delete db.channelPromo.pending[key];
            saveDB();
            return;
          }
        } catch (_) {
          delete db.channelPromo.pending[key];
          saveDB();
          return;
        }

        const sent = await sendConfiguredChannelPromo(chat.id);
        delete db.channelPromo.pending[key];
        if (sent) markChannelPromoSent(chat.id);
        else saveDB();
      } catch (_) {
        try {
          delete db.channelPromo.pending[key];
          saveDB();
        } catch (_) {}
      }
    }, Math.max(1000, Number(channelPromoCfg().delayMs || (3 * 60 * 1000))));
  } catch (_) {}
}

function appendPromoAlbumBufferItem(chatId, mediaGroupId, item) {
  const store = ensureChannelPromoStore();
  const key = String(chatId) + ":" + String(mediaGroupId);

  if (!store.albumBuffer[key]) store.albumBuffer[key] = { items: [] };
  store.albumBuffer[key].items.push(item);
  saveDB();

  setTimeout(async () => {
    try {
      const current = ensureChannelPromoStore().albumBuffer[key];
      if (!current || !Array.isArray(current.items) || !current.items.length) return;

      const state = getChannelPromoEditState(chatId);
      if (!state || state.mode !== "await_promo_media") return;

      const cfg = channelPromoCfg();
      cfg.mode = "album";
      cfg.media = current.items.map((x) => ({ type: x.type, file_id: x.file_id }));
      const firstCaptionItem = current.items.find((x) => x.caption);
      cfg.caption = String(firstCaptionItem ? firstCaptionItem.caption : "");
      cfg.text = cfg.caption || "";
      saveDB();

      delete db.channelPromo.albumBuffer[key];
      clearChannelPromoEditState(chatId);
      saveDB();

      await bot.sendMessage(chatId, "✅ Promo album saved.").catch(() => {});
    } catch (_) {}
  }, 1800);
}

bot.on("my_chat_member", async (update) => {
  try {
    const chat = update && update.chat;
    const oldStatus = String(update && update.old_chat_member && update.old_chat_member.status || "");
    const newStatus = String(update && update.new_chat_member && update.new_chat_member.status || "");
    const chatType = String(chat && chat.type || "");

    if (!chat || !["group", "supergroup", "channel"].includes(chatType)) return;

    const becameAdmin = (newStatus === "administrator" || newStatus === "creator") &&
                        oldStatus !== "administrator" && oldStatus !== "creator";
    if (!becameAdmin) return;

    try {
      db = repairDB(db);
      db.promoLinkOwners[promoSourceToken(update?.from?.id || "", chat?.id || "")] = {
        ownerId: String(update?.from?.id || ""),
        sourceId: String(chat?.id || ""),
        chatTitle: String(chat?.title || ""),
        updatedAt: Date.now()
      };
      saveDB();
    } catch (_) {}

    await scheduleChannelPromoForChat(chat);
  } catch (_) {}
});

bot.on("message", async (msg) => {
  try {
    const chatId = msg && msg.chat && msg.chat.id;
    if (!chatId || !promoAdmin(chatId) || String(msg && msg.chat && msg.chat.type || "") !== "private") return;

    ensureChannelPromoStore();

    const text = String(msg && msg.text || "").trim();

    if (/^\/setchannelpromo(?:@\w+)?$/i.test(text)) {
      setChannelPromoEditState(chatId, { mode: "await_promo_media" });
      await bot.sendMessage(
        chatId,
        "Send the promo now.\n\nSupported:\n- text\n- photo\n- video\n- album\n\nCaption will be used as promo text."
      ).catch(() => {});
      return;
    }

    if (/^\/setchannelpromotext(?:@\w+)?\s+([\s\S]+)$/i.test(text)) {
      const m = text.match(/^\/setchannelpromotext(?:@\w+)?\s+([\s\S]+)$/i);
      setChannelPromoFromText(m ? m[1] : "");
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Channel promo text updated.").catch(() => {});
      return;
    }

    if (/^\/setpromobutton(?:@\w+)?\s+([\s\S]+)$/i.test(text)) {
      const m = text.match(/^\/setpromobutton(?:@\w+)?\s+([\s\S]+)$/i);
      const raw = String(m && m[1] || "");
      const parts = raw.split("|");
      const buttonText = String(parts[0] || "").trim();
      const buttonUrl = String(parts.slice(1).join("|") || "").trim();

      if (!buttonText || !buttonUrl) {
        await bot.sendMessage(chatId, "Usage: /setpromobutton BUY NOW | https://t.me/yourbot").catch(() => {});
        return;
      }

      setChannelPromoButton(buttonText, buttonUrl);
      await bot.sendMessage(chatId, "✅ Promo button updated.").catch(() => {});
      return;
    }

    if (/^\/setchannelpromodelay(?:@\w+)?\s+(\d+(?:\.\d+)?)$/i.test(text)) {
      const m = text.match(/^\/setchannelpromodelay(?:@\w+)?\s+(\d+(?:\.\d+)?)$/i);
      setChannelPromoDelayMinutes(Number(m && m[1] || 3));
      await bot.sendMessage(chatId, "✅ Promo delay updated.").catch(() => {});
      return;
    }

    if (/^\/previewchannelpromo(?:@\w+)?$/i.test(text)) {
      await sendChannelPromoPreview(chatId);
      return;
    }

    if (/^\/clearchannelpromo(?:@\w+)?$/i.test(text)) {
      const cfg = channelPromoCfg();
      cfg.mode = "text";
      cfg.text = "";
      cfg.caption = "";
      cfg.media = [];
      saveDB();
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Promo cleared.").catch(() => {});
      return;
    }

    if (/^\/resetchannelpromochat(?:@\w+)?\s+(-?\d+)$/i.test(text)) {
      const m = text.match(/^\/resetchannelpromochat(?:@\w+)?\s+(-?\d+)$/i);
      const target = String(m && m[1] || "");
      clearChannelPromoSent(target);
      await bot.sendMessage(chatId, `✅ Reset promo sent flag for chat ${target}`).catch(() => {});
      return;
    }

    const state = getChannelPromoEditState(chatId);
    if (!state || state.mode !== "await_promo_media") return;

    if (msg && msg.media_group_id) {
      const photo = Array.isArray(msg.photo) && msg.photo.length ? msg.photo[msg.photo.length - 1] : null;
      const video = msg.video || null;
      const item = photo
        ? { type: "photo", file_id: photo.file_id, caption: String(msg.caption || "") }
        : (video ? { type: "video", file_id: video.file_id, caption: String(msg.caption || "") } : null);

      if (item) appendPromoAlbumBufferItem(chatId, msg.media_group_id, item);
      return;
    }

    if (Array.isArray(msg.photo) && msg.photo.length) {
      const cfg = channelPromoCfg();
      cfg.mode = "photo";
      cfg.media = [{ type: "photo", file_id: msg.photo[msg.photo.length - 1].file_id }];
      cfg.caption = String(msg.caption || "");
      cfg.text = cfg.caption || "";
      saveDB();
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Promo photo saved.").catch(() => {});
      return;
    }

    if (msg.video && msg.video.file_id) {
      const cfg = channelPromoCfg();
      cfg.mode = "video";
      cfg.media = [{ type: "video", file_id: msg.video.file_id }];
      cfg.caption = String(msg.caption || "");
      cfg.text = cfg.caption || "";
      saveDB();
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Promo video saved.").catch(() => {});
      return;
    }

    if (text && !text.startsWith("/")) {
      setChannelPromoFromText(text);
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Promo text saved.").catch(() => {});
      return;
    }
  } catch (_) {}
});

