function channelPromoAdminKeyboard() {
  const cfg = channelPromoCfg();
  const mode = String(cfg.mode || "text").toUpperCase();
  const delayMin = Math.round(Number(cfg.delayMs || 180000) / 60000);
  const pinMark = cfg.pinNew ? "✅" : "⬜️";
  const unpinMark = cfg.unpinOld ? "✅" : "⬜️";

  return {
    reply_markup: {
      inline_keyboard: [
        [{ text: `📣 Mode: ${mode}`, callback_data: "cpadm:noop" }],
        [{ text: "📝 Set Text", callback_data: "cpadm:set_text" }, { text: "🖼 Set Media", callback_data: "cpadm:set_media" }],
        [{ text: "🔘 Set Button", callback_data: "cpadm:set_button" }, { text: `⏱ Delay: ${delayMin}m`, callback_data: "cpadm:set_delay" }],
        [{ text: `${pinMark} Auto Pin`, callback_data: "cpadm:toggle_pin" }, { text: `${unpinMark} Unpin Old`, callback_data: "cpadm:toggle_unpin" }],
        [{ text: "👀 Preview", callback_data: "cpadm:preview" }, { text: "🧹 Clear Promo", callback_data: "cpadm:clear" }],
        [{ text: "♻️ Reset Chat Flag", callback_data: "cpadm:reset_chat" }, { text: "❌ Close", callback_data: "cpadm:close" }]
      ]
    }
  };
}

function channelPromoAdminText() {
  const cfg = channelPromoCfg();
  const rcfg = channelPromoRepostCfg();
  const mode = String(cfg.mode || "text");
  const delayMin = Math.round(Number(cfg.delayMs || 180000) / 60000);
  const mediaCount = Array.isArray(cfg.media) ? cfg.media.length : 0;
  const btnText = String(cfg.buttonText || "").trim() || "(none)";
  const btnUrl = String(cfg.buttonUrl || "").trim() || "(none)";
  const targetText = String(rcfg.targetMode || "all") === "all" ? "All active channels/groups" : (String(rcfg.targetChatId || "") || "(not set)");
  const intervalText = Number(rcfg.intervalMs || 0) >= 1000 ? `${Number(rcfg.intervalMs || 0)} ms` : "OFF";

  return (
    "📣 CHANNEL PROMO ADMIN\n\n" +
    `Mode: ${mode}\n` +
    `Media items: ${mediaCount}\n` +
    `Button: ${btnText}\n` +
    `Link: ${btnUrl}\n` +
    `Delay: ${delayMin} minute(s)\n` +
    `Pin new: ${cfg.pinNew ? "ON" : "OFF"}\n` +
    `Unpin old: ${cfg.unpinOld ? "ON" : "OFF"}\n` +
    `Auto repost: ${rcfg.enabled ? "ON" : "OFF"}\n` +
    `Repost interval: ${intervalText}\n` +
    `Repost target: ${targetText}\n` +
    `Delete previous repost: ${rcfg.deletePrevious ? "ON" : "OFF"}\n\n` +
    "Use the buttons below to edit the auto promo that is sent after the bot becomes admin in a channel or group."
  );
}

async function openChannelPromoAdminMenu(chatId, editMessage) {
  const text = channelPromoAdminText();
  const kb = channelPromoAdminKeyboard();

  if (editMessage && editMessage.chat && editMessage.message_id) {
    try {
      await bot.editMessageText(text, {
        chat_id: editMessage.chat.id,
        message_id: editMessage.message_id,
        ...kb
      });
      return;
    } catch (_) {}
  }

  await bot.sendMessage(chatId, text, kb).catch(() => {});
}

async function answerPromoCb(q, text) {
  try { await bot.answerCallbackQuery(q.id, text ? { text } : {}); } catch (_) {}
}

bot.on("message", async (msg) => {
  try {
    const chatId = msg && msg.chat && msg.chat.id;
    if (!chatId || !promoAdmin(chatId) || String(msg && msg.chat && msg.chat.type || "") !== "private") return;

    const text = String(msg && msg.text || "").trim();
    if (/^\/channelpromo(?:@\w+)?$/i.test(text)) {
      clearChannelPromoEditState(chatId);
      await openChannelPromoAdminMenu(chatId);
      return;
    }
  } catch (_) {}
});

bot.on("callback_query", async (q) => {
  try {
    const data = String(q && q.data || "");
    const chatId = q && q.from && q.from.id;
    if (!data.startsWith("cpadm:")) return;
    if (!promoAdmin(chatId)) {
      await answerPromoCb(q, "Not authorized.");
      return;
    }

    ensureChannelPromoStore();

    if (data === "cpadm:noop") {
      await answerPromoCb(q);
      return;
    }

    if (data === "cpadm:close") {
      await answerPromoCb(q, "Closed");
      try {
        await bot.editMessageText("❌ Closed.", {
          chat_id: q.message.chat.id,
          message_id: q.message.message_id
        });
      } catch (_) {}
      return;
    }

    if (data === "cpadm:preview") {
      await answerPromoCb(q, "Preview sent");
      await sendChannelPromoPreview(chatId);
      return;
    }

    if (data === "cpadm:toggle_pin") {
      const cfg = channelPromoCfg();
      cfg.pinNew = !cfg.pinNew;
      saveDB();
      await answerPromoCb(q, `Auto Pin ${cfg.pinNew ? "ON" : "OFF"}`);
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadm:toggle_unpin") {
      const cfg = channelPromoCfg();
      cfg.unpinOld = !cfg.unpinOld;
      saveDB();
      await answerPromoCb(q, `Unpin Old ${cfg.unpinOld ? "ON" : "OFF"}`);
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadm:clear") {
      const cfg = channelPromoCfg();
      cfg.mode = "text";
      cfg.text = "";
      cfg.caption = "";
      cfg.media = [];
      saveDB();
      clearChannelPromoEditState(chatId);
      await answerPromoCb(q, "Promo cleared");
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadm:set_text") {
      setChannelPromoEditState(chatId, { mode: "await_inline_text" });
      await answerPromoCb(q, "Send the promo text");
      await bot.sendMessage(chatId, "📝 Send the new promo text now.").catch(() => {});
      return;
    }

    if (data === "cpadm:set_media") {
      setChannelPromoEditState(chatId, { mode: "await_promo_media" });
      await answerPromoCb(q, "Send promo media");
      await bot.sendMessage(chatId, "🖼 Send the promo now.\n\nSupported:\n- text\n- single photo\n- single video\n- album\n\nCaption will be used as promo text.").catch(() => {});
      return;
    }

    if (data === "cpadm:set_button") {
      setChannelPromoEditState(chatId, { mode: "await_inline_button" });
      await answerPromoCb(q, "Send button details");
      await bot.sendMessage(chatId, "🔘 Send button in this format:\nBUY NOW | https://t.me/yourbot").catch(() => {});
      return;
    }

    if (data === "cpadm:set_delay") {
      setChannelPromoEditState(chatId, { mode: "await_inline_delay" });
      await answerPromoCb(q, "Send delay in minutes");
      await bot.sendMessage(chatId, "⏱ Send the delay in minutes.\nExample: 3").catch(() => {});
      return;
    }

    if (data === "cpadm:reset_chat") {
      setChannelPromoEditState(chatId, { mode: "await_inline_reset_chat" });
      await answerPromoCb(q, "Send chat ID");
      await bot.sendMessage(chatId, "♻️ Send the target chat ID to reset promo sent flag.\nExample: -1001234567890").catch(() => {});
      return;
    }
  } catch (_) {}
});

// Extend existing private-admin promo editor flow to support inline states
bot.on("message", async (msg) => {
  try {
    const chatId = msg && msg.chat && msg.chat.id;
    if (!chatId || !promoAdmin(chatId) || String(msg && msg.chat && msg.chat.type || "") !== "private") return;

    const state = getChannelPromoEditState(chatId);
    if (!state) return;

    const text = String(msg && msg.text || "").trim();

    if (state.mode === "await_inline_text") {
      if (text && !text.startsWith("/")) {
        setChannelPromoFromText(text);
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, "✅ Promo text updated.").catch(() => {});
        await openChannelPromoAdminMenu(chatId);
      }
      return;
    }

    if (state.mode === "await_inline_button") {
      if (text && !text.startsWith("/")) {
        const parts = text.split("|");
        const buttonText = String(parts[0] || "").trim();
        const buttonUrl = String(parts.slice(1).join("|") || "").trim();
        if (!buttonText || !buttonUrl) {
          await bot.sendMessage(chatId, "Usage:\nBUY NOW | https://t.me/yourbot").catch(() => {});
          return;
        }
        setChannelPromoButton(buttonText, buttonUrl);
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, "✅ Promo button updated.").catch(() => {});
        await openChannelPromoAdminMenu(chatId);
      }
      return;
    }

    if (state.mode == "await_inline_delay") {
      if (/^\d+(?:\.\d+)?$/.test(text)) {
        setChannelPromoDelayMinutes(Number(text));
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, "✅ Promo delay updated.").catch(() => {});
        await openChannelPromoAdminMenu(chatId);
      } else {
        await bot.sendMessage(chatId, "Send only the number of minutes.\nExample: 3").catch(() => {});
      }
      return;
    }

    if (state.mode === "await_inline_reset_chat") {
      if (/^-?\d+$/.test(text)) {
        clearChannelPromoSent(String(text));
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, `✅ Reset promo sent flag for chat ${text}`).catch(() => {});
        await openChannelPromoAdminMenu(chatId);
      } else {
        await bot.sendMessage(chatId, "Send a valid chat ID.\nExample: -1001234567890").catch(() => {});
      }
      return;
    }
  } catch (_) {}
});


