// ============================================================================
// ✅ CHANNEL PROMO TRACKING / STATS / DELETE / LEAVE
// ============================================================================

function ensureChannelPromoMetricsStore() {
  const store = ensureChannelPromoStore();
  if (!store.metrics || typeof store.metrics !== "object") store.metrics = {};
  if (!store.metrics.totals || typeof store.metrics.totals !== "object") {
    store.metrics.totals = { clicks: 0, sends: 0, clicksByDay: {}, sendsByDay: {} };
  }
  if (!store.metrics.byChannel || typeof store.metrics.byChannel !== "object") {
    store.metrics.byChannel = {};
  }
  return store.metrics;
}

function promoDayKey() {
  try { return todayKey(); } catch (_) { return new Date().toISOString().slice(0, 10); }
}

function ensurePromoChannelMetric(chatId) {
  const metrics = ensureChannelPromoMetricsStore();
  const key = String(chatId);
  if (!metrics.byChannel[key] || typeof metrics.byChannel[key] !== "object") {
    metrics.byChannel[key] = {
      title: "",
      type: "",
      joinedAt: 0,
      active: false,
      lastValidatedAt: 0,
      lastSendAt: 0,
      lastPromoMessageId: 0,
      totalClicks: 0,
      totalSends: 0,
      clicksByDay: {},
      sendsByDay: {}
    };
  }
  return metrics.byChannel[key];
}

function registerPromoChannel(chat) {
  try {
    if (!chat || !chat.id) return;
    const rec = ensurePromoChannelMetric(chat.id);
    if (!rec.joinedAt) rec.joinedAt = Date.now();
    rec.title = String(chat.title || chat.username || rec.title || "");
    rec.type = String(chat.type || rec.type || "");
    rec.active = true;
    rec.lastValidatedAt = Date.now();
    saveDB();
  } catch (_) {}
}

function trackPromoSend(chatId, messageId) {
  try {
    const metrics = ensureChannelPromoMetricsStore();
    const rec = ensurePromoChannelMetric(chatId);
    const day = promoDayKey();

    metrics.totals.sends = Number(metrics.totals.sends || 0) + 1;
    metrics.totals.sendsByDay[day] = Number(metrics.totals.sendsByDay[day] || 0) + 1;

    rec.totalSends = Number(rec.totalSends || 0) + 1;
    rec.sendsByDay[day] = Number(rec.sendsByDay[day] || 0) + 1;
    rec.lastSendAt = Date.now();
    rec.lastPromoMessageId = Number(messageId || 0);
    rec.active = true;
    rec.lastValidatedAt = Date.now();
    saveDB();
  } catch (_) {}
}

function trackPromoClick(chatId) {
  try {
    const metrics = ensureChannelPromoMetricsStore();
    const rec = ensurePromoChannelMetric(chatId);
    const day = promoDayKey();

    metrics.totals.clicks = Number(metrics.totals.clicks || 0) + 1;
    metrics.totals.clicksByDay[day] = Number(metrics.totals.clicksByDay[day] || 0) + 1;

    rec.totalClicks = Number(rec.totalClicks || 0) + 1;
    rec.clicksByDay[day] = Number(rec.clicksByDay[day] || 0) + 1;
    saveDB();
  } catch (_) {}
}

function promoTrackedButtonKeyboard(targetChatId) {
  const cfg = channelPromoCfg();
  const txt = String(cfg.buttonText || "").trim();
  const realUrl = normalizePromoUrl(cfg.buttonUrl);
  if (!txt || !realUrl) return undefined;

  let finalUrl = realUrl;
  try {
    const root = String(BASE_URL || "").replace(/\/+$/, "");
    if (root && /^https?:\/\//i.test(root)) {
      finalUrl = `${root}/promo/go?chat=${encodeURIComponent(String(targetChatId))}&to=${encodeURIComponent(realUrl)}`;
    }
  } catch (_) {}

  return {
    reply_markup: {
      inline_keyboard: [[{ text: txt, url: finalUrl }]]
    }
  };
}

async function resolvePromoTarget(raw) {
  const input = String(raw || "").trim();
  if (!input) return null;
  try {
    const chat = await bot.getChat(input);
    return chat || null;
  } catch (_) {
    return null;
  }
}

async function validatePromoChannelsAndCount() {
  const metrics = ensureChannelPromoMetricsStore();
  const me = await bot.getMe().catch(() => null);
  let activeValid = 0;
  let todayActiveJoined = 0;
  const day = promoDayKey();

  for (const [chatId, rec] of Object.entries(metrics.byChannel || {})) {
    try {
      if (!me || !me.id) {
        rec.active = false;
        continue;
      }
      const member = await bot.getChatMember(chatId, me.id);
      const s = String(member && member.status || "");
      const ok = (s === "administrator" || s === "creator");
      rec.active = ok;
      rec.lastValidatedAt = Date.now();
      if (ok) {
        activeValid += 1;
        const joinedDay = rec.joinedAt ? new Date(Number(rec.joinedAt)).toISOString().slice(0, 10) : "";
        if (joinedDay === day) todayActiveJoined += 1;
        try {
          const chat = await bot.getChat(chatId);
          if (chat) {
            rec.title = String(chat.title || chat.username || rec.title || "");
            rec.type = String(chat.type || rec.type || "");
          }
        } catch (_) {}
      }
    } catch (_) {
      rec.active = false;
      rec.lastValidatedAt = Date.now();
    }
  }

  saveDB();
  return { activeValid, todayActiveJoined, totalKnown: Object.keys(metrics.byChannel || {}).length };
}

async function buildPromoStatsText() {
  const metrics = ensureChannelPromoMetricsStore();
  const day = promoDayKey();
  const counts = await validatePromoChannelsAndCount();

  const totalClicks = Number(metrics.totals.clicks || 0);
  const todayClicks = Number(metrics.totals.clicksByDay[day] || 0);
  const totalSends = Number(metrics.totals.sends || 0);
  const todaySends = Number(metrics.totals.sendsByDay[day] || 0);

  const top = Object.entries(metrics.byChannel || {})
    .filter(([, v]) => v && v.active)
    .map(([k, v]) => ({
      chatId: k,
      title: String(v.title || k),
      clicks: Number(v.totalClicks || 0),
      sends: Number(v.totalSends || 0)
    }))
    .sort((a, b) => b.clicks - a.clicks)
    .slice(0, 10);

  const lines = [];
  lines.push("📊 CHANNEL PROMO STATS");
  lines.push("");
  lines.push(`Total clicks: ${totalClicks}`);
  lines.push(`Today clicks: ${todayClicks}`);
  lines.push(`Total advert sends: ${totalSends}`);
  lines.push(`Today advert sends: ${todaySends}`);
  lines.push(`Active valid channels now: ${counts.activeValid}`);
  lines.push(`Channels joined today (active/valid): ${counts.todayActiveJoined}`);
  lines.push(`Channels seen total: ${counts.totalKnown}`);
  lines.push(`Views: Not available from standard Telegram Bot API.`);
  lines.push("");

  if (top.length) {
    lines.push("Top active channels:");
    for (const row of top) {
      lines.push(`• ${row.title} — clicks ${row.clicks}, sends ${row.sends}`);
    }
  } else {
    lines.push("Top active channels: none");
  }

  return lines.join("\n");
}

app.get("/promo/go", (req, res) => {
  try {
    const chatId = String(req.query && req.query.chat || "").trim();
    const to = String(req.query && req.query.to || "").trim();
    if (chatId) {
      try { trackPromoClick(chatId); } catch (_) {}
    }
    if (to && /^https?:\/\//i.test(to)) {
      return res.redirect(to);
    }
    return res.status(200).send("OK");
  } catch (_) {
    return res.status(200).send("OK");
  }
});

// Track channels whenever bot becomes admin there
bot.on("my_chat_member", async (update) => {
  try {
    const chat = update && update.chat;
    const oldStatus = String(update && update.old_chat_member && update.old_chat_member.status || "");
    const newStatus = String(update && update.new_chat_member && update.new_chat_member.status || "");
    if (!chat || !["group", "supergroup", "channel"].includes(String(chat.type || ""))) return;

    const becameAdmin = (newStatus === "administrator" || newStatus === "creator") &&
                        oldStatus !== "administrator" && oldStatus !== "creator";
    if (!becameAdmin) return;

    registerPromoChannel(chat);
  } catch (_) {}
});

// Override send to include tracked button URL + counters
async function sendConfiguredChannelPromo(targetChatId) {
  const cfg = channelPromoCfg();
  const kb = promoTrackedButtonKeyboard(targetChatId);
  let pinMessageId = null;

  if (cfg.unpinOld) {
    try { await bot.unpinAllChatMessages(targetChatId); } catch (_) {}
  }

  if (Array.isArray(cfg.media) && cfg.media.length) {
    const m0 = cfg.media[0];
    if (m0 && m0.file_id) {
      if (m0.type === "video") {
        const sent = await bot.sendVideo(targetChatId, m0.file_id, {
          caption: String(cfg.caption || cfg.text || ""),
          ...(kb || {})
        }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      } else {
        const sent = await bot.sendPhoto(targetChatId, m0.file_id, {
          caption: String(cfg.caption || cfg.text || ""),
          ...(kb || {})
        }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      }
    }
  } else {
    const sent = await bot.sendMessage(
      targetChatId,
      String(cfg.text || cfg.caption || ""),
      kb || {}
    ).catch(() => null);

    if (sent && sent.message_id) pinMessageId = sent.message_id;
  }

  if (cfg.pinNew && pinMessageId) {
    try { await bot.pinChatMessage(targetChatId, pinMessageId, { disable_notification: true }); } catch (_) {}
  }

  if (pinMessageId) {
    try { trackPromoSend(targetChatId, pinMessageId); } catch (_) {}
  }

  return !!pinMessageId;
}

// Extend admin inline promo menu
function channelPromoAdminKeyboard() {
  const cfg = channelPromoCfg();
  const rcfg = channelPromoRepostCfg();
  const mode = String(cfg.mode || "text").toUpperCase();
  const delayMin = Math.round(Number(cfg.delayMs || 180000) / 60000);
  const pinMark = cfg.pinNew ? "✅" : "⬜️";
  const unpinMark = cfg.unpinOld ? "✅" : "⬜️";
  const repostMark = rcfg.enabled ? "✅" : "⬜️";
  const delPrevMark = rcfg.deletePrevious ? "✅" : "⬜️";

  return {
    reply_markup: {
      inline_keyboard: [
        [{ text: `📣 Mode: ${mode}`, callback_data: "cpadm:noop" }],
        [{ text: "📝 Set Text", callback_data: "cpadm:set_text" }, { text: "🖼 Set Media", callback_data: "cpadm:set_media" }],
        [{ text: "🔘 Set Button", callback_data: "cpadm:set_button" }, { text: `⏱ Delay: ${delayMin}m`, callback_data: "cpadm:set_delay" }],
        [{ text: `${pinMark} Auto Pin`, callback_data: "cpadm:toggle_pin" }, { text: `${unpinMark} Unpin Old`, callback_data: "cpadm:toggle_unpin" }],
        [{ text: `${repostMark} Auto Repost`, callback_data: "cpadm:toggle_repost" }, { text: `${delPrevMark} Delete Previous`, callback_data: "cpadm:toggle_delprev" }],
        [{ text: "🕒 Set Repost Interval", callback_data: "cpadm:set_repost_interval" }, { text: "🎯 Set Repost Target", callback_data: "cpadm:set_repost_target" }],
        [{ text: "✏️ Post To Target", callback_data: "cpadm:edit_specific" }, { text: "📊 Stats", callback_data: "cpadm:stats" }],
        [{ text: "👀 Preview", callback_data: "cpadm:preview" }, { text: "🗑 Delete Channel Post", callback_data: "cpadm:delete_post" }],
        [{ text: "🚪 Leave Channel", callback_data: "cpadm:leave_channel" }, { text: "🧹 Clear Promo", callback_data: "cpadm:clear" }],
        [{ text: "❌ Close", callback_data: "cpadm:close" }]
      ]
    }
  };
}

// Extra callback actions
bot.on("callback_query", async (q) => {
  try {
    const data = String(q && q.data || "");
    const chatId = q && q.from && q.from.id;
    if (!data.startsWith("cpadm:")) return;
    if (!promoAdmin(chatId)) return;

    if (data === "cpadm:stats") {
      await answerPromoCb(q, "Loading stats...");
      const text = await buildPromoStatsText();
      await bot.sendMessage(chatId, text).catch(() => {});
      return;
    }

    if (data === "cpadm:delete_post") {
      setChannelPromoEditState(chatId, { mode: "await_delete_channel_post" });
      await answerPromoCb(q, "Send channel ID or @username");
      await bot.sendMessage(chatId, "🗑 Send the target channel/group ID or @username to delete the last promo post there.").catch(() => {});
      return;
    }

    if (data === "cpadm:leave_channel") {
      setChannelPromoEditState(chatId, { mode: "await_leave_channel_target" });
      await answerPromoCb(q, "Send channel ID or @username");
      await bot.sendMessage(chatId, "🚪 Send the target channel/group ID or @username. I will leave that channel/group.").catch(() => {});
      return;
    }

    if (data === "cpadm:toggle_repost") {
      const rcfg = channelPromoRepostCfg();
      rcfg.enabled = !rcfg.enabled;
      if (rcfg.enabled && !Number(rcfg.intervalMs || 0)) rcfg.intervalMs = 24 * 60 * 60 * 1000;
      if (rcfg.enabled) rcfg.nextRunAt = Date.now() + Number(rcfg.intervalMs || 0);
      saveDB();
      await answerPromoCb(q, `Auto repost ${rcfg.enabled ? "ON" : "OFF"}`);
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadm:toggle_delprev") {
      const rcfg = channelPromoRepostCfg();
      rcfg.deletePrevious = !rcfg.deletePrevious;
      saveDB();
      await answerPromoCb(q, `Delete previous ${rcfg.deletePrevious ? "ON" : "OFF"}`);
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadm:set_repost_interval") {
      setChannelPromoEditState(chatId, { mode: "await_repost_interval" });
      await answerPromoCb(q, "Send interval");
      await bot.sendMessage(chatId, "🕒 Send repost interval like:\n• 30s\n• 10m\n• 1h\n• 1d\n• 1w").catch(() => {});
      return;
    }

    if (data === "cpadm:set_repost_target") {
      setChannelPromoEditState(chatId, { mode: "await_repost_target" });
      await answerPromoCb(q, "Send target");
      await bot.sendMessage(chatId, "🎯 Send repost target:\n• all\n• @channelusername\n• -1001234567890").catch(() => {});
      return;
    }

    if (data === "cpadm:edit_specific") {
      setChannelPromoEditState(chatId, { mode: "await_specific_post_target" });
      await answerPromoCb(q, "Send target");
      await bot.sendMessage(chatId, "✏️ Send the channel/group @username or chat ID to post the CURRENT promo there now.").catch(() => {});
      return;
    }
  } catch (_) {}
});

// Extra state handlers for stats / delete / leave
bot.on("message", async (msg) => {
  try {
    const chatId = msg && msg.chat && msg.chat.id;
    if (!chatId || !promoAdmin(chatId) || String(msg && msg.chat && msg.chat.type || "") !== "private") return;

    const text = String(msg && msg.text || "").trim();

    if (/^\/adstats(?:@\w+)?$/i.test(text)) {
      const stats = await buildPromoStatsText();
      await bot.sendMessage(chatId, stats).catch(() => {});
      return;
    }

    if (/^\/deletechannelpromo(?:@\w+)?\s+([\s\S]+)$/i.test(text)) {
      const m = text.match(/^\/deletechannelpromo(?:@\w+)?\s+([\s\S]+)$/i);
      const target = await resolvePromoTarget(m && m[1] || "");
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      const rec = ensurePromoChannelMetric(target.id);
      if (!rec.lastPromoMessageId) {
        await bot.sendMessage(chatId, "⚠️ No tracked promo message found for that channel/group.").catch(() => {});
        return;
      }
      const ok = await bot.deleteMessage(target.id, rec.lastPromoMessageId).then(() => true).catch(() => false)
      if (ok) {
        rec.lastPromoMessageId = 0;
        saveDB();
        await bot.sendMessage(chatId, `✅ Deleted the tracked promo message in ${target.title || target.id}`).catch(() => {});
      } else {
        await bot.sendMessage(chatId, "❌ Could not delete the promo message. It may already be gone.").catch(() => {});
      }
      return;
    }

    if (/^\/leavechannel(?:@\w+)?\s+([\s\S]+)$/i.test(text)) {
      const m = text.match(/^\/leavechannel(?:@\w+)?\s+([\s\S]+)$/i);
      const target = await resolvePromoTarget(m && m[1] || "");
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      try { await bot.leaveChat(target.id); } catch (_) {}
      try {
        const metrics = ensureChannelPromoMetricsStore();
        const rec = ensurePromoChannelMetric(target.id);
        rec.active = false;
        rec.lastValidatedAt = Date.now();
        delete db.channelPromo.sentChats[String(target.id)];
        delete db.channelPromo.pending[String(target.id)];
        const fj = getForceJoinChannels();
        saveForceJoinChannels((fj || []).filter((x) => String(x) !== String(target.id) && String(x) !== String(target.username ? "@" + target.username : "")));
        saveDB();
      } catch (_) {}
      await bot.sendMessage(chatId, `✅ Left ${target.title || target.id}`).catch(() => {});
      return;
    }

    const state = getChannelPromoEditState(chatId);
    if (!state) return;

    if (state.mode === "await_delete_channel_post") {
      const target = await resolvePromoTarget(text);
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      const rec = ensurePromoChannelMetric(target.id);
      if (!rec.lastPromoMessageId) {
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, "⚠️ No tracked promo message found for that channel/group.").catch(() => {});
        await openChannelPromoAdminMenu(chatId);
        return;
      }
      const ok = await bot.deleteMessage(target.id, rec.lastPromoMessageId).then(() => true).catch(() => false);
      clearChannelPromoEditState(chatId);
      if (ok) {
        rec.lastPromoMessageId = 0;
        saveDB();
        await bot.sendMessage(chatId, `✅ Deleted the tracked promo message in ${target.title || target.id}`).catch(() => {});
      } else {
        await bot.sendMessage(chatId, "❌ Could not delete the promo message. It may already be gone.").catch(() => {});
      }
      await openChannelPromoAdminMenu(chatId);
      return;
    }

    if (state.mode === "await_leave_channel_target") {
      const target = await resolvePromoTarget(text);
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      try { await bot.leaveChat(target.id); } catch (_) {}
      try {
        const rec = ensurePromoChannelMetric(target.id);
        rec.active = false;
        rec.lastValidatedAt = Date.now();
        delete db.channelPromo.sentChats[String(target.id)];
        delete db.channelPromo.pending[String(target.id)];
        const fj = getForceJoinChannels();
        saveForceJoinChannels((fj || []).filter((x) => String(x) !== String(target.id) && String(x) !== String(target.username ? "@" + target.username : "")));
        saveDB();
      } catch (_) {}
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, `✅ Left ${target.title || target.id}`).catch(() => {});
      await openChannelPromoAdminMenu(chatId);
      return;
    }

    if (state.mode === "await_repost_interval") {
      const raw = String(text || "").trim().toLowerCase();
      const m = raw.match(/^(\d+(?:\.\d+)?)(s|sec|secs|second|seconds|m|min|mins|minute|minutes|h|hr|hrs|hour|hours|d|day|days|w|week|weeks)$/i);
      if (!m) {
        await bot.sendMessage(chatId, "❌ Send interval like 30s, 10m, 1h, 1d, 1w").catch(() => {});
        return;
      }
      const n = Number(m[1] || 0);
      const unit = String(m[2] || "").toLowerCase();
      let mult = 1000;
      if (["m","min","mins","minute","minutes"].includes(unit)) mult = 60 * 1000;
      else if (["h","hr","hrs","hour","hours"].includes(unit)) mult = 60 * 60 * 1000;
      else if (["d","day","days"].includes(unit)) mult = 24 * 60 * 60 * 1000;
      else if (["w","week","weeks"].includes(unit)) mult = 7 * 24 * 60 * 60 * 1000;
      setChannelPromoRepostSchedule(n * mult);
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, "✅ Repost interval updated.").catch(() => {});
      await openChannelPromoAdminMenu(chatId);
      return;
    }

    if (state.mode === "await_repost_target") {
      const raw = String(text || "").trim();
      if (/^all$/i.test(raw)) {
        setChannelPromoRepostTarget("all", "");
        clearChannelPromoEditState(chatId);
        await bot.sendMessage(chatId, "✅ Repost target set to ALL active channels/groups.").catch(() => {});
        await openChannelPromoAdminMenu(chatId);
        return;
      }
      const target = await resolvePromoTarget(raw);
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      ensurePromoChannelMetric(target.id);
      setChannelPromoRepostTarget("single", String(target.id));
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, `✅ Repost target set to ${target.title || target.id}`).catch(() => {});
      await openChannelPromoAdminMenu(chatId);
      return;
    }

    if (state.mode === "await_specific_post_target") {
      const target = await resolvePromoTarget(text);
      if (!target) {
        await bot.sendMessage(chatId, "❌ Could not resolve that channel/group.").catch(() => {});
        return;
      }
      ensurePromoChannelMetric(target.id);
      const ok = await sendConfiguredChannelPromoToTarget(target.id, { deletePrevious: false }).catch(() => false);
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, ok ? `✅ Promo posted to ${target.title || target.id}` : "❌ Failed to post promo to that target.").catch(() => {});
      await openChannelPromoAdminMenu(chatId);
      return;
    }
  } catch (_) {}
});



// ============================================================================
// ✅ AUTO ADD CHANNEL/GROUP TO FORCE-JOIN WHEN BOT BECOMES ADMIN
// ============================================================================

function normalizeDetectedForceJoinTarget(chat) {
  try {
    if (!chat || !chat.id) return null;
    if (chat.username) return "@" + String(chat.username).replace(/^@/, "");
    return String(chat.id);
  } catch (_) {
    return null;
  }
}

async function autoAddChatToForceJoin(chat) {
  try {
    if (!chat || !chat.id) return false;
    const target = normalizeDetectedForceJoinTarget(chat);
    if (!target) return false;

    const current = getForceJoinChannels();
    if (Array.isArray(current) && current.includes(target)) return true;

    const next = Array.isArray(current) ? current.slice() : [];
    next.push(target);
    saveForceJoinChannels(next);

    try {
      await bot.sendMessage(
        String(ADMIN_ID),
        `✅ Auto-added to force join:\n${String(chat.title || target)}\n${target}`
      ).catch(() => {});
    } catch (_) {}

    return true;
  } catch (_) {
    return false;
  }
}

// Auto-detect + auto-add any channel/group where bot becomes admin
bot.on("my_chat_member", async (update) => {
  try {
    const chat = update && update.chat;
    const oldStatus = String(update && update.old_chat_member && update.old_chat_member.status || "");
    const newStatus = String(update && update.new_chat_member && update.new_chat_member.status || "");
    const chatType = String(chat && chat.type || "");

    if (!chat || !["group", "supergroup", "channel"].includes(chatType)) return;

    const becameAdmin =
      (newStatus === "administrator" || newStatus === "creator") &&
      oldStatus !== "administrator" &&
      oldStatus !== "creator";

    if (!becameAdmin) return;

    await autoAddChatToForceJoin(chat);
  } catch (_) {}
});



// ============================================================================
// ✅ CHANNEL AUTO-ADD RULES
// - Auto add ONLY channels with 250+ subscribers
// - Auto leave dead channels with no new channel posts for 7 days
// IMPORTANT:
//   Telegram Bot API does not provide reliable historical post lookup.
//   "Dead for 1 week" is tracked from channel_post updates the bot receives
//   AFTER it has been added as admin.
// ============================================================================

function ensureAutoChannelRulesStore() {
  db = repairDB(db);
  if (!db.autoChannelRules || typeof db.autoChannelRules !== "object") db.autoChannelRules = {};
  if (!db.autoChannelRules.channels || typeof db.autoChannelRules.channels !== "object") db.autoChannelRules.channels = {};
  return db.autoChannelRules;
}

function getAutoChannelRec(chatId) {
  const store = ensureAutoChannelRulesStore();
  const key = String(chatId);
  if (!store.channels[key] || typeof store.channels[key] !== "object") {
    store.channels[key] = {
      title: "",
      username: "",
      addedAt: 0,
      subsAtAdd: 0,
      lastPostAt: 0,
      lastCheckedAt: 0,
      active: false,
      leftAt: 0,
      reason: ""
    };
  }
  return store.channels[key];
}

async function getChatSubscribersCountSafe(chatId) {
  try {
    if (typeof bot.getChatMemberCount === "function") {
      const n = await bot.getChatMemberCount(chatId);
      return Number(n || 0);
    }
  } catch (_) {}
  try {
    if (typeof bot.getChatMembersCount === "function") {
      const n = await bot.getChatMembersCount(chatId);
      return Number(n || 0);
    }
  } catch (_) {}
  return 0;
}

async function removeFromForceJoinEverywhere(chat) {
  try {
    const current = Array.isArray(getForceJoinChannels()) ? getForceJoinChannels() : [];
    const names = [];
    if (chat && chat.id) names.push(String(chat.id));
    if (chat && chat.username) names.push("@" + String(chat.username).replace(/^@/, ""));
    const next = current.filter((x) => !names.includes(String(x)));
    saveForceJoinChannels(next);
  } catch (_) {}
}

async function leaveDeadOrInvalidChannel(chat, reason) {
  try {
    await removeFromForceJoinEverywhere(chat);
  } catch (_) {}

  try {
    const rec = getAutoChannelRec(chat && chat.id);
    rec.active = false;
    rec.leftAt = Date.now();
    rec.reason = String(reason || "left");
    rec.lastCheckedAt = Date.now();
    saveDB();
  } catch (_) {}

  try { await bot.leaveChat(chat.id); } catch (_) {}

  try {
    await bot.sendMessage(
      String(ADMIN_ID),
      `⚠️ Auto-left channel:\n${String((chat && (chat.title || chat.username || chat.id)) || "")}\nReason: ${String(reason || "left")}`
    ).catch(() => {});
  } catch (_) {}
}

async function autoAddChatToForceJoin(chat) {
  try {
    if (!chat || !chat.id) return false;
    if (String(chat.type || "") !== "channel") return false;

    const subs = await getChatSubscribersCountSafe(chat.id);
    const rec = getAutoChannelRec(chat.id);
    rec.title = String(chat.title || rec.title || "");
    rec.username = String(chat.username || rec.username || "");
    rec.addedAt = rec.addedAt || Date.now();
    rec.subsAtAdd = subs;
    rec.lastCheckedAt = Date.now();
    rec.active = false;
    saveDB();

    if (subs < 250) {
      await leaveDeadOrInvalidChannel(chat, `below minimum subscribers (${subs}/250)`);
      return false;
    }

    const target = normalizeDetectedForceJoinTarget(chat);
    if (!target) return false;

    const current = getForceJoinChannels();
    if (!Array.isArray(current) || !current.includes(target)) {
      const next = Array.isArray(current) ? current.slice() : [];
      next.push(target);
      saveForceJoinChannels(next);
    }

    rec.active = true;
    rec.reason = "";
    saveDB();

    try {
      await bot.sendMessage(
        String(ADMIN_ID),
        `✅ Auto-added to force join:\n${String(chat.title || target)}\n${target}\nSubscribers: ${subs}`
      ).catch(() => {});
    } catch (_) {}

    return true;
  } catch (_) {
    return false;
  }
}

// Track new channel posts so we can detect inactivity after add
bot.on("channel_post", async (msg) => {
  try {
    const chat = msg && msg.chat;
    if (!chat || String(chat.type || "") !== "channel") return;
    const rec = getAutoChannelRec(chat.id);
    rec.title = String(chat.title || rec.title || "");
    rec.username = String(chat.username || rec.username || "");
    rec.lastPostAt = Date.now();
    rec.lastCheckedAt = Date.now();
    rec.active = true;
    saveDB();
  } catch (_) {}
});

// Periodic cleanup for inactive channels (no new channel posts for 7 days)
// Note: inactivity can only be measured from posts received AFTER bot was added.
async function sweepDeadChannels() {
  try {
    const store = ensureAutoChannelRulesStore();
    const items = Object.entries(store.channels || {});
    if (!items.length) return;

    const now = Date.now();
    const weekMs = 7 * 24 * 60 * 60 * 1000;
    const me = await bot.getMe().catch(() => null);

    for (const [chatId, rec] of items) {
      try {
        if (!rec || rec.leftAt) continue;

        let chat = null;
        try { chat = await bot.getChat(chatId); } catch (_) { chat = { id: chatId, title: rec.title || "", username: rec.username || "", type: "channel" }; }

        // If bot is no longer admin, remove and skip
        try {
          if (!me || !me.id) {
            await leaveDeadOrInvalidChannel(chat, "bot identity unavailable");
            continue;
          }
          const member = await bot.getChatMember(chatId, me.id);
          const status = String(member && member.status || "");
          if (!(status === "administrator" || status === "creator")) {
            await leaveDeadOrInvalidChannel(chat, "bot no longer admin");
            continue;
          }
        } catch (_) {
          await leaveDeadOrInvalidChannel(chat, "bot no longer has access");
          continue;
        }

        const lastActivity = Number(rec.lastPostAt || rec.addedAt || 0);
        if (lastActivity && now - lastActivity > weekMs) {
          await leaveDeadOrInvalidChannel(chat, "no channel posts detected for 7 days");
          continue;
        }

        rec.lastCheckedAt = now;
        saveDB();
      } catch (_) {}
    }
  } catch (_) {}
}

setInterval(() => { sweepDeadChannels().catch(() => {}); }, 6 * 60 * 60 * 1000);






// ============================================================================
// ✅ GMAIL ACCOUNTS STORE + BUY FLOW
// Price: Ksh 29 per Gmail account
// Admin adds stock manually as: email,password
// Delivered uniquely once payment is confirmed
// ============================================================================

function ensureGmailStore() {
  db = repairDB(db);
  if (!db.gmailStore || typeof db.gmailStore !== "object") db.gmailStore = {};
  if (!Array.isArray(db.gmailStore.stock)) db.gmailStore.stock = [];
  if (!db.gmailStore.pendingOrders || typeof db.gmailStore.pendingOrders !== "object") db.gmailStore.pendingOrders = {};
  if (!db.gmailStore.await || typeof db.gmailStore.await !== "object") db.gmailStore.await = {};
  if (!db.gmailStore.cfg || typeof db.gmailStore.cfg !== "object") {
    db.gmailStore.cfg = { price: 29 };
  }
  return db.gmailStore;
}

function gmailPrice() {
  return Number(ensureGmailStore().cfg.price || 29);
}

function gmailAvailableCount() {
  return Number(ensureGmailStore().stock.length || 0);
}

function gmailVisibleToUser(chatId) {
  return gmailAvailableCount() > 0 || isAdmin(chatId);
}

function setGmailAwait(chatId, state) {
  const store = ensureGmailStore();
  if (state) store.await[String(chatId)] = state;
  else delete store.await[String(chatId)];
  saveDB();
}

function getGmailAwait(chatId) {
  return ensureGmailStore().await[String(chatId)] || null;
}

function normalizeGmailLine(line) {
  const raw = String(line || "").trim();
  if (!raw) return null;
  const parts = raw.split(",");
  if (parts.length < 2) return null;
  const email = String(parts[0] || "").trim().toLowerCase();
  const password = String(parts.slice(1).join(",") || "").trim();
  if (!/^[^@\s]+@gmail\.com$/i.test(email) || !password) return null;
  return { email, password };
}

function addGmailStockFromLines(lines) {
  const store = ensureGmailStore();
  let added = 0;
  let skipped = 0;
  const existing = new Set(store.stock.map((x) => String(x.email || "").toLowerCase()));

  for (const line of String(lines || "").split(/\r?\n/)) {
    const rec = normalizeGmailLine(line);
    if (!rec) continue;
    if (existing.has(rec.email)) { skipped += 1; continue; }
    existing.add(rec.email);
    store.stock.push({ email: rec.email, password: rec.password, createdAt: Date.now() });
    added += 1;
  }
  saveDB();
  return { added, skipped, total: store.stock.length };
}

function gmailPercentButtons(stockCount) {
  const labels = [1, 3, 10, 25, 50, 70, 90, 100];
  const rows = [];
  const seen = new Set();

  for (const pct of labels) {
    let qty = Math.floor(stockCount * (pct / 100));
    if (pct > 0 && qty < 1 && stockCount > 0) qty = 1;
    if (pct === 100) qty = stockCount;
    if (qty < 1 || qty > stockCount || seen.has(qty)) continue;
    seen.add(qty);
    rows.push([{ text: `📧 ${pct}% (${qty})`, callback_data: `gmail_qty:${qty}` }]);
  }

  if (!rows.length && stockCount > 0) {
    rows.push([{ text: `📧 100% (${stockCount})`, callback_data: `gmail_qty:${stockCount}` }]);
  }
  rows.push([{ text: "❌ Close", callback_data: "ui:close" }]);
  return { reply_markup: { inline_keyboard: rows } };
}

async function sendGmailOfferMenu(chatId, editCtx = null) {
  if (!gmailVisibleToUser(chatId)) return;
  const count = gmailAvailableCount();
  const price = gmailPrice();

  const body = count > 0
    ? `📧 Gmail Accounts\n\nPrice: Ksh ${price} each\nAvailable now: ${count}\n\nChoose how many accounts you want to buy:`
    : `📧 Gmail Accounts\n\nPrice: Ksh ${price} each\n\n⚠️ Currently out of stock.\nOnly admin can see this button when stock is empty.`;

  const kb = count > 0
    ? gmailPercentButtons(count)
    : { reply_markup: { inline_keyboard: [[{ text: "❌ Close", callback_data: "ui:close" }]] } };

  try {
    if (editCtx && editCtx.chat_id && editCtx.message_id) {
      await bot.editMessageText(body, {
        chat_id: editCtx.chat_id,
        message_id: editCtx.message_id,
        ...(kb || {})
      });
      return;
    }
  } catch (_) {}

  await bot.sendMessage(chatId, body, kb).catch(() => {});
}

async function beginGmailPurchase(chatId, qty) {
  const count = gmailAvailableCount();
  const price = gmailPrice();
  const q = Math.max(1, Number(qty || 0));

  if (count < q) {
    await bot.sendMessage(chatId, `❌ Only ${count} Gmail account(s) are available right now.`).catch(() => {});
    return;
  }

  const total = q * price;
  const savedPhone = String(getUserPhone(chatId) || "");

  if (savedPhone) {
    await confirmGmailPhoneAndPush(chatId, q, savedPhone, total);
    return;
  }

  setGmailAwait(chatId, { mode: "await_phone", qty: q, total });
  await bot.sendMessage(
    chatId,
    `📧 Gmail Accounts\n\nQuantity: ${q}\nPrice each: Ksh ${price}\nTotal: Ksh ${total}\n\nSend the M-Pesa phone number to pay.`
  ).catch(() => {});
}

async function confirmGmailPhoneAndPush(chatId, qty, phoneInput, total) {
  const phone254 = normalizePhone(phoneInput);
  const count = gmailAvailableCount();

  if (!phone254) {
    setGmailAwait(chatId, { mode: "await_phone", qty: qty, total: total });
    await bot.sendMessage(chatId, "❌ Invalid phone number. Send a valid Safaricom number like 07xxxxxxxx or 01xxxxxxxx.").catch(() => {});
    return;
  }

  if (count < qty) {
    setGmailAwait(chatId, null);
    await bot.sendMessage(chatId, `❌ Stock changed. Only ${count} Gmail account(s) are available now.`).catch(() => {});
    return;
  }

  const paymentBlock = isPaymentNumberBlockedForChat(chatId, phone254);
  if (paymentBlock.blocked && !isAdmin(chatId)) {
    alertPaymentNumberCrossAccount(chatId, phone254);
    await bot.sendMessage(chatId, "❌ This PAYMENT number is already linked to another account and cannot be used here.").catch(() => {});
    return;
  }

  const prevPhoneGmail = getUserPhone(chatId);
  const phoneChangeResGmail = registerPaymentNumberChange(chatId, phone254, prevPhoneGmail);
  if (!phoneChangeResGmail.ok && phoneChangeResGmail.blocked) {
    await bot.sendMessage(chatId, "🚫 Too many PAYMENT number changes. Please try again later.").catch(() => {});
    return;
  }

  setUserPhone(chatId, phone254);
  rememberPaymentNumberOwner(chatId, phone254);

  const externalRef = makeExternalRef(chatId, "GMAIL", total);
  const pkgLabel = `${qty} Gmail Account${qty > 1 ? "s" : ""}`;

  addPendingPayment(externalRef, {
    chatId: chatId,
    category: "Gmail Accounts",
    pkgLabel: pkgLabel,
    phone254: phone254,
    price: total,
    quantity: qty,
    createdAt: Date.now()
  });

  const store = ensureGmailStore();
  store.pendingOrders[String(externalRef)] = {
    chatId: chatId,
    qty: qty,
    phone254: phone254,
    total: total,
    createdAt: Date.now(),
    delivered: false
  };
  saveDB();

  try {
    await payheroStkPush({
      amount: total,
      phone: phone254,
      externalRef: externalRef,
      channelId: PAYHERO_CHANNEL_ID_DATA
    });

    setGmailAwait(chatId, null);
    await bot.sendMessage(
      chatId,
      formatStkSentMessage({
        amount: total,
        pkgLabel,
        paymentPhone: phone254,
        receivePhone: phone254,
        ref: externalRef,
        extraLines: ["When payment is successful you will receive a confirmation message here.", `If delay: ${HELP_PHONE}`],
      })
    ).catch(() => {});
  } catch (e) {
    deletePendingPayment(externalRef);
    delete store.pendingOrders[String(externalRef)];
    saveDB();

    const errMsg = String(e && e.message || e || "Unknown error");
    await bot.sendMessage(chatId, `❌ Failed to send STK for Gmail Accounts.\n\n${errMsg}`).catch(() => {});
    try {
      await bot.sendMessage(String(ADMIN_ID), `⚠️ Gmail STK failed\nUser: ${chatId}\nPhone: ${formatTo07(phone254)}\nAmount: Ksh ${total}\nRef: ${externalRef}\nError: ${errMsg}`).catch(() => {});
    } catch (_) {}
  }
}

function allocateUniqueGmails(qty) {
  const store = ensureGmailStore();
  const q = Math.max(1, Number(qty || 0));
  if (store.stock.length < q) return [];
  const items = store.stock.splice(0, q);
  saveDB();
  return items;
}

async function fulfillGmailOrdersSweep() {
  try {
    const store = ensureGmailStore();
    for (const [ref, rec] of Object.entries(store.pendingOrders || {})) {
      try {
        if (!rec || rec.delivered) continue;
        if (!alreadyProcessed(ref)) continue;

        const qty = Number(rec.qty || 0);
        const chatId = Number(rec.chatId || 0);
        const pending = getPendingPayment(ref) || { pkgLabel: `${qty} Gmail Account${qty > 1 ? "s" : ""}`, price: rec.total || (qty * gmailPrice()) };
        const user = getUser(chatId);
        const totalPurchases = Number(user.totalPurchases || 0);

        if (gmailAvailableCount() < qty) {
          await bot.sendMessage(chatId, "⚠️ Payment confirmed, but Gmail stock is temporarily insufficient. Admin has been notified and delivery will follow shortly.").catch(() => {});
          await bot.sendMessage(String(ADMIN_ID), `⚠️ Gmail delivery pending: not enough stock for ref ${ref}. Needed ${qty}, available ${gmailAvailableCount()}.`).catch(() => {});
          queueRefundReview(chatId, ref, "gmail_stock_unavailable", { needed: qty, available: gmailAvailableCount() });
          continue;
        }

        const items = allocateUniqueGmails(qty);
        if (!items.length) continue;

        let details = "";
        for (const item of items) {
          details += `Email: ${item.email}\nPassword: ${item.password}\n\n`;
        }

        const msg =
          `✅ Payment Confirmed\n\n` +
          `🆔 Reference: ${ref}\n` +
          `📦 Package: ${pending.pkgLabel || `${qty} Gmail Accounts`}\n` +
          `💰 Amount: Ksh ${pending.price || (qty * gmailPrice())}\n` +
          `🛒 Total Purchases: ${totalPurchases}\n\n` +
          `Gmail account details\n` +
          `${details}` +
          `Instructions:\n` +
          `1. Open Gmail or Google sign-in.\n` +
          `2. Enter the email and password exactly as shown.\n` +
          `3. Change the password immediately after login.\n` +
          `4. Add a recovery email/phone if needed.\n\n` +
          `Your payment has been received and your request is being processed.`;

        await bot.sendMessage(chatId, msg).catch(() => {});
        transitionOrderState(ref, ORDER_STATES.FULFILLED, { chatId });
        appendPaymentTrail(ref, "gmail_fulfilled", { chatId, deliveredCount: items.length });
        rec.delivered = true;
        rec.deliveredAt = Date.now();
        rec.deliveredCount = items.length;
        saveDB();

        await bot.sendMessage(String(ADMIN_ID), `✅ Gmail delivered\nRef: ${ref}\nUser: ${chatId}\nQty: ${items.length}\nStock left: ${gmailAvailableCount()}`).catch(() => {});
      } catch (_) {}
    }
  } catch (_) {}
}

setInterval(() => { fulfillGmailOrdersSweep().catch(() => {}); }, 60 * 1000);

