// Gmail inline callbacks
bot.on("callback_query", async (q) => {
  try {
    const data = String(q.data || "");
    const chatId = q.message?.chat?.id || q.from?.id;
    if (!data.startsWith("gmail_")) return;

    if (data === "gmail_menu") {
      await bot.answerCallbackQuery(q.id).catch(() => {});
      await sendGmailOfferMenu(chatId, { chat_id: q.message.chat.id, message_id: q.message.message_id });
      return;
    }

    if (data.startsWith("gmail_qty:")) {
      const qty = Math.max(1, Number(data.split(":")[1] || 0));
      const count = gmailAvailableCount();
      const total = qty * gmailPrice();

      if (count < qty) {
        await bot.answerCallbackQuery(q.id, { text: `Only ${count} available now.` }).catch(() => {});
        return;
      }

      await bot.answerCallbackQuery(q.id).catch(() => {});
      const body = `📧 Gmail Accounts\n\nQuantity: ${qty}\nPrice each: Ksh ${gmailPrice()}\nTotal: Ksh ${total}\nAvailable now: ${count}\n\nTap Proceed to continue.`;
      const opts = {
        reply_markup: {
          inline_keyboard: [
            [{ text: "✅ Proceed", callback_data: `gmail_buy:${qty}` }],
            [{ text: "⬅️ Back", callback_data: "gmail_menu" }]
          ]
        }
      };

      try {
        await bot.editMessageText(body, {
          chat_id: q.message.chat.id,
          message_id: q.message.message_id,
          ...opts
        });
      } catch (_) {
        await bot.sendMessage(chatId, body, opts).catch(() => {});
      }
      return;
    }

    if (data.startsWith("gmail_buy:")) {
      const qty = Math.max(1, Number(data.split(":")[1] || 0));
      await bot.answerCallbackQuery(q.id).catch(() => {});
      await beginGmailPurchase(chatId, qty);
      return;
    }
  } catch (_) {}
});




