function cleanupOldGmails(days = 365) {
  const store = ensureGmailStore();
  const cutoff = Date.now() - (Number(days || 365) * 24 * 60 * 60 * 1000);
  const before = Array.isArray(store.stock) ? store.stock.length : 0;
  store.stock = (store.stock || []).filter((x) => Number(x && x.createdAt || 0) >= cutoff);
  const removed = before - store.stock.length;
  saveDB();
  return { removed, remaining: store.stock.length };
}

function gmailAdminStatusText() {
  const store = ensureGmailStore();
  const price = gmailPrice();
  const total = gmailAvailableCount();
  let oldest = "-";
  let newest = "-";
  try {
    if (Array.isArray(store.stock) && store.stock.length) {
      const ts = store.stock.map((x) => Number(x.createdAt || 0)).filter(Boolean).sort((a, b) => a - b);
      if (ts.length) {
        oldest = kenyaDateTimeFromTs(ts[0]);
        newest = kenyaDateTimeFromTs(ts[ts.length - 1]);
      }
    }
  } catch (_) {}
  return (
    `📧 GMAIL ADMIN\n\n` +
    `Price: Ksh ${price}\n` +
    `Stock: ${total}\n` +
    `Oldest stock: ${oldest}\n` +
    `Newest stock: ${newest}\n\n` +
    `Choose an action below.`
  );
}

