function updateOneGmail(line) {
  const rec = normalizeGmailLine(line);
  if (!rec) return { ok: false, err: "Invalid format. Use email@gmail.com,password" };
  const store = ensureGmailStore();
  const idx = (store.stock || []).findIndex((x) => String(x.email || "").toLowerCase() === rec.email);
  if (idx < 0) return { ok: false, err: "Gmail not found in stock." };
  store.stock[idx].password = rec.password;
  store.stock[idx].updatedAt = Date.now();
  saveDB();
  return { ok: true, email: rec.email };
}

function removeOneGmail(emailInput) {
  const email = String(emailInput || "").trim().toLowerCase();
  if (!/^[^@\s]+@gmail\.com$/i.test(email)) return { ok: false, err: "Invalid Gmail address." };
  const store = ensureGmailStore();
  const before = store.stock.length;
  store.stock = store.stock.filter((x) => String(x.email || "").toLowerCase() !== email);
  const removed = before - store.stock.length;
  saveDB();
  if (!removed) return { ok: false, err: "Gmail not found in stock." };
  return { ok: true, email, removed };
}

