// Plans admin callbacks
bot.on("callback_query", async (q) => {
  try {
    const data = String(q.data || "");
    if (!data.startsWith("planadm:")) return;
    const chatId = q.message?.chat?.id || q.from?.id;
    if (!chatId || !isAdmin(chatId)) { await bot.answerCallbackQuery(q.id).catch(() => {}); return; }
    await bot.answerCallbackQuery(q.id).catch(() => {});
    const action = data.split(":")[1] || "status";

    if (action === "close") {
      setPlanAdminState(chatId, null);
      await bot.deleteMessage(q.message.chat.id, q.message.message_id).catch(() => {});
      return;
    }
    if (action === "status") {
      setPlanAdminState(chatId, { mode: "menu", messageId: q.message.message_id });
      await openPlansAdminPanel(chatId, { chat_id: q.message.chat.id, message_id: q.message.message_id });
      return;
    }
    if (action === "addcat") {
      setPlanAdminState(chatId, { mode: "await_new_category_name", messageId: q.message.message_id });
      await bot.editMessageText(`➕ Add Category\n\nSend the new category name.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:status" }]] } }).catch(() => {});
      return;
    }
    if (["addplan", "removeplan", "editplan", "renamecat", "settemplate", "loadstock"].includes(action)) {
      setPlanAdminState(chatId, { mode: `pick_${action}`, messageId: q.message.message_id });
      await bot.editMessageText(`Select category for ${action}.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: categorySelectRows(action) } }).catch(() => {});
      return;
    }
    if (action === "pickcatview") {
      const sub = data.split(":")[2] || "status";
      setPlanAdminState(chatId, { mode: `pick_${sub}`, messageId: q.message.message_id });
      await bot.editMessageText(`Select category for ${sub}.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: categorySelectRows(sub) } }).catch(() => {});
      return;
    }
    if (action === "pickcat") {
      const parts = data.split(":");
      const sub = parts[2] || "status";
      const cat = base64UrlDecode(parts[3] || "") || "";
      if (!cat) return;
      if (sub === "addplan") {
        setPlanAdminState(chatId, { mode: "await_plan_amount", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`➕ Add Plan\n\nCategory: ${cat}\n\nSend amount/details.\nExamples:\n1GB\n100 SMS\n20 MIN\n3 Gmail Accounts`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:addplan" }]] } }).catch(() => {});
        return;
      }
      if (sub === "removeplan") {
        setPlanAdminState(chatId, { mode: "pick_plan_remove", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`🗑 Remove Plan\n\nCategory: ${cat}\n\nChoose plan to remove.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: planButtonsForCategory(cat, "remove") } }).catch(() => {});
        return;
      }
      if (sub === "editplan") {
        setPlanAdminState(chatId, { mode: "pick_plan_edit", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`✏️ Edit Plan\n\nCategory: ${cat}\n\nChoose plan.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: planButtonsForCategory(cat, "edit") } }).catch(() => {});
        return;
      }
      if (sub === "renamecat") {
        setPlanAdminState(chatId, { mode: "await_rename_category", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`✏️ Rename Category\n\nCurrent: ${cat}\n\nSend new category name.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:renamecat" }]] } }).catch(() => {});
        return;
      }
      if (sub === "settemplate") {
        setPlanAdminState(chatId, { mode: "pick_template", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`⚙️ Category Behaviour\n\nCategory: ${cat}\nCurrent: ${categoryTemplate(cat)}\n\nChoose behaviour.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "📦 Normal Flow", callback_data: `planadm:settpl:${base64UrlEncode(cat)}:normal` }], [{ text: "📧 Gmail Style", callback_data: `planadm:settpl:${base64UrlEncode(cat)}:gmail` }], [{ text: "⬅️ Back", callback_data: "planadm:settemplate" }]] } }).catch(() => {});
        return;
      }
      if (sub === "loadstock") {
        if (categoryTemplate(cat) !== "gmail") {
          await bot.editMessageText(`❌ ${cat} is not Gmail-style. Set behaviour to Gmail Style first.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:status" }]] } }).catch(() => {});
          return;
        }
        setPlanAdminState(chatId, { mode: "await_load_stock", category: cat, messageId: q.message.message_id });
        await bot.editMessageText(`📥 Load Accounts\n\nCategory: ${cat}\n\nSend stock lines now:\nemail@gmail.com,password\nOne per line.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:loadstock" }]] } }).catch(() => {});
        return;
      }
    }
    if (action === "pickplan") {
      const parts = data.split(":");
      const sub = parts[2] || "edit";
      const cat = base64UrlDecode(parts[3] || "") || "";
      const idx = Number(parts[4] || -1);
      const plan = (PACKAGES[cat] || [])[idx];
      if (!plan) return;
      if (sub === "remove") {
        setPlanAdminState(chatId, { mode: "confirm_remove_plan", category: cat, index: idx, messageId: q.message.message_id });
        await bot.editMessageText(`Confirm remove?\n\n${plan.label}\nKsh ${plan.price}`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "✅ Confirm Remove", callback_data: `planadm:confirmremove:${base64UrlEncode(cat)}:${idx}` }], [{ text: "⬅️ Back", callback_data: `planadm:pickcat:removeplan:${base64UrlEncode(cat)}` }]] } }).catch(() => {});
        return;
      }
      if (sub === "edit") {
        setPlanAdminState(chatId, { mode: "choose_edit_plan_field", category: cat, index: idx, messageId: q.message.message_id });
        await bot.editMessageText(`✏️ Edit Plan\n\n${plan.label}\nKsh ${plan.price}\n\nChoose what to edit.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "✏️ Edit Name", callback_data: `planadm:editfield:${base64UrlEncode(cat)}:${idx}:name` }], [{ text: "💰 Edit Price", callback_data: `planadm:editfield:${base64UrlEncode(cat)}:${idx}:price` }], [{ text: "⬅️ Back", callback_data: `planadm:pickcat:editplan:${base64UrlEncode(cat)}` }]] } }).catch(() => {});
        return;
      }
    }
    if (action === "confirmremove") {
      const parts = data.split(":");
      const cat = base64UrlDecode(parts[2] || "") || "";
      const idx = Number(parts[3] || -1);
      const res = removePlanFromCategory(cat, idx);
      setPlanAdminState(chatId, { mode: "menu", messageId: q.message.message_id });
      await bot.editMessageText(res.ok ? `✅ Plan removed from ${cat}.` : `❌ ${res.err}`, { chat_id: q.message.chat.id, message_id: q.message.message_id, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
    if (action === "editfield") {
      const parts = data.split(":");
      const cat = base64UrlDecode(parts[2] || "") || "";
      const idx = Number(parts[3] || -1);
      const field = parts[4] || "name";
      setPlanAdminState(chatId, { mode: field === "price" ? "await_edit_plan_price" : "await_edit_plan_name", category: cat, index: idx, messageId: q.message.message_id });
      await bot.editMessageText(field === "price" ? `Send new price for selected plan in ${cat}.` : `Send new name for selected plan in ${cat}.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: `planadm:pickcat:editplan:${base64UrlEncode(cat)}` }]] } }).catch(() => {});
      return;
    }
    if (action === "settpl") {
      const parts = data.split(":");
      const cat = base64UrlDecode(parts[2] || "") || "";
      const tpl = parts[3] || "normal";
      setCategoryTemplate(cat, tpl);
      setPlanAdminState(chatId, { mode: "menu", messageId: q.message.message_id });
      await bot.editMessageText(`✅ ${cat} now uses ${tpl} behaviour.`, { chat_id: q.message.chat.id, message_id: q.message.message_id, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
  } catch (_) {}
});

// Plans admin input handler
bot.on("message", async (msg) => {
  try {
    const chatId = msg.chat.id;
  if (msg.chat && ["group", "supergroup", "channel"].includes(String(msg.chat.type || "")) && msg.from?.id) {
    try { setUserSourceChat(msg.from.id, msg.chat.id); } catch (_) {}
    verifyBotPermissionsAndFreeze(msg.chat.id).catch(() => {});
  }
    const text = String(msg.text || "").trim();
    if (!isAdmin(chatId) || !text || text.startsWith("/")) return;
    const st = getPlanAdminState(chatId);
    if (!st || !st.mode || st.mode === "menu") return;

    if (st.mode === "await_new_category_name") {
      const name = text.trim();
      if (!name) return;
      if (PACKAGES[name]) {
        await bot.editMessageText(`❌ Category already exists: ${name}`, { chat_id: chatId, message_id: st.messageId, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "planadm:status" }]] } }).catch(() => {});
        return;
      }
      PACKAGES[name] = [];
      ensureCategoryMeta();
      setCategoryTemplate(name, "normal");
      savePackageCatalogFromRuntime();
      setPlanAdminState(chatId, { mode: "pick_new_category_template", category: name, messageId: st.messageId });
      await bot.editMessageText(`✅ Category added: ${name}\n\nChoose behaviour.`, { chat_id: chatId, message_id: st.messageId, reply_markup: { inline_keyboard: [[{ text: "📦 Normal Flow", callback_data: `planadm:settpl:${base64UrlEncode(name)}:normal` }], [{ text: "📧 Gmail Style", callback_data: `planadm:settpl:${base64UrlEncode(name)}:gmail` }]] } }).catch(() => {});
      return;
    }
    if (st.mode === "await_plan_amount") {
      setPlanAdminState(chatId, { ...st, mode: "await_plan_period", amountText: text });
      await bot.editMessageText(`Category: ${st.category}\nAmount/details: ${text}\n\nNow send period.\nExamples:\n24HRS\n7 DAYS\n1HR\nMONTHLY\n1 DAY`, { chat_id: chatId, message_id: st.messageId, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: `planadm:pickcat:addplan:${base64UrlEncode(st.category)}` }]] } }).catch(() => {});
      return;
    }
    if (st.mode === "await_plan_period") {
      setPlanAdminState(chatId, { ...st, mode: "await_plan_price", periodText: text });
      await bot.editMessageText(`Category: ${st.category}\nAmount/details: ${st.amountText}\nPeriod: ${text}\n\nNow send price in Ksh.`, { chat_id: chatId, message_id: st.messageId, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: `planadm:pickcat:addplan:${base64UrlEncode(st.category)}` }]] } }).catch(() => {});
      return;
    }
    if (st.mode === "await_plan_price") {
      const price = Number(String(text).replace(/[^\d.]/g, ""));
      if (!Number.isFinite(price) || price <= 0) return;
      const amountText = String(st.amountText || "").trim();
      const periodText = String(st.periodText || "").trim();
      const label = `Ksh ${price} • ${amountText}${periodText ? ` ${periodText}` : ""}`.replace(/\s+/g, " ").trim();
      const res = addPlanToCategory(st.category, label, price);
      setPlanAdminState(chatId, { mode: "menu", messageId: st.messageId });
      await bot.editMessageText(res.ok ? `✅ Plan added\n\nCategory: ${st.category}\n${label}` : `❌ ${res.err}`, { chat_id: chatId, message_id: st.messageId, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
    if (st.mode === "await_rename_category") {
      const res = renameCategory(st.category, text.trim());
      setPlanAdminState(chatId, { mode: "menu", messageId: st.messageId });
      await bot.editMessageText(res.ok ? `✅ Category renamed to ${text.trim()}` : `❌ ${res.err}`, { chat_id: chatId, message_id: st.messageId, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
    if (st.mode === "await_edit_plan_name") {
      const res = updatePlanAtIndex(st.category, st.index, { label: text.trim() });
      setPlanAdminState(chatId, { mode: "menu", messageId: st.messageId });
      await bot.editMessageText(res.ok ? `✅ Plan name updated\n\n${res.plan.label}\nKsh ${res.plan.price}` : `❌ ${res.err}`, { chat_id: chatId, message_id: st.messageId, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
    if (st.mode === "await_edit_plan_price") {
      const price = Number(String(text).replace(/[^\d.]/g, ""));
      const res = updatePlanAtIndex(st.category, st.index, { price });
      setPlanAdminState(chatId, { mode: "menu", messageId: st.messageId });
      await bot.editMessageText(res.ok ? `✅ Plan price updated\n\n${res.plan.label}\nKsh ${res.plan.price}` : `❌ ${res.err}`, { chat_id: chatId, message_id: st.messageId, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
    if (st.mode === "await_load_stock") {
      if (categoryTemplate(st.category) !== "gmail") return;
      const res = addGmailStockFromLines(text);
      setPlanAdminState(chatId, { mode: "menu", messageId: st.messageId });
      await bot.editMessageText(`✅ Accounts loaded for ${st.category}\nAdded: ${res.added}\nSkipped: ${res.skipped}\nTotal Gmail stock: ${res.total}`, { chat_id: chatId, message_id: st.messageId, ...plansAdminKeyboard() }).catch(() => {});
      return;
    }
  } catch (_) {}
});

