// Admin input handler for panel actions
bot.on("message", async (msg) => {
  try {
    const chatId = msg.chat.id;
  if (msg.chat && ["group", "supergroup", "channel"].includes(String(msg.chat.type || "")) && msg.from?.id) {
    try { setUserSourceChat(msg.from.id, msg.chat.id); } catch (_) {}
    verifyBotPermissionsAndFreeze(msg.chat.id).catch(() => {});
  }
    const text = String(msg.text || "").trim();
    if (!isAdmin(chatId) || !text || text.startsWith("/")) return;

    const st = getGmailAdminState(chatId);
    if (!st || !st.mode || st.mode === "menu") return;

    if (st.mode === "await_add") {
      const res = addGmailStockFromLines(text);
      setGmailAdminState(chatId, { mode: "menu", messageId: st.messageId || null });
      if (st.messageId) {
        await bot.editMessageText(
          `✅ Gmail stock updated.\nAdded: ${res.added}\nSkipped duplicates: ${res.skipped}\nAvailable now: ${res.total}`,
          { chat_id: chatId, message_id: st.messageId, ...gmailAdminKeyboard() }
        ).catch(() => {});
      } else {
        await openGmailAdminPanel(chatId);
      }
      return;
    }

    if (st.mode === "await_edit") {
      const res = updateOneGmail(text);
      setGmailAdminState(chatId, { mode: "menu", messageId: st.messageId || null });
      const body = res.ok
        ? `✅ Gmail updated\n\nEmail: ${res.email}`
        : `❌ ${res.err}`;
      if (st.messageId) {
        await bot.editMessageText(body, { chat_id: chatId, message_id: st.messageId, ...gmailAdminKeyboard() }).catch(() => {});
      } else {
        await bot.sendMessage(chatId, body, gmailAdminKeyboard()).catch(() => {});
      }
      return;
    }

    if (st.mode === "await_remove") {
      const res = removeOneGmail(text);
      setGmailAdminState(chatId, { mode: "menu", messageId: st.messageId || null });
      const body = res.ok
        ? `✅ Gmail removed\n\nEmail: ${res.email}\nRemaining: ${gmailAvailableCount()}`
        : `❌ ${res.err}`;
      if (st.messageId) {
        await bot.editMessageText(body, { chat_id: chatId, message_id: st.messageId, ...gmailAdminKeyboard() }).catch(() => {});
      } else {
        await bot.sendMessage(chatId, body, gmailAdminKeyboard()).catch(() => {});
      }
      return;
    }

    if (st.mode === "await_price") {
      const price = Number(text);
      if (!Number.isFinite(price) || price <= 0) {
        if (st.messageId) {
          await bot.editMessageText(
            `❌ Invalid price.\n\nCurrent price: Ksh ${gmailPrice()}\nSend a valid number.`,
            { chat_id: chatId, message_id: st.messageId, reply_markup: { inline_keyboard: [[{ text: "⬅️ Back", callback_data: "gmailadm:status" }]] } }
          ).catch(() => {});
        }
        return;
      }
      const store = ensureGmailStore();
      store.cfg.price = price;
      saveDB();
      setGmailAdminState(chatId, { mode: "menu", messageId: st.messageId || null });
      const body = `✅ Gmail price updated\n\nNew price: Ksh ${gmailPrice()}`;
      if (st.messageId) {
        await bot.editMessageText(body, { chat_id: chatId, message_id: st.messageId, ...gmailAdminKeyboard() }).catch(() => {});
      } else {
        await bot.sendMessage(chatId, body, gmailAdminKeyboard()).catch(() => {});
      }
      return;
    }
  } catch (_) {}
});

