function adminAccessLogsText() {
  ensureAdminPanelStore();
  const rows = Array.isArray(db.adminLogs) ? db.adminLogs.slice(0, 25) : [];
  if (!rows.length) return "🧾 ACCESS LOGS\n\n• No admin actions logged yet.";
  return "🧾 ACCESS LOGS\n\n" + rows.map((x, i) => {
    const when = kenyaDateTimeFromTs(Number(x.ts || 0));
    const meta = x.meta && typeof x.meta === "object" ? Object.entries(x.meta).slice(0, 3).map(([k, v]) => `${k}=${v}`).join(", ") : "";
    return `${i + 1}. ${when} — ${x.action}${meta ? ` (${meta})` : ""}`;
  }).join("\n");
}

function adminPanelCategoryKey(cat) {
  return String(cat || "").toLowerCase().replace(/[^a-z0-9]+/g, "_");
}

function adminPanelCategoryFromKey(key) {
  const k = String(key || "").trim();
  for (const cat of ADMIN_PANEL_CATEGORY_ORDER) {
    if (adminPanelCategoryKey(cat) === k) return cat;
  }
  return null;
}

function isOfferCategoryClosed(category) {
  try {
    ensureAdminPanelStore();
    return !!db.closedOfferCategories[String(category || "")];
  } catch (_) {
    return false;
  }
}

function closedOfferUnavailableText(category) {
  return `❌ ${String(category || "This offer")} not available at this time.`;
}

function normalizeClosedOfferAllowedEntry(chatId) {
  try {
    db = repairDB(db);
    const key = String(chatId || "");
    const raw = db.closedOfferAllowedUsers[key];
    if (raw === true) {
      db.closedOfferAllowedUsers[key] = { all: true, categories: {} };
      return db.closedOfferAllowedUsers[key];
    }
    if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
      db.closedOfferAllowedUsers[key] = { all: false, categories: {} };
      return db.closedOfferAllowedUsers[key];
    }
    if (!raw.categories || typeof raw.categories !== "object" || Array.isArray(raw.categories)) raw.categories = {};
    raw.all = !!raw.all;
    return raw;
  } catch (_) {
    return { all: false, categories: {} };
  }
}

function getClosedOfferAllowedEntry(chatId) {
  try {
    if (isAdmin(chatId)) return { all: true, categories: {} };
    return normalizeClosedOfferAllowedEntry(chatId);
  } catch (_) {
    return { all: false, categories: {} };
  }
}

function isClosedOfferAllowedUser(chatId, category = null) {
  try {
    if (isAdmin(chatId)) return true;
    const entry = getClosedOfferAllowedEntry(chatId);
    if (entry.all) return true;
    if (!category) return Object.values(entry.categories || {}).some(Boolean);
    return !!entry.categories[String(category || "")];
  } catch (_) {
    return false;
  }
}

function setClosedOfferAllowedUser(chatId, value, category = null) {
  try {
    db = repairDB(db);
    const key = String(chatId || "");
    if (!value && !category) {
      delete db.closedOfferAllowedUsers[key];
      saveDB();
      return;
    }
    const entry = normalizeClosedOfferAllowedEntry(chatId);
    if (!category) {
      entry.all = !!value;
      if (!value) entry.categories = {};
    } else {
      entry.categories[String(category || "")] = !!value;
      if (!value) delete entry.categories[String(category || "")];
    }
    if (!entry.all && !Object.keys(entry.categories || {}).length) delete db.closedOfferAllowedUsers[key];
    else db.closedOfferAllowedUsers[key] = entry;
    saveDB();
  } catch (_) {}
}

function canUseCategoryEvenIfClosed(chatId, category) {
  return !isOfferCategoryClosed(category) || isClosedOfferAllowedUser(chatId, category);
}

function closedOfferAllowedSummary(chatId) {
  const entry = getClosedOfferAllowedEntry(chatId);
  if (entry.all) return "All closed categories";
  const cats = Object.keys(entry.categories || {}).filter((cat) => !!entry.categories[cat]);
  return cats.length ? cats.join(", ") : "None";
}

function normalizeUserOfferBlocks(chatId) {
  try {
    db = repairDB(db);
    if (!db.userOfferBlocks || typeof db.userOfferBlocks !== "object" || Array.isArray(db.userOfferBlocks)) db.userOfferBlocks = {};
    const key = String(chatId || "");
    const raw = db.userOfferBlocks[key];
    if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
      db.userOfferBlocks[key] = {};
      return db.userOfferBlocks[key];
    }
    for (const cat of Object.keys(raw)) {
      if (!raw[cat] || typeof raw[cat] !== "object" || Array.isArray(raw[cat])) raw[cat] = {};
    }
    return raw;
  } catch (_) {
    return {};
  }
}

function isOfferBlockedForUser(chatId, category, pkgLabel) {
  try {
    if (isAdmin(chatId)) return false;
    const map = normalizeUserOfferBlocks(chatId);
    return !!map?.[String(category || "")]?.[String(pkgLabel || "")];
  } catch (_) {
    return false;
  }
}

function canUseOfferForUser(chatId, category, pkgLabel) {
  if (!canUseCategoryEvenIfClosed(chatId, category)) return false;
  return !isOfferBlockedForUser(chatId, category, pkgLabel);
}

function setOfferBlockedForUser(chatId, category, pkgLabel, value) {
  try {
    db = repairDB(db);
    if (!db.userOfferBlocks || typeof db.userOfferBlocks !== "object" || Array.isArray(db.userOfferBlocks)) db.userOfferBlocks = {};
    const key = String(chatId || "");
    const cat = String(category || "");
    const lbl = String(pkgLabel || "");
    if (!cat || !lbl) return;
    const map = normalizeUserOfferBlocks(chatId);
    if (!map[cat] || typeof map[cat] !== "object" || Array.isArray(map[cat])) map[cat] = {};
    if (value) map[cat][lbl] = true;
    else delete map[cat][lbl];
    if (map[cat] && !Object.keys(map[cat]).length) delete map[cat];
    if (!Object.keys(map).length) delete db.userOfferBlocks[key];
    else db.userOfferBlocks[key] = map;
    saveDB();
  } catch (_) {}
}

function clearOfferBlocksForUser(chatId, category = null) {
  try {
    db = repairDB(db);
    if (!db.userOfferBlocks || typeof db.userOfferBlocks !== "object" || Array.isArray(db.userOfferBlocks)) db.userOfferBlocks = {};
    const key = String(chatId || "");
    if (!category) {
      delete db.userOfferBlocks[key];
      saveDB();
      return;
    }
    const map = normalizeUserOfferBlocks(chatId);
    delete map[String(category || "")];
    if (!Object.keys(map).length) delete db.userOfferBlocks[key];
    else db.userOfferBlocks[key] = map;
    saveDB();
  } catch (_) {}
}

function blockedOffersSummary(chatId, category = null) {
  try {
    const map = normalizeUserOfferBlocks(chatId);
    if (category) {
      const labels = Object.keys(map[String(category || "")] || {});
      return labels.length ? labels.join(", ") : "None";
    }
    const cats = [];
    for (const [cat, obj] of Object.entries(map || {})) {
      const labels = Object.keys(obj || {});
      if (labels.length) cats.push(`${cat} (${labels.length})`);
    }
    return cats.length ? cats.join(", ") : "None";
  } catch (_) {
    return "None";
  }
}

function setOfferCategoryClosed(category, value) {
  try {
    ensureAdminPanelStore();
    db.closedOfferCategories[String(category || "")] = !!value;
    saveDB();
  } catch (_) {}
}

