function adminPanelUserOfferToggleKeyboard(targetChatId, category) {
  const list = sortPackagesByTier(PACKAGES[category] || []);
  const blocked = normalizeUserOfferBlocks(targetChatId)?.[String(category || "")] || {};
  const rows = [];
  for (let i = 0; i < list.length; i++) {
    const pkg = list[i] || {};
    const on = !!blocked[String(pkg.label || "")];
    rows.push([{ text: `${on ? "🔴" : "🟢"} ${pkg.label}`, callback_data: `ap:block_offer_toggle:${targetChatId}:${adminPanelCategoryKey(category)}:${i}` }]);
  }
  rows.push([{ text: "🗑 Clear this category", callback_data: `ap:block_offer_clear_cat:${targetChatId}:${adminPanelCategoryKey(category)}` }]);
  rows.push([{ text: "⬅️ Back", callback_data: `ap:block_offer_pick_user:${targetChatId}` }, { text: "✅ Done", callback_data: "ap:offers" }]);
  return { reply_markup: { inline_keyboard: rows } };
}

