function ensureCampaignAdminTools() {
  const c = ensureWeeklyDrawObject();
  c.admin = c.admin && typeof c.admin === "object" ? c.admin : {};
  const a = c.admin;
  a.frozenTickets = a.frozenTickets && typeof a.frozenTickets === "object" ? a.frozenTickets : {};
  a.frozenPosition = a.frozenPosition && typeof a.frozenPosition === "object" ? a.frozenPosition : {};
  a.frozenWinnings = a.frozenWinnings && typeof a.frozenWinnings === "object" ? a.frozenWinnings : {};
  a.frozenCurrent = a.frozenCurrent && typeof a.frozenCurrent === "object" ? a.frozenCurrent : {};
  a.exemptRequirements = a.exemptRequirements && typeof a.exemptRequirements === "object" ? a.exemptRequirements : {};
  a.forcedParticipants = a.forcedParticipants && typeof a.forcedParticipants === "object" ? a.forcedParticipants : {};
  a.forcedPosition = a.forcedPosition && typeof a.forcedPosition === "object" ? a.forcedPosition : {};
  return a;
}

function getWeeklyDrawRankedParticipants(limit = 0) {
  const c = ensureWeeklyDrawObject();
  const admin = ensureCampaignAdminTools();
  const entries = c.entries && typeof c.entries === "object" ? c.entries : {};
  const ids = new Set([
    ...Object.keys(entries || {}),
    ...Object.keys(admin.forcedParticipants || {}),
    ...Object.keys(admin.frozenCurrent || {}),
    ...Object.keys(admin.forcedPosition || {}),
  ]);

  let items = [];
  for (const cid of ids) {
    const tickets = Number(entries[String(cid)] || 0);
    const forcedCurrent = !!admin.frozenCurrent[String(cid)];
    const forcedParticipant = !!admin.forcedParticipants[String(cid)];
    if (!(tickets > 0) && !forcedCurrent && !forcedParticipant) continue;
    const q = weeklyDrawQualification(cid);
    const eligible = forcedCurrent || forcedParticipant || q.qualified;
    const boardOk = forcedCurrent || forcedParticipant || isWeeklyDrawLeaderboardEligible(cid);
    if (!eligible || !boardOk) continue;
    const u = getUser(cid);
    items.push({
      cid: String(cid),
      chatId: Number(cid),
      tickets,
      name: safeDisplayName(u, cid),
      qualified: !!q.qualified,
      forcedPos: Number(admin.forcedPosition[String(cid)] || 0),
    });
  }

  items.sort((a, b) => (b.tickets - a.tickets) || String(a.name).localeCompare(String(b.name)));
  const pinned = items.filter(x => x.forcedPos > 0).sort((a, b) => a.forcedPos - b.forcedPos || b.tickets - a.tickets);
  const normal = items.filter(x => !(x.forcedPos > 0));
  const used = new Set();
  const byPos = {};
  for (const item of pinned) {
    const pos = Math.max(1, Math.floor(Number(item.forcedPos || 0)));
    (byPos[pos] = byPos[pos] || []).push(item);
  }
  const result = [];
  let idx = 0;
  const maxPos = Math.max(items.length, ...Object.keys(byPos).map(x => Number(x || 0)), 0);
  for (let pos = 1; pos <= maxPos; pos += 1) {
    const forcedHere = byPos[pos] || [];
    if (forcedHere.length) {
      for (const item of forcedHere) {
        if (!used.has(item.cid)) {
          result.push(item);
          used.add(item.cid);
        }
      }
    }
    while (idx < normal.length && used.has(normal[idx].cid)) idx += 1;
    if (result.length < pos && idx < normal.length) {
      result.push(normal[idx]);
      used.add(normal[idx].cid);
      idx += 1;
    }
  }
  while (idx < normal.length) {
    if (!used.has(normal[idx].cid)) result.push(normal[idx]);
    idx += 1;
  }
  return limit > 0 ? result.slice(0, limit) : result;
}

