// ===================== INLINE CHANNEL TARGET SELECTORS (NO COMMAND NEEDED) =====================

function ensureInlineChannelTargetStore() {
  db = repairDB(db);
  if (!db.inlineChannelTargets || typeof db.inlineChannelTargets !== "object") {
    db.inlineChannelTargets = {
      knownChats: {},
      autoPostTargets: {},
      repostTargets: {},
      postTargets: {},
    };
  }
  return db.inlineChannelTargets;
}

function registerInlineKnownChat(chat, ownerId = "") {
  try {
    if (!chat || !chat.id) return;
    const store = ensureInlineChannelTargetStore();
    const id = String(chat.id);
    store.knownChats[id] = {
      id,
      title: String(chat.title || chat.username || id),
      username: chat.username ? ("@" + String(chat.username).replace(/^@/, "")) : "",
      type: String(chat.type || ""),
      ownerId: String(ownerId || ""),
      active: true,
      updatedAt: Date.now(),
    };
    saveDB();
  } catch (_) {}
}

function getInlineKnownChats() {
  const store = ensureInlineChannelTargetStore();
  return Object.values(store.knownChats || {}).sort((a, b) => String(a.title || "").localeCompare(String(b.title || "")));
}

function isMarkedInlineTarget(kind, chatId) {
  const store = ensureInlineChannelTargetStore();
  const key = String(chatId || "");
  if (kind === "autopost") return !!store.autoPostTargets[key];
  if (kind === "repost") return !!store.repostTargets[key];
  if (kind === "postnow") return !!store.postTargets[key];
  return false;
}

function setMarkedInlineTarget(kind, chatId, value) {
  const store = ensureInlineChannelTargetStore();
  const key = String(chatId || "");
  const bucket =
    kind === "autopost" ? store.autoPostTargets :
    kind === "repost" ? store.repostTargets :
    store.postTargets;

  if (value) bucket[key] = true;
  else delete bucket[key];
  saveDB();
}

function toggleManualForceJoinTarget(chatId) {
  try {
    const known = (ensureInlineChannelTargetStore().knownChats || {})[String(chatId)];
    const current = getForceJoinChannels();
    const usernameTarget = known && known.username ? known.username : "";
    const idTarget = String(chatId || "");
    const exists = current.some((x) => String(x) === usernameTarget || String(x) === idTarget);

    let next = current.slice();
    if (exists) {
      next = next.filter((x) => String(x) !== usernameTarget && String(x) !== idTarget);
    } else {
      next.push(usernameTarget || idTarget);
    }
    saveForceJoinChannels(Array.from(new Set(next.filter(Boolean))));
    return !exists;
  } catch (_) {
    return false;
  }
}

function isManualForceJoinTarget(chatId) {
  try {
    const known = (ensureInlineChannelTargetStore().knownChats || {})[String(chatId)];
    const current = getForceJoinChannels();
    const usernameTarget = known && known.username ? known.username : "";
    const idTarget = String(chatId || "");
    return current.some((x) => String(x) === usernameTarget || String(x) === idTarget);
  } catch (_) {
    return false;
  }
}

function inlineTargetSelectorKeyboard(kind) {
  const chats = getInlineKnownChats();
  const rows = [];

  for (const ch of chats) {
    const id = String(ch.id);
    let marked = false;
    if (kind === "forcejoin") marked = isManualForceJoinTarget(id);
    else marked = isMarkedInlineTarget(kind, id);

    const title = String(ch.title || ch.username || id);
    rows.push([{
      text: `${marked ? "✅" : "⬜️"} ${title}`,
      callback_data: kind === "settings"
        ? `cpadv:settingsopen:${id}`
        : kind === "forcejoin"
          ? `cpadv:forcejoin:${id}`
          : `cpadv:toggle:${kind}:${id}`
    }]);
  }

  rows.push([{ text: "⬅️ Back", callback_data: "cpadv:panel" }, { text: "🏠 Main Menu", callback_data: "cpadv:home" }]);
  return { reply_markup: { inline_keyboard: rows } };
}

function countMarkedTargets(kind) {
  const store = ensureInlineChannelTargetStore();
  if (kind === "autopost") return Object.keys(store.autoPostTargets || {}).length;
  if (kind === "repost") return Object.keys(store.repostTargets || {}).length;
  if (kind === "postnow") return Object.keys(store.postTargets || {}).length;
  return 0;
}

// Override the promo admin keyboard to add full inline selectors
function channelPromoAdminKeyboard() {
  const cfg = channelPromoCfg();
  const rcfg = channelPromoRepostCfg();
  const mode = String(cfg.mode || "text").toUpperCase();
  const delayMin = Math.round(Number(cfg.delayMs || 180000) / 60000);
  const pinMark = cfg.pinNew ? "✅" : "⬜️";
  const unpinMark = cfg.unpinOld ? "✅" : "⬜️";
  const repostMark = rcfg.enabled ? "✅" : "⬜️";
  const delPrevMark = rcfg.deletePrevious ? "✅" : "⬜️";

  return {
    reply_markup: {
      inline_keyboard: [
        [{ text: `📣 Mode: ${mode}`, callback_data: "cpadm:noop" }],
        [{ text: "📝 Set Text", callback_data: "cpadm:set_text" }, { text: "🖼 Set Media", callback_data: "cpadm:set_media" }],
        [{ text: "🔘 Set Button", callback_data: "cpadm:set_button" }, { text: `⏱ Delay: ${delayMin}m`, callback_data: "cpadm:set_delay" }],
        [{ text: `${pinMark} Auto Pin`, callback_data: "cpadm:toggle_pin" }, { text: `${unpinMark} Unpin Old`, callback_data: "cpadm:toggle_unpin" }],
        [{ text: `${repostMark} Auto Repost`, callback_data: "cpadm:toggle_repost" }, { text: `${delPrevMark} Delete Previous`, callback_data: "cpadm:toggle_delprev" }],
        [{ text: `📢 Auto Post Targets (${countMarkedTargets("autopost")})`, callback_data: "cpadv:autopost_menu" }],
        [{ text: `🔁 Repost Targets (${countMarkedTargets("repost")})`, callback_data: "cpadv:repost_menu" }],
        [{ text: "⚙️ Channel Target Settings", callback_data: "cpadv:settings_menu" }],
        [{ text: "🎯 Post To Target Now", callback_data: "cpadv:postnow_menu" }],
        [{ text: "➕ Force Join Targets", callback_data: "cpadv:forcejoin_menu" }],
        [{ text: "📊 Stats", callback_data: "cpadm:stats" }, { text: "👀 Preview", callback_data: "cpadm:preview" }],
        [{ text: "🗑 Delete Channel Post", callback_data: "cpadm:delete_post" }, { text: "🚪 Leave Channel", callback_data: "cpadm:leave_channel" }],
        [{ text: "🧹 Clear Promo", callback_data: "cpadm:clear" }, { text: "❌ Close", callback_data: "cpadm:close" }]
      ]
    }
  };
}

// Override admin text to reflect inline target counts
function channelPromoAdminText() {
  const cfg = channelPromoCfg();
  const rcfg = channelPromoRepostCfg();
  const mode = String(cfg.mode || "text");
  const delayMin = Math.round(Number(cfg.delayMs || 180000) / 60000);
  const mediaCount = Array.isArray(cfg.media) ? cfg.media.length : 0;
  const btnText = String(cfg.buttonText || "").trim() || "(none)";
  const btnUrl = String(cfg.buttonUrl || "").trim() || "(none)";

  return (
    "📣 CHANNEL PROMO ADMIN\n\n" +
    `Mode: ${mode}\n` +
    `Media items: ${mediaCount}\n` +
    `Button: ${btnText}\n` +
    `Link: ${btnUrl}\n` +
    `Delay: ${delayMin} minute(s)\n` +
    `Pin new: ${cfg.pinNew ? "ON" : "OFF"}\n` +
    `Unpin old: ${cfg.unpinOld ? "ON" : "OFF"}\n` +
    `Auto repost: ${rcfg.enabled ? "ON" : "OFF"}\n` +
    `Delete previous repost: ${rcfg.deletePrevious ? "ON" : "OFF"}\n` +
    `Auto post targets: ${countMarkedTargets("autopost")}\n` +
    `Repost targets: ${countMarkedTargets("repost")}\n\n` +
    "Use the inline buttons below to select channels/groups. Channels are not added to force join unless you manually choose them."
  );
}

// Register known chats when bot is added, but do NOT auto-add them to force join.
bot.on("my_chat_member", async (update) => {
  try {
    const chat = update && update.chat;
    const oldStatus = String(update && update.old_chat_member && update.old_chat_member.status || "");
    const newStatus = String(update && update.new_chat_member && update.new_chat_member.status || "");
    const chatType = String(chat && chat.type || "");
    if (!chat || !["group", "supergroup", "channel"].includes(chatType)) return;

    const becameAdmin = (newStatus === "administrator" || newStatus === "creator") &&
                        oldStatus !== "administrator" && oldStatus !== "creator";
    if (!becameAdmin) return;

    registerInlineKnownChat(chat, update?.from?.id || "");
  } catch (_) {}
});

// Override schedule so promo is auto-posted ONLY to admin-selected auto-post targets
async function scheduleChannelPromoForChat(chat) {
  try {
    if (!chat || !chat.id) return;
    registerInlineKnownChat(chat);
    const targetId = String(chat.id);
    if (!isMarkedInlineTarget("autopost", targetId)) return;

    ensureChannelPromoStore();
    const key = String(chat.id);
    const store = db.channelPromo;

    if (store.pending[key] || wasChannelPromoSent(chat.id)) return;

    store.pending[key] = {
      scheduledAt: Date.now(),
      runAt: Date.now() + Number(channelPromoCfg().delayMs || (3 * 60 * 1000)),
      type: String(chat.type || "")
    };
    saveDB();

    setTimeout(async () => {
      try {
        ensureChannelPromoStore();
        const pending = db.channelPromo.pending[key];
        if (!pending) return;

        try {
          const me = await bot.getMe();
          const botMember = await bot.getChatMember(chat.id, me.id);
          const status = String(botMember && botMember.status || "");
          const botOk = (status === "administrator" || status === "creator");
          if (!botOk) {
            delete db.channelPromo.pending[key];
            saveDB();
            return;
          }
        } catch (_) {
          delete db.channelPromo.pending[key];
          saveDB();
          return;
        }

        const sent = await sendConfiguredChannelPromo(chat.id);
        delete db.channelPromo.pending[key];
        if (sent) markChannelPromoSent(chat.id);
        else saveDB();
      } catch (_) {
        try {
          delete db.channelPromo.pending[key];
          saveDB();
        } catch (_) {}
      }
    }, Math.max(1000, Number(channelPromoCfg().delayMs || (3 * 60 * 1000))));
  } catch (_) {}
}

// Override repost runner so it uses inline-selected repost targets when present
async function runChannelPromoRepostIfDue() {
  try {
    ensureChannelPromoStore();
    const rcfg = channelPromoRepostCfg();
    if (!rcfg.enabled) return;
    if (!rcfg.intervalMs || Date.now() < Number(rcfg.nextRunAt || 0)) return;

    const selected = Object.keys((ensureInlineChannelTargetStore().repostTargets || {}));
    const targets = selected.length ? selected : [];

    for (const targetId of targets) {
      await sendConfiguredChannelPromoToTarget(targetId, { deletePrevious: !!rcfg.deletePrevious }).catch(() => {});
    }

    rcfg.nextRunAt = Date.now() + Number(rcfg.intervalMs || 0);
    saveDB();
  } catch (_) {}
}

bot.on("callback_query", async (q) => {
  try {
    const data = String(q && q.data || "");
    const chatId = q && q.from && q.from.id;
    if (!chatId || !isAdmin(chatId)) return;

    if (data === "cpadv:panel") {
      await openChannelPromoAdminMenu(chatId, q.message);
      return;
    }

    if (data === "cpadv:home") {
      await bot.sendMessage(chatId, "🏠 Main Menu", { ...mainMenuKeyboard(chatId) }).catch(() => {});
      return;
    }

    if (data === "cpadv:autopost_menu") {
      await bot.editMessageText("📢 Select channels/groups for AUTO POST:", {
        chat_id: q.message.chat.id,
        message_id: q.message.message_id,
        ...inlineTargetSelectorKeyboard("autopost")
      }).catch(() => {});
      return;
    }

    if (data === "cpadv:repost_menu") {
      await bot.editMessageText("🔁 Select channels/groups for REPOST:", {
        chat_id: q.message.chat.id,
        message_id: q.message.message_id,
        ...inlineTargetSelectorKeyboard("repost")
      }).catch(() => {});
      return;
    }

    if (data === "cpadv:settings_menu") {
      await bot.editMessageText("⚙️ Select a channel/group to manage PIN, UNPIN OLD, DELETE PREVIOUS, and REPOST INTERVAL:", {
        chat_id: q.message.chat.id,
        message_id: q.message.message_id,
        ...inlineTargetSelectorKeyboard("settings")
      }).catch(() => {});
      return;
    }

    if (data === "cpadv:postnow_menu") {
      await bot.editMessageText("🎯 Select a channel/group to post the CURRENT promo there now:", {
        chat_id: q.message.chat.id,
        message_id: q.message.message_id,
        ...inlineTargetSelectorKeyboard("postnow")
      }).catch(() => {});
      return;
    }

    if (data === "cpadv:forcejoin_menu") {
      await bot.editMessageText("➕ Select which channels/groups should be added to FORCE JOIN. Nothing is auto-added:", {
        chat_id: q.message.chat.id,
        message_id: q.message.message_id,
        ...inlineTargetSelectorKeyboard("forcejoin")
      }).catch(() => {});
      return;
    }

    if (data.startswith && false) {
      return;
    }

    if (data.startsWith("cpadv:toggle:")) {
      const parts = data.split(":");
      const kind = String(parts[2] || "");
      const targetId = String(parts[3] || "");
      const next = !isMarkedInlineTarget(kind, targetId);
      setMarkedInlineTarget(kind, targetId, next);

      await bot.editMessageReplyMarkup(
        inlineTargetSelectorKeyboard(kind).reply_markup,
        { chat_id: q.message.chat.id, message_id: q.message.message_id }
      ).catch(() => {});
      return;
    }

    if (data.startsWith("cpadv:settingsopen:")) {
      const targetId = String(data.split(":")[2] || "");
      const known = (ensureInlineChannelTargetStore().knownChats || {})[targetId] || {};
      const title = String(known.title || targetId);
      await bot.editMessageText(
        `⚙️ Channel Target Settings\n\nTarget: ${title}\nID: ${targetId}`,
        {
          chat_id: q.message.chat.id,
          message_id: q.message.message_id,
          ...channelTargetSettingsKeyboard(targetId)
        }
      ).catch(() => {});
      return;
    }

    if (data.startsWith("cpadv:postone:")) {
      const targetId = String(data.split(":")[2] || "");
      const known = (ensureInlineChannelTargetStore().knownChats || {})[targetId] || {};
      const ok = await sendConfiguredChannelPromoToTarget(targetId, { deletePrevious: false }).catch(() => false);
      await bot.answerCallbackQuery(q.id, { text: ok ? "Posted" : "Failed to post" }).catch(() => {});
      try {
        await bot.sendMessage(chatId, ok ? `✅ Promo posted to ${known.title || targetId}` : `❌ Failed to post promo to ${known.title || targetId}`).catch(() => {});
      } catch (_) {}
      return;
    }

    if (data.startsWith("cpadv:postnow:")) {
      const targetId = String(data.split(":")[2] || "");
      const next = !isMarkedInlineTarget("postnow", targetId);
      setMarkedInlineTarget("postnow", targetId, next);
      await bot.answerCallbackQuery(q.id, { text: next ? "Marked for post" : "Unmarked" }).catch(() => {});
      await bot.editMessageReplyMarkup(
        inlineTargetSelectorKeyboard("postnow").reply_markup,
        { chat_id: q.message.chat.id, message_id: q.message.message_id }
      ).catch(() => {});
      return;
    }

    if (data.startsWith("cpadv:forcejoin:")) {
      const targetId = String(data.split(":")[2] || "");
      toggleManualForceJoinTarget(targetId);
      await bot.editMessageReplyMarkup(
        inlineTargetSelectorKeyboard("forcejoin").reply_markup,
        { chat_id: q.message.chat.id, message_id: q.message.message_id }
      ).catch(() => {});
      return;
    }
  } catch (_) {}
});

