function inlineTargetSelectorKeyboard(kind) {
  const chats = getInlineKnownChats();
  const rows = [];

  if (kind === 'postnow') {
    rows.push([{ text: `📤 Post To All Marked Targets (${countMarkedTargets('postnow')})`, callback_data: 'cpadv:postall' }]);
  }
  if (kind === 'settings') {
    rows.push([{ text: '🕒 Set Auto Post Interval All', callback_data: 'cpadv:setautopostall' }, { text: '🗑 Set Auto Delete All', callback_data: 'cpadv:setautodelall' }]);
  }

  for (const ch of chats) {
    const id = String(ch.id);
    const title = String(ch.title || ch.username || id);

    if (kind === 'settings') {
      const s = getChannelPromoTargetSettings(id);
      rows.push([{
        text: `⚙️ ${title} · Post:${formatPromoIntervalShort(s.autoPostIntervalMs)} · Del:${formatPromoIntervalShort(s.autoDeleteMs)}`,
        callback_data: `cpadv:settingsopen:${id}`
      }]);
      continue;
    }

    let marked = false;
    if (kind === 'forcejoin') marked = isManualForceJoinTarget(id);
    else marked = isMarkedInlineTarget(kind, id);

    rows.push([{
      text: `${marked ? '✅' : '⬜️'} ${title}`,
      callback_data: kind === 'forcejoin'
        ? `cpadv:forcejoin:${id}`
        : `cpadv:toggle:${kind}:${id}`
    }]);
  }

  rows.push([{ text: '⬅️ Back', callback_data: 'cpadv:panel' }, { text: '🏠 Main Menu', callback_data: 'cpadv:home' }]);
  return { reply_markup: { inline_keyboard: rows } };
}

async function sendConfiguredChannelPromoToTarget(targetChatId, opts = {}) {
  const cfg = channelPromoCfg();
  const settings = getChannelPromoTargetSettings(targetChatId);
  let pinMessageId = null;

  if (opts.deletePrevious || settings.deletePrevious) {
    try {
      const rec = ensurePromoChannelMetric(targetChatId);
      if (rec.lastPromoMessageId) await bot.deleteMessage(targetChatId, rec.lastPromoMessageId).catch(() => {});
    } catch (_) {}
  }

  if (settings.unpinOld) {
    try { await bot.unpinAllChatMessages(targetChatId); } catch (_) {}
  }

  const kb = promoTrackedButtonKeyboard(targetChatId);

  if (Array.isArray(cfg.media) && cfg.media.length) {
    const m0 = cfg.media[0];
    if (m0 && m0.file_id) {
      if (m0.type === 'video') {
        const sent = await bot.sendVideo(targetChatId, m0.file_id, { caption: String(cfg.caption || cfg.text || ''), ...(kb || {}) }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      } else {
        const sent = await bot.sendPhoto(targetChatId, m0.file_id, { caption: String(cfg.caption || cfg.text || ''), ...(kb || {}) }).catch(() => null);
        if (sent && sent.message_id) pinMessageId = sent.message_id;
      }
    }
  } else {
    const sent = await bot.sendMessage(targetChatId, String(cfg.text || cfg.caption || ''), kb || {}).catch(() => null);
    if (sent && sent.message_id) pinMessageId = sent.message_id;
  }

  if (settings.pinNew && pinMessageId) {
    try { await bot.pinChatMessage(targetChatId, pinMessageId, { disable_notification: true }); } catch (_) {}
  }
  if (pinMessageId) {
    try { trackPromoSend(targetChatId, pinMessageId); } catch (_) {}
    await schedulePromoAutoDelete(targetChatId, pinMessageId, settings.autoDeleteMs);
  }
  return !!pinMessageId;
}

async function postPromoToAllMarkedTargets() {
  const store = ensureInlineChannelTargetStore();
  const ids = Object.keys(store.postTargets || {});
  let ok = 0;
  let fail = 0;
  for (const targetId of ids) {
    const sent = await sendConfiguredChannelPromoToTarget(targetId, { deletePrevious: true }).catch(() => false);
    if (sent) ok += 1;
    else fail += 1;
  }
  return { total: ids.length, ok, fail };
}

async function runChannelPromoRepostIfDue() {
  try {
    ensureChannelPromoStore();
    const rcfg = channelPromoRepostCfg();
    if (!rcfg.enabled) return;

    const targets = Object.keys((ensureInlineChannelTargetStore().repostTargets || {}));
    if (!targets.length) return;

    let touched = false;
    for (const targetId of targets) {
      const settings = getChannelPromoTargetSettings(targetId);
      const intervalMs = Math.max(0, Number(settings.autoPostIntervalMs || rcfg.intervalMs || 0));
      if (!intervalMs) continue;
      const nextAt = Number(settings.nextAutoPostAt || 0);
      if (nextAt && Date.now() < nextAt) continue;

      const sent = await sendConfiguredChannelPromoToTarget(targetId, { deletePrevious: !!settings.deletePrevious }).catch(() => false);
      settings.nextAutoPostAt = Date.now() + intervalMs;
      touched = true;
      if (!sent && intervalMs >= 60000) settings.nextAutoPostAt = Date.now() + Math.min(intervalMs, 10 * 60 * 1000);
    }

    rcfg.nextRunAt = Date.now() + 30000;
    if (touched) saveDB();
  } catch (_) {}
}

bot.on('callback_query', async (q) => {
  try {
    const data = String(q && q.data || '');
    const chatId = q && q.from && q.from.id;
    if (!chatId || !isAdmin(chatId)) return;

    if (data === 'cpadv:setautopostall') {
      setChannelPromoEditState(chatId, { mode: 'await_all_autopost_interval', sourceMessageId: q.message.message_id, sourceChatId: q.message.chat.id });
      await bot.answerCallbackQuery(q.id, { text: 'Send interval in chat' }).catch(() => {});
      await bot.sendMessage(chatId, '🕒 Send AUTO POST interval for ALL known channels/groups\n\nExamples:\n• off\n• 30s\n• 10m\n• 1h\n• 1d').catch(() => {});
      return;
    }

    if (data === 'cpadv:setautodelall') {
      setChannelPromoEditState(chatId, { mode: 'await_all_autodelete', sourceMessageId: q.message.message_id, sourceChatId: q.message.chat.id });
      await bot.answerCallbackQuery(q.id, { text: 'Send interval in chat' }).catch(() => {});
      await bot.sendMessage(chatId, '🗑 Send AUTO DELETE interval for ALL known channels/groups\n\nExamples:\n• off\n• 30s\n• 10m\n• 1h\n• 1d').catch(() => {});
      return;
    }

    if (data === 'cpadv:postall') {
      const result = await postPromoToAllMarkedTargets();
      await bot.answerCallbackQuery(q.id, { text: result.total ? `Posted: ${result.ok}/${result.total}` : 'No marked post targets' }).catch(() => {});
      if (!result.total) {
        await bot.sendMessage(chatId, '⚠️ No marked post targets yet. Open “Post Targets” first, mark channels/groups, then tap “Post To All Marked Targets”.').catch(() => {});
      }
      return;
    }

    if (data.startsWith('cpadv:setautopostint:')) {
      const targetId = String(data.split(':')[2] || '');
      const known = (ensureInlineChannelTargetStore().knownChats || {})[targetId] || {};
      const title = String(known.title || targetId);
      setChannelPromoEditState(chatId, { mode: 'await_target_autopost_interval', targetId, sourceMessageId: q.message.message_id, sourceChatId: q.message.chat.id });
      await bot.answerCallbackQuery(q.id, { text: 'Send interval in chat' }).catch(() => {});
      await bot.sendMessage(chatId, `🕒 Send auto post interval for ${title}\n\nExamples:\n• off\n• 30s\n• 10m\n• 1h\n• 1d`).catch(() => {});
      return;
    }
  } catch (_) {}
});

bot.on('message', async (msg) => {
  try {
    const chatId = msg && msg.chat && msg.chat.id;
    if (!chatId || !promoAdmin(chatId) || String(msg && msg.chat && msg.chat.type || '') !== 'private') return;
    const state = getChannelPromoEditState(chatId);
    if (!state) return;

    const text = String(msg && msg.text || '').trim();

    if (state.mode === 'await_target_autopost_interval') {
      const ms = parsePromoIntervalMs(text);
      if (ms === null) {
        await bot.sendMessage(chatId, '❌ Send interval like off, 30s, 10m, 1h, 1d').catch(() => {});
        return;
      }
      setChannelPromoTargetSetting(state.targetId, { autoPostIntervalMs: ms, nextAutoPostAt: ms ? (Date.now() + ms) : 0 });
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, `✅ Auto post interval set to ${formatPromoIntervalLong(ms)}.`).catch(() => {});
      if (state.sourceChatId && state.sourceMessageId) {
        const fakeQ = { message: { chat: { id: state.sourceChatId }, message_id: state.sourceMessageId } };
        await renderChannelTargetSettingsMenu(fakeQ, state.targetId);
      }
      return;
    }

    if (state.mode === 'await_all_autodelete') {
      const ms = parsePromoIntervalMs(text);
      if (ms === null) {
        await bot.sendMessage(chatId, '❌ Send interval like off, 30s, 10m, 1h, 1d').catch(() => {});
        return;
      }
      for (const ch of getInlineKnownChats()) setChannelPromoTargetSetting(ch.id, { autoDeleteMs: ms });
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, `✅ Auto delete interval set to ${formatPromoIntervalLong(ms)} for all known channels/groups.`).catch(() => {});
      if (state.sourceChatId && state.sourceMessageId) {
        await bot.editMessageReplyMarkup(inlineTargetSelectorKeyboard('settings').reply_markup, { chat_id: state.sourceChatId, message_id: state.sourceMessageId }).catch(() => {});
      }
      return;
    }

    if (state.mode === 'await_all_autopost_interval') {
      const ms = parsePromoIntervalMs(text);
      if (ms === null) {
        await bot.sendMessage(chatId, '❌ Send interval like off, 30s, 10m, 1h, 1d').catch(() => {});
        return;
      }
      for (const ch of getInlineKnownChats()) setChannelPromoTargetSetting(ch.id, { autoPostIntervalMs: ms, nextAutoPostAt: ms ? (Date.now() + ms) : 0 });
      clearChannelPromoEditState(chatId);
      await bot.sendMessage(chatId, `✅ Auto post interval set to ${formatPromoIntervalLong(ms)} for all known channels/groups.`).catch(() => {});
      if (state.sourceChatId && state.sourceMessageId) {
        await bot.editMessageReplyMarkup(inlineTargetSelectorKeyboard('settings').reply_markup, { chat_id: state.sourceChatId, message_id: state.sourceMessageId }).catch(() => {});
      }
      return;
    }
  } catch (_) {}
});

