function packagesKeyboard(category, chatId = null) {
  if (!canUseCategoryEvenIfClosed(chatId, category)) {
    return { reply_markup: { keyboard: [[PREV_BTN, '🏠 Main Menu']], resize_keyboard: true, one_time_keyboard: false } };
  }
  const list = sortPackagesByTier(PACKAGES[category] || []).filter((x) => canUseOfferForUser(chatId, category, x.label));
  const rows = [];
  for (let i = 0; i < list.length; i += 2) rows.push(list.slice(i, i + 2).map((x) => x.label));
  rows.push([PREV_BTN, '🏠 Main Menu']);
  return { reply_markup: { keyboard: rows, resize_keyboard: true, one_time_keyboard: false } };
}

function searchOffersInline(query, viewerChatId = null) {
  const q = String(query || '').trim().toLowerCase();
  if (!q) return [];
  const all = getAllOffersFlat();
  const tokens = q.split(/\s+/g).filter(Boolean);

  return all.filter((x) => {
    if (!canUseOfferForUser(viewerChatId, x.category, x.label)) return false;
    const hay = `${x.category} ${x.label} ${x.price}`.toLowerCase();
    return tokens.every(t => hay.includes(t));
  });
}

bot.on('inline_query', async (q) => {
  try {
    const query = String(q.query || '').trim();
    const results = [];

    const cmdHits = commandMatchesInline(query).slice(0, 8);
    for (const c of cmdHits) {
      results.push({
        type: 'article',
        id: `cmd_${c.key}`,
        title: c.title,
        description: c.desc,
        input_message_content: { message_text: c.text },
      });
    }

    const catHits = categoryMatchesInline(query)
      .filter((cat) => canUseCategoryEvenIfClosed(q.from?.id, cat))
      .slice(0, 8);
    for (const cat of catHits) {
      results.push({
        type: 'article',
        id: `cat_${base64UrlEncode(cat)}`,
        title: `📦 ${cat}`,
        description: 'Open category packages',
        input_message_content: { message_text: `#cat ${base64UrlEncode(cat)}` },
      });
    }

    const hits = searchOffersInline(query, q.from?.id).slice(0, 20);
    for (const h of hits) {
      results.push({
        type: 'article',
        id: `offer_${base64UrlEncode(h.category)}_${base64UrlEncode(h.label)}`,
        title: h.label,
        description: `${h.category} • Ksh ${h.price}`,
        input_message_content: { message_text: `#buy ${base64UrlEncode(h.category)}:${base64UrlEncode(h.label)}` },
      });
    }

    if (!query) {
      const top = getTopTrendingOffers(5).filter((t) => canUseOfferForUser(q.from?.id, t.category, t.label));
      if (top.length) {
        for (const t of top) {
          results.push({
            type: 'article',
            id: `trend_${base64UrlEncode(t.category)}_${base64UrlEncode(t.label)}`,
            title: `🔥 ${t.label}`,
            description: `${t.category} • Ksh ${t.price} • ${t.count} buys`,
            input_message_content: { message_text: `#buy ${base64UrlEncode(t.category)}:${base64UrlEncode(t.label)}` },
          });
        }
      }
    }

    await bot.answerInlineQuery(q.id, results, { cache_time: 1, is_personal: true }).catch(() => {});
  } catch (_) {}
});

bot.on("message", async (msg) => {
  const chatId = msg?.chat?.id;
  const text = String(msg?.text || "").trim();
  if (!chatId || !text) return;
  if (Number(chatId) !== Number(ADMIN_ID)) return;
  if (text.startsWith("/")) return;

  try {
    const u = getUser(chatId);
    const pending = u?.pendingAction;
    if (!pending || typeof pending !== "object" || pending.type !== "set_payment_id") return;

    const newId = Number(text.replace(/[^0-9-]/g, ""));
    if (!Number.isInteger(newId) || newId <= 0) {
      await bot.sendMessage(chatId, "❌ Send a valid numeric payment ID. Example: 2486").catch(() => {});
      return;
    }

    setConfiguredPaymentId(pending.category, newId);
    u.pendingAction = null;
    saveDB();
    await bot.sendMessage(chatId, `✅ Payment ID updated.\n\nCategory: ${pending.category}\nNew ID: ${newId}`, paymentIdCategoryKeyboard()).catch(() => {});
  } catch (e) {
    console.log("set payment id message error:", e?.message || e);
    await bot.sendMessage(chatId, "❌ Failed to update payment ID.").catch(() => {});
  }
});


async function runCartReminderSweep() {
  const now = Date.now();
  const entries = Array.from(sessions.entries());
  for (const [chatId, s] of entries) {
    try {
      if (!s || !Array.isArray(s.cart) || !s.cart.length) {
        if (s && s.cartReminderMsgId) await deleteCartReminderMessage(chatId, s);
        continue;
      }
      const lastAction = Number(s.cartLastActionAt || 0) || now;
      const idleMs = now - lastAction;
      if (idleMs >= 30 * 60 * 1000) {
        await deleteCartReminderMessage(chatId, s);
        clearSessionCart(s);
        if (s.step && String(s.step).startsWith('cart_')) s.step = 'category';
        s.category = null;
        s.pkgKey = null;
        sessions.set(chatId, s);
        await sendTracked(chatId, '⌛ Cart cleared after 30 minutes with no action. Start again from 🛒 Buy Offers.', { ...mainMenuKeyboard(chatId) });
        continue;
      }
      const lastReminder = Number(s.cartLastReminderAt || 0);
      if (idleMs >= 10 * 60 * 1000 && now - lastReminder >= 10 * 60 * 1000) {
        await sendCartReminder(chatId, s);
        sessions.set(chatId, s);
      }
    } catch (_) {}
  }
}
setInterval(() => { runCartReminderSweep().catch(() => {}); }, 60 * 1000);


